// 🚀 Debounce — олон realtime event нэг дор ирэхэд queue хийх (DB-руу хэт олон query явахаас сэргийлнэ)
function useDebouncedCallback(callback, delay = 800) {
  const timeoutRef = useRef(null);
  const callbackRef = useRef(callback);
  callbackRef.current = callback;

  return useMemo(() => {
    return (...args) => {
      if (timeoutRef.current) clearTimeout(timeoutRef.current);
      timeoutRef.current = setTimeout(() => {
        callbackRef.current(...args);
      }, delay);
    };
  }, [delay]);
}

// 📍 Point-in-polygon — Ray casting algorithm
// Цэг (lat, lng) нь polygon дотор байгаа эсэхийг шалгана
function isPointInPolygon(point, polygon) {
  if (!polygon || polygon.length < 3) return false;
  const [lat, lng] = point;
  let inside = false;
  for (let i = 0, j = polygon.length - 1; i < polygon.length; j = i++) {
    const [latI, lngI] = polygon[i];
    const [latJ, lngJ] = polygon[j];
    const intersect = ((lngI > lng) !== (lngJ > lng)) &&
      (lat < (latJ - latI) * (lng - lngI) / (lngJ - lngI) + latI);
    if (intersect) inside = !inside;
  }
  return inside;
}

// 🚀 Supabase 1000-н row hard limit-ийг bypass хийх pagination helper
// Хязгаарлалтгүй бүх row татаж буцаана

// 🔧 Production-руу sensitive data leak хийхгүй байх — зөвхөн dev-д
const isDev = (() => {
  try { return import.meta.env?.DEV === true; }
  catch { return false; }
})();
const logDev = (...args) => { if (isDev) console.log(...args); };
const logErr = (...args) => {
  console.error(...args);
  // 🛡️ Sentry-руу алдаа илгээх (production-д)
  if (SENTRY_DSN && !isDev) {
    const err = args.find(a => a instanceof Error);
    if (err) {
      Sentry.captureException(err, { extra: { context: args[0] } });
    } else {
      Sentry.captureMessage(args.map(a =>
        typeof a === "string" ? a : JSON.stringify(a)
      ).join(" "), "error");
    }
  }
};

async function fetchAllRows(queryBuilder) {
  const PAGE = 1000;
  let all = [];
  let from = 0;
  while (true) {
    const { data, error } = await queryBuilder.range(from, from + PAGE - 1);
    if (error) throw error;
    if (!data || data.length === 0) break;
    all = all.concat(data);
    if (data.length < PAGE) break;
    from += PAGE;
    if (from > 50000) break; // safety: 50K row хүртэл
  }
  return all;
}

// 🧩 Хэт олон ID-тай .in() query-г chunk-аар асууна
// PostgREST URL ~8KB хязгаартай. UUID 37 char × 200 ≈ 7400 → аюулгүй
async function fetchInChunks(table, ids, options = {}) {
  const {
    select = "*",
    filterColumn = "id",
    chunkSize = 200,
  } = options;

  if (!ids || ids.length === 0) return [];
  const uniqueIds = [...new Set(ids)];
  const results = [];

  for (let i = 0; i < uniqueIds.length; i += chunkSize) {
    const chunk = uniqueIds.slice(i, i + chunkSize);
    let from = 0;
    const PAGE = 1000;
    while (true) {
      const { data, error } = await supabase
        .from(table)
        .select(select)
        .in(filterColumn, chunk)
        .range(from, from + PAGE - 1);
      if (error) {
        console.error(`[fetchInChunks ${table}] chunk ${i}-${i + chunkSize} error:`, error);
        throw error;
      }
      if (!data || data.length === 0) break;
      results.push(...data);
      if (data.length < PAGE) break;
      from += PAGE;
      if (from > 50000) break;
    }
  }
  return results;
}

// 🔧 .in()-ийг chunk-аар UPDATE хийх (URL хязгаараас сэргийлэх)
async function updateInChunks(table, filterColumn, ids, updateData, chunkSize = 200) {
  if (!ids || ids.length === 0) return { error: null };
  const uniqueIds = [...new Set(ids)];
  for (let i = 0; i < uniqueIds.length; i += chunkSize) {
    const chunk = uniqueIds.slice(i, i + chunkSize);
    const { error } = await supabase.from(table).update(updateData).in(filterColumn, chunk);
    if (error) {
      console.error(`[updateInChunks ${table}] chunk ${i}-${i + chunkSize} error:`, error);
      return { error };
    }
  }
  return { error: null };
}

// 🔧 .in()-ийг chunk-аар DELETE хийх
async function deleteInChunks(table, filterColumn, ids, chunkSize = 200) {
  if (!ids || ids.length === 0) return { error: null };
  const uniqueIds = [...new Set(ids)];
  for (let i = 0; i < uniqueIds.length; i += chunkSize) {
    const chunk = uniqueIds.slice(i, i + chunkSize);
    const { error } = await supabase.from(table).delete().in(filterColumn, chunk);
    if (error) {
      console.error(`[deleteInChunks ${table}] chunk ${i}-${i + chunkSize} error:`, error);
      return { error };
    }
  }
  return { error: null };
}

// 🚚 Захиалгын координатаар → ямар бүсэд багтахыг олох
async function findZoneByLocation(lat, lng) {
  if (!lat || !lng) return null;
  try {
    const { data: zones } = await supabase.from("biz_zones")
      .select("id, name, driver_id, polygon")
      .eq("is_active", true);
    
    if (!zones || zones.length === 0) return null;
    
    for (const zone of zones) {
      if (isPointInPolygon([Number(lat), Number(lng)], zone.polygon || [])) {
        return zone;
      }
    }
    return null;
  } catch (e) {
    console.error("findZoneByLocation error:", e);
    return null;
  }
}

