// 🛡️ ErrorBoundary Fallback UI (алдаа гарвал харагдах page)
function ErrorFallback({ error, resetError }) {
  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      padding: "1rem",
      background: "linear-gradient(135deg, #fef3c7 0%, #fee2e2 100%)",
    }}>
      <div style={{
        maxWidth: "420px",
        background: "white",
        borderRadius: "16px",
        padding: "2rem",
        boxShadow: "0 10px 40px rgba(0,0,0,0.1)",
        textAlign: "center",
      }}>
        <div style={{ fontSize: "48px", marginBottom: "1rem" }}>⚠️</div>
        <h2 style={{ fontSize: "1.25rem", fontWeight: 700, marginBottom: "0.5rem", color: "#1f2937" }}>
          Алдаа гарлаа
        </h2>
        <p style={{ color: "#6b7280", fontSize: "0.875rem", marginBottom: "1.5rem", lineHeight: 1.5 }}>
          Уучлаарай, системд гэнэтийн алдаа гарлаа. Програмыг дахин ачаалж үзнэ үү.
          {SENTRY_DSN && <span><br/><span style={{ fontSize: "11px", opacity: 0.7 }}>Алдааг автоматаар техникийн багт мэдээллээ.</span></span>}
        </p>
        {isDev && error && (
          <details style={{ textAlign: "left", marginBottom: "1rem", padding: "0.5rem", background: "#fef2f2", borderRadius: "8px" }}>
            <summary style={{ cursor: "pointer", fontSize: "11px", color: "#991b1b", fontWeight: 600 }}>
              Dev info
            </summary>
            <pre style={{ fontSize: "10px", color: "#7f1d1d", marginTop: "0.5rem", overflow: "auto", maxHeight: "200px" }}>
              {error.message}
              {"\n\n"}
              {error.stack}
            </pre>
          </details>
        )}
        <div style={{ display: "flex", gap: "0.5rem" }}>
          <button onClick={() => { resetError(); window.location.reload(); }}
            style={{
              flex: 1,
              padding: "0.75rem 1rem",
              background: "linear-gradient(135deg, #3FE0C6, #0E9C8E)",
              color: "white",
              border: "none",
              borderRadius: "10px",
              fontWeight: 600,
              cursor: "pointer",
              fontSize: "0.875rem",
            }}>
            🔄 Дахин ачаалах
          </button>
          <button onClick={() => { supabase.auth.signOut(); window.location.href = "/"; }}
            style={{
              flex: 1,
              padding: "0.75rem 1rem",
              background: "#f3f4f6",
              color: "#374151",
              border: "1px solid #e5e7eb",
              borderRadius: "10px",
              fontWeight: 600,
              cursor: "pointer",
              fontSize: "0.875rem",
            }}>
            Гарах
          </button>
        </div>
      </div>
    </div>
  );
}

function AppRoot() {
  const [session, setSession] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [installPrompt, setInstallPrompt] = useState(null);
  const [showInstallBanner, setShowInstallBanner] = useState(false);
  const [toasts, setToasts] = useState([]); // ⭐ Toast notification stack
  const toastIdRef = useRef(0);

  // ─── window.alert-ыг toast notification болгож солих ─────────────────
  useEffect(() => {
    const originalAlert = window.alert.bind(window);
    window.alert = (msg) => {
      const id = ++toastIdRef.current;
      const text = String(msg ?? "");
      setToasts((prev) => [...prev, { id, text, ts: Date.now() }]);
      // Auto-dismiss дараа
      const dismissMs = text.length > 100 ? 6000 : 4000;
      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, dismissMs);
    };
    return () => { window.alert = originalAlert; };
  }, []);

  const dismissToast = (id) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  };

  // Alert-ийн төрлийг автомат илрүүлэх (icon, color)
  const detectAlertType = (msg) => {
    if (!msg) return { kind: "info", icon: "ℹ", color: "#0ea5e9" };
    const m = msg.toLowerCase();
    if (msg.includes("✅") || m.includes("амжилттай") || m.includes("хадгалагдлаа") || m.includes("дууслаа")) {
      return { kind: "success", icon: "✅", color: "#10b981" };
    }
    if (msg.includes("⚠") || m.includes("анхаар") || m.includes("хүрэлцэхгүй")) {
      return { kind: "warning", icon: "⚠", color: "#f59e0b" };
    }
    if (msg.includes("✕") || msg.includes("❌") || m.startsWith("алдаа") || m.includes("error") || m.includes("буруу")) {
      return { kind: "error", icon: "❌", color: "#ef4444" };
    }
    return { kind: "info", icon: "ℹ", color: "#0ea5e9" };
  };

  // ─── Mobile UX системт сайжруулалт CSS ──────────────────────────
  useEffect(() => {
    // Browser tab гарчиг
    document.title = "CoreLink";
    // Favicon — Ripple лого (aqua gradient SVG)
    (function setFavicon() {
      const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="64" height="64" viewBox="0 0 200 200"><defs><linearGradient id="rip" x1="46" y1="46" x2="154" y2="154" gradientUnits="userSpaceOnUse"><stop stop-color="#3FE0C6"/><stop offset="1" stop-color="#0E9C8E"/></linearGradient></defs><circle cx="100" cy="100" r="78" stroke="url(#rip)" stroke-width="5" opacity="0.30" fill="none"/><circle cx="100" cy="100" r="58" stroke="url(#rip)" stroke-width="8" opacity="0.62" fill="none"/><circle cx="100" cy="100" r="36" stroke="url(#rip)" stroke-width="12" fill="none"/><circle cx="100" cy="100" r="13" fill="url(#rip)"/></svg>`;
      const href = "data:image/svg+xml," + encodeURIComponent(svg);
      let link = document.querySelector("link[rel~='icon']");
      if (!link) {
        link = document.createElement("link");
        link.rel = "icon";
        document.head.appendChild(link);
      }
      link.type = "image/svg+xml";
      link.href = href;
    })();
    const styleId = "orgoo-mobile-improvements";
    if (document.getElementById(styleId)) return;
    const style = document.createElement("style");
    style.id = styleId;
    style.innerHTML = `
      /* Бүх touch товч багадаа 44px (iOS Apple HIG) */
      @media (max-width: 768px) {
        button:not(.leaflet-control-zoom-in):not(.leaflet-control-zoom-out):not([class*="leaflet-"]),
        a[href]:not([class*="leaflet-"]),
        [role="button"]:not([class*="leaflet-"]) {
          min-height: 40px;
          touch-action: manipulation;
        }

        /* Жижиг текст уншигдахуйц болгох */
        .text-\\[8px\\] { font-size: 10px !important; }
        .text-\\[9px\\] { font-size: 10px !important; }
        .text-\\[10px\\] { font-size: 11px !important; }
        .text-\\[11px\\] { font-size: 12px !important; }
        
        /* Input талбар жижиг харагдахаас сэргийлэх */
        input:not([type="checkbox"]):not([type="radio"]),
        select,
        textarea {
          font-size: 16px !important; /* iOS auto-zoom-аас сэргийлэх */
          min-height: 40px;
        }
        textarea {
          min-height: 80px;
        }

        /* Sidebar өргөн */
        aside, nav[class*="sidebar"] {
          width: min(85vw, 320px) !important;
        }

        /* Тач feedback */
        .press-btn:active {
          transform: scale(0.97);
          transition: transform 0.1s;
        }
      }

      /* Бүх дэлгэцэнд: scrollbar нарийхан */
      ::-webkit-scrollbar {
        width: 6px;
        height: 6px;
      }
      ::-webkit-scrollbar-thumb {
        background: rgba(0,0,0,0.15);
        border-radius: 3px;
      }
      ::-webkit-scrollbar-thumb:hover {
        background: rgba(0,0,0,0.3);
      }

      /* Leaflet map fix — давхар padding оруулахаас сэргийлэх */
      .leaflet-container {
        height: 100% !important;
        width: 100% !important;
      }
      
      /* Sidebar collapsed: button text + section labels-ийг нуух */
      .sidebar-collapsed-nav button > span:not(:empty),
      .sidebar-collapsed-nav button > span.text-\\[10px\\] {
        display: none !important;
      }
      .sidebar-collapsed-nav > div > button > span {
        display: none !important;
      }
      .sidebar-collapsed-nav button {
        justify-content: center !important;
      }
      .sidebar-collapsed-nav button > svg {
        flex-shrink: 0;
      }

      /* ═══════════ DARK MODE ═══════════ */
      html.dark-mode body { background: #07211f; }
      html.dark-mode .min-h-screen { background: #07211f !important; color: #d6ede8 !important; }
      /* Цайвар surface (rgba цагаан) → бараан teal */
      html.dark-mode [style*="rgba(255, 255, 255, 0.7)"],
      html.dark-mode [style*="rgba(255, 255, 255, 0.85)"],
      html.dark-mode [style*="rgba(255, 255, 255, 0.55)"],
      html.dark-mode [style*="rgba(255,255,255,0.7)"],
      html.dark-mode [style*="rgba(255,255,255,0.85)"] {
        background: rgba(18, 48, 46, 0.85) !important;
      }
      html.dark-mode [style*="rgba(255, 255, 255, 0.45)"],
      html.dark-mode [style*="rgba(255,255,255,0.45)"] {
        background: rgba(255, 255, 255, 0.04) !important;
      }
      /* Текст өнгө */
      html.dark-mode h1, html.dark-mode h2, html.dark-mode h3,
      html.dark-mode p, html.dark-mode span, html.dark-mode div,
      html.dark-mode td, html.dark-mode th, html.dark-mode label,
      html.dark-mode button, html.dark-mode a {
        color: inherit;
      }
      html.dark-mode [style*="color: rgb(12, 42, 48)"],
      html.dark-mode [style*="color:#0C2A30"],
      html.dark-mode [style*="color: #0C2A30"] { color: #e3f3ef !important; }
      html.dark-mode [style*="color: rgb(31, 66, 72)"],
      html.dark-mode [style*="#1f4248"] { color: #cfe6e1 !important; }
      html.dark-mode [style*="#5b7c7e"],
      html.dark-mode [style*="rgb(91, 124, 126)"] { color: #8fb3ae !important; }
      html.dark-mode [style*="#8fabac"] { color: #6e928e !important; }
      /* Border */
      html.dark-mode [style*="rgba(255, 255, 255, 0.7)"][style*="border"],
      html.dark-mode [style*="borderColor"] { border-color: rgba(255,255,255,0.08) !important; }
      /* Card border-той surface */
      html.dark-mode .glass { background: rgba(18, 48, 46, 0.85) !important; border-color: rgba(255,255,255,0.08) !important; }
      /* Input талбар */
      html.dark-mode input, html.dark-mode select, html.dark-mode textarea {
        background: rgba(255,255,255,0.05) !important;
        color: #e3f3ef !important;
        border-color: rgba(255,255,255,0.12) !important;
      }
      html.dark-mode input::placeholder, html.dark-mode textarea::placeholder { color: #6e928e !important; }
      /* hover саарал → бараан */
      html.dark-mode .hover\\:bg-gray-50:hover,
      html.dark-mode .hover\\:bg-gray-100:hover { background: rgba(255,255,255,0.06) !important; }
      /* Border utility классууд */
      html.dark-mode .border-b, html.dark-mode .border-t,
      html.dark-mode .border { border-color: rgba(255,255,255,0.08) !important; }
    `;
    document.head.appendChild(style);
    return () => {
      const existing = document.getElementById(styleId);
      if (existing) existing.remove();
    };
  }, []);

  // PWA install prompt detection
  useEffect(() => {
    const handler = (e) => {
      e.preventDefault();
      setInstallPrompt(e);
      // Only show banner if not previously dismissed
      const dismissed = localStorage.getItem("hours-install-dismissed");
      if (!dismissed) setShowInstallBanner(true);
    };
    window.addEventListener("beforeinstallprompt", handler);
    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const promptInstall = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    await installPrompt.userChoice;
    setInstallPrompt(null);
    setShowInstallBanner(false);
  };

  const dismissInstall = () => {
    localStorage.setItem("hours-install-dismissed", "1");
    setShowInstallBanner(false);
  };

  useEffect(() => {
    if (!isConfigured) { setLoading(false); return; }
    (async () => {
      const { data: { session: s } } = await supabase.auth.getSession();
      setSession(s);
      setLoading(false);
    })();
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, newSession) => {
      setSession(newSession);
      if (!newSession) setProfile(null);
    });
    return () => subscription.unsubscribe();
  }, []);

  useEffect(() => {
    if (!session) {
      setProfile(null);
      // 🛡️ Sentry: гарсан үед user context-ийг арилгана
      if (SENTRY_DSN) Sentry.setUser(null);
      return;
    }
    (async () => {
      const { data, error } = await supabase
        .from("profiles")
        .select("*")
        .eq("id", session.user.id)
        .maybeSingle();
      if (error) logErr("profile load:", error);
      setProfile(data);
      // 🛡️ Sentry: нэвтэрсэн хэрэглэгчийг context-руу нэмнэ (PII биш — id+role л)
      if (SENTRY_DSN && data) {
        Sentry.setUser({
          id: data.id,
          username: data.name || "—",
          role: data.role || "unknown",
        });
      }
    })();
  }, [session]);

  if (!isConfigured) return <ConfigError />;
  if (loading) return <Loading />;

  const installBanner = showInstallBanner && installPrompt && (
    <InstallBanner onInstall={promptInstall} onDismiss={dismissInstall} />
  );

  if (!session) return <>{installBanner}<LoginScreen /></>;
  if (!profile) {
    return (
      <>
        {installBanner}
        <CenterCard>
          <Loader2 size={24} className="animate-spin mb-4 mx-auto" style={{ color: T.muted }} />
          <p style={{ color: T.muted }} className="text-sm mb-4">Профайл татаж байна…</p>
          <p style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-[0.2em] mb-3">
            Профайл олдсонгүй гэж гарвал админд хандаарай
          </p>
          <button onClick={() => supabase.auth.signOut()}
            style={{ fontFamily: FS, color: "#1e1b4b" }}
            className="glass-soft press-btn w-full py-2 rounded-xl text-sm">
            Гарах
          </button>
        </CenterCard>
      </>
    );
  }

  return (
    <>
      {installBanner}
      <NotificationManager profile={profile} />
      {(profile.role === "admin" || profile.role === "manager" || profile.role === "marketing") ? <AdminDashboard profile={profile} />
        : profile.role === "operator" ? <OperatorDashboard profile={profile} />
        : profile.role === "driver" ? <DriverDashboard profile={profile} />
        : profile.role === "merchant" ? <MerchantDashboard profile={profile} />
        : <EmployeeDashboard profile={profile} />}

      {/* ─── 🍞 Toast Notification Stack (window.alert override) ───────── */}
      {toasts.length > 0 && createPortal(
        <div style={{
          position: "fixed",
          top: 16,
          right: 16,
          zIndex: 100000,
          display: "flex",
          flexDirection: "column",
          gap: 8,
          maxWidth: 360,
          width: "calc(100vw - 32px)",
          pointerEvents: "none",
        }}>
          {toasts.map((toast) => {
            const at = detectAlertType(toast.text);
            const cleanMsg = toast.text.replace(/^[✅✕⚠❌ℹ📭🎉]\s*/g, "").trim();
            const lines = cleanMsg.split("\n").filter((l) => l.trim());
            const title = lines[0] || "";
            const body = lines.slice(1).join("\n").trim();
            return (
              <div key={toast.id}
                onClick={() => dismissToast(toast.id)}
                style={{
                  background: "white",
                  borderRadius: 12,
                  boxShadow: `0 10px 30px rgba(0,0,0,0.12), 0 0 0 1px ${at.color}33`,
                  borderLeft: `4px solid ${at.color}`,
                  padding: "12px 14px",
                  display: "flex",
                  alignItems: "flex-start",
                  gap: 10,
                  cursor: "pointer",
                  pointerEvents: "auto",
                  animation: "toast-slide-in 0.3s cubic-bezier(0.16, 1, 0.3, 1)",
                  fontFamily: "'SF Pro Text', system-ui",
                }}>
                <div style={{
                  fontSize: 20,
                  lineHeight: 1,
                  flexShrink: 0,
                  marginTop: 1,
                }}>{at.icon}</div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{
                    fontWeight: 600,
                    fontSize: 13,
                    color: at.color,
                    lineHeight: 1.4,
                    marginBottom: body ? 4 : 0,
                  }}>{title}</div>
                  {body && (
                    <div style={{
                      fontSize: 12,
                      color: "#475569",
                      lineHeight: 1.5,
                      whiteSpace: "pre-wrap",
                      maxHeight: 100,
                      overflowY: "auto",
                    }}>{body}</div>
                  )}
                </div>
                <button onClick={(e) => { e.stopPropagation(); dismissToast(toast.id); }}
                  style={{
                    background: "transparent",
                    border: "none",
                    color: "#94a3b8",
                    cursor: "pointer",
                    fontSize: 16,
                    padding: 2,
                    lineHeight: 1,
                    flexShrink: 0,
                  }}
                  aria-label="Хаах">
                  ✕
                </button>
              </div>
            );
          })}
          <style>{`
            @keyframes toast-slide-in {
              from { transform: translateX(120%); opacity: 0; }
              to { transform: translateX(0); opacity: 1; }
            }
          `}</style>
        </div>,
        document.body
      )}
    </>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  NOTIFICATION MANAGER — Push subscription + in-app realtime toast
// ═══════════════════════════════════════════════════════════════════════════
// ─── Цаг бүртгэх (зураг + GPS-тэй) — Operator + Driver-руу ─────────
function TimeTracker({ profile }) {
  const [active, setActive] = useState(null);
  const [todayHrs, setTodayHrs] = useState(0);
  const [busy, setBusy] = useState(false);
  const [, setTick] = useState(0);
  const [photoCapture, setPhotoCapture] = useState(null); // { type: "in"|"out", loc?, durationMs? }

  useEffect(() => { 
    const id = setInterval(() => setTick((t) => t + 1), 1000); 
    return () => clearInterval(id); 
  }, []);

  const loadMy = async () => {
    try {
      const { data: act } = await supabase
        .from("active_sessions")
        .select("*")
        .eq("employee_id", profile.id)
        .maybeSingle();
      setActive(act);
      
      const startOfDay = new Date();
      startOfDay.setHours(0, 0, 0, 0);
      const { data: sess } = await supabase
        .from("sessions")
        .select("start_time, end_time")
        .eq("employee_id", profile.id)
        .gte("start_time", startOfDay.toISOString());
      // ⚠ sessions хүснэгтэд duration_ms багана БАЙХГҮЙ — start_time/end_time-аас тооцно
      const totalMs = (sess || []).reduce((s, x) => {
        if (!x.start_time) return s;
        const end = x.end_time ? new Date(x.end_time) : new Date(); // дуусаагүй бол одоо хүртэл
        return s + Math.max(0, end - new Date(x.start_time));
      }, 0);
      setTodayHrs(totalMs / 3600000);
    } catch (e) { console.error(e); }
  };

  useEffect(() => {
    loadMy();
    const ch = supabase.channel(`time-tracker-${profile.id}`)
      .on("postgres_changes", { 
        event: "*", schema: "public", table: "active_sessions",
        filter: `employee_id=eq.${profile.id}` 
      }, () => loadMy())
      .subscribe();
    return () => { supabase.removeChannel(ch); };
  }, [profile.id]);

  const onStartClick = async () => {
    setBusy(true);
    try {
      // GPS байршил татах
      let loc = null;
      try {
        loc = await getGeolocation();
      } catch (e) {
        if (!confirm("⚠ Байршил татаж чадсангүй. GPS-гүйгээр үргэлжлүүлэх үү?")) {
          setBusy(false);
          return;
        }
      }
      // Photo capture modal нээх
      setPhotoCapture({ type: "in", loc });
    } catch (e) { alert("Алдаа: " + e.message); }
    finally { setBusy(false); }
  };

  const onStopClick = async () => {
    if (!active) return;
    if (!confirm("Цаг бүртгэлийг зогсоох уу?")) return;
    setBusy(true);
    try {
      let loc = null;
      try { loc = await getGeolocation(); } catch (e) {}
      setPhotoCapture({ type: "out", loc, active });
    } catch (e) { alert("Алдаа: " + e.message); }
    finally { setBusy(false); }
  };

  const completeWithPhoto = async (photoBlob) => {
    if (!photoCapture) return;
    setBusy(true);
    try {
      if (photoCapture.type === "in") {
        // ── START ──
        const photoUrl = photoBlob ? await uploadClockPhoto(profile.id, photoBlob, "in") : null;
        const { error } = await supabase.from("active_sessions").upsert({
          employee_id: profile.id,
          start_time: new Date().toISOString(),
          start_lat: photoCapture.loc?.lat,
          start_lng: photoCapture.loc?.lng,
          clock_in_photo_url: photoUrl,
        });
        if (error) throw error;
      } else {
        // ── STOP ──
        const photoUrl = photoBlob ? await uploadClockPhoto(profile.id, photoBlob, "out") : null;
        const startTime = new Date(photoCapture.active.start_time);
        const endTime = new Date();

        await supabase.from("sessions").insert({
          employee_id: profile.id,
          start_time: startTime.toISOString(),
          end_time: endTime.toISOString(),
          start_lat: photoCapture.active.start_lat,
          start_lng: photoCapture.active.start_lng,
          end_lat: photoCapture.loc?.lat,
          end_lng: photoCapture.loc?.lng,
          clock_in_photo_url: photoCapture.active.clock_in_photo_url,
          clock_out_photo_url: photoUrl,
        });
        await supabase.from("active_sessions").delete().eq("employee_id", profile.id);
      }
      setPhotoCapture(null);
      await loadMy();
    } catch (e) {
      alert("Алдаа: " + e.message);
      setPhotoCapture(null);
    } finally { setBusy(false); }
  };

  let liveHrs = 0;
  if (active) {
    const elapsed = Date.now() - new Date(active.start_time).getTime();
    liveHrs = elapsed / 3600000;
  }
  const totalLive = todayHrs + liveHrs;
  const hh = Math.floor(totalLive);
  const mm = Math.floor((totalLive - hh) * 60);
  const ss = Math.floor(((totalLive - hh) * 60 - mm) * 60);

  return (
    <>
      <div className="glass rounded-xl p-2 flex items-center gap-2">
        <div style={{
          background: active ? "rgba(16,185,129,0.15)" : T.surfaceAlt,
          color: active ? T.ok : T.muted,
        }} className="w-8 h-8 rounded-full flex items-center justify-center text-sm flex-shrink-0">
          {active ? "▶" : "⏸"}
        </div>
        <div className="flex-1 min-w-0">
          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider">
            {active ? "🟢 Ажиллаж байна" : "Цаг бүртгэгдээгүй"}
          </div>
          <div style={{ fontFamily: FD, fontWeight: 700, color: active ? T.ok : T.ink }} className="text-sm tabular-nums">
            {String(hh).padStart(2, "0")}:{String(mm).padStart(2, "0")}{active && `:${String(ss).padStart(2, "0")}`}
          </div>
        </div>
        {active ? (
          <button onClick={onStopClick} disabled={busy}
            className="press-btn px-3 py-1.5 rounded-lg text-xs font-semibold"
            style={{ background: T.err, color: "white", fontFamily: FS }}>
            {busy ? "..." : "⏹ Зогсох"}
          </button>
        ) : (
          <button onClick={onStartClick} disabled={busy}
            className="press-btn px-3 py-1.5 rounded-lg text-xs font-semibold"
            style={{ background: T.ok, color: "white", fontFamily: FS }}>
            {busy ? "..." : "▶ Эхлэх"}
          </button>
        )}
      </div>

      {/* Photo capture modal */}
      {photoCapture && createPortal(
        <TimePhotoCaptureModal
          type={photoCapture.type}
          onCapture={completeWithPhoto}
          onSkip={() => completeWithPhoto(null)}
          onCancel={() => setPhotoCapture(null)}
        />,
        document.body
      )}
    </>
  );
}

// ─── Зураг авах modal — Camera-аар selfie авна ────────────
function TimePhotoCaptureModal({ type, onCapture, onSkip, onCancel }) {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const [stream, setStream] = useState(null);
  const [error, setError] = useState(null);
  const [busy, setBusy] = useState(false);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const mediaStream = await navigator.mediaDevices.getUserMedia({
          video: { facingMode: "user", width: { ideal: 480 }, height: { ideal: 480 } },
        });
        if (!mounted) {
          mediaStream.getTracks().forEach((t) => t.stop());
          return;
        }
        setStream(mediaStream);
        if (videoRef.current) {
          videoRef.current.srcObject = mediaStream;
        }
      } catch (e) {
        setError(e.message);
      }
    })();
    return () => {
      mounted = false;
      if (stream) {
        stream.getTracks().forEach((t) => t.stop());
      }
    };
  }, []);

  const takePhoto = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setBusy(true);
    try {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext("2d");
      ctx.drawImage(video, 0, 0);
      canvas.toBlob((blob) => {
        if (blob) onCapture(blob);
        if (stream) stream.getTracks().forEach((t) => t.stop());
      }, "image/jpeg", 0.85);
    } catch (e) {
      alert("Алдаа: " + e.message);
      setBusy(false);
    }
  };

  return (
    <div style={{
      position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 100000,
      display: "flex", alignItems: "center", justifyContent: "center", padding: 16,
      background: "rgba(0,0,0,0.85)",
    }}>
      <div style={{
        background: T.bg, borderRadius: 16, width: "100%", maxWidth: 400,
        boxShadow: "0 24px 48px rgba(0,0,0,0.5)",
      }}>
        <div className="p-4">
          <div className="text-center mb-3">
            <div className="text-3xl mb-1">📸</div>
            <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-base">
              {type === "in" ? "Цаг эхлүүлэх зураг" : "Цаг зогсоох зураг"}
            </div>
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-1">
              Camera-руу харж зураг авна уу
            </div>
          </div>

          {error ? (
            <div className="rounded-lg p-3 mb-3 text-center" 
              style={{ background: T.errSoft, color: T.err }}>
              <div className="text-2xl mb-1">⚠</div>
              <div style={{ fontFamily: FS, fontWeight: 600 }} className="text-xs">
                Camera ашиглах боломжгүй
              </div>
              <div style={{ fontFamily: FM }} className="text-[10px] mt-1">
                {error}
              </div>
            </div>
          ) : (
            <div className="rounded-lg overflow-hidden mb-3" 
              style={{ background: "black", aspectRatio: "1/1" }}>
              <video ref={videoRef} autoPlay playsInline muted
                style={{ width: "100%", height: "100%", objectFit: "cover" }} />
            </div>
          )}
          <canvas ref={canvasRef} style={{ display: "none" }} />

          <div className="space-y-2">
            {!error && (
              <button onClick={takePhoto} disabled={busy || !stream}
                className="press-btn w-full py-3 rounded-xl text-sm font-semibold"
                style={{ background: T.ok, color: "white", fontFamily: FS, fontWeight: 700 }}>
                {busy ? "Хадгалж байна..." : "📸 Зураг авах"}
              </button>
            )}
            <button onClick={() => { 
              if (stream) stream.getTracks().forEach((t) => t.stop());
              onSkip();
            }} disabled={busy}
              className="press-btn w-full py-2 rounded-xl text-xs"
              style={{ background: T.surfaceAlt, color: T.muted, border: `1px solid ${T.border}`, fontFamily: FS }}>
              Зураггүйгээр үргэлжлүүлэх
            </button>
            <button onClick={() => {
              if (stream) stream.getTracks().forEach((t) => t.stop());
              onCancel();
            }} disabled={busy}
              className="press-btn w-full py-2 rounded-xl text-xs"
              style={{ color: T.err, fontFamily: FS }}>
              Цуцлах
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function NotificationManager({ profile }) {
  const [toast, setToast] = useState(null); // { title, body, link }
  const [permState, setPermState] = useState(typeof Notification !== "undefined" ? Notification.permission : "default");
  const [showPrompt, setShowPrompt] = useState(false);

  // Push subscription
  useEffect(() => {
    if (!profile?.id) return;
    if (typeof Notification === "undefined") return;
    if (!("serviceWorker" in navigator) || !("PushManager" in window)) return;

    // Хэрэглэгч хараахан зөвшөөрөл өгөөгүй бол → 5 секундын дараа prompt
    if (Notification.permission === "default") {
      const dismissed = localStorage.getItem("orgoo-notif-dismissed");
      if (!dismissed) {
        const timer = setTimeout(() => setShowPrompt(true), 5000);
        return () => clearTimeout(timer);
      }
    } else if (Notification.permission === "granted") {
      subscribeUser(profile.id);
    }
  }, [profile?.id]);

  // Realtime in-app notifications listener
  useEffect(() => {
    if (!profile?.id) return;

    // Initial: read latest unread
    supabase.from("notifications")
      .select("*")
      .eq("user_id", profile.id)
      .eq("read", false)
      .order("created_at", { ascending: false })
      .limit(1)
      .then(({ data }) => {
        if (data && data[0]) {
          // Last-shown ID-г localStorage-д хадгалж дараа дараагүй болгоно
          const lastShown = localStorage.getItem("orgoo-last-notif-id");
          if (lastShown !== data[0].id) {
            // Анхны нэвтрэн орох үед дахин гаргахгүй
          }
        }
      });

    const ch = supabase.channel(`notif-${profile.id}`)
      .on("postgres_changes", {
        event: "INSERT", schema: "public", table: "notifications",
        filter: `user_id=eq.${profile.id}`,
      }, (payload) => {
        const n = payload.new;
        setToast({ title: n.title, body: n.body, link: n.link, id: n.id });
        // Sound (pleasant ding-dong)
        playNotificationSound();
        // Auto dismiss
        setTimeout(() => setToast((t) => (t?.id === n.id ? null : t)), 6000);
      })
      .subscribe();

    return () => { supabase.removeChannel(ch); };
  }, [profile?.id]);

  // Subscribe to push (after user grants permission)
  const subscribeUser = async (userId) => {
    if (!VAPID_PUBLIC_KEY) {
      console.warn("VAPID_PUBLIC_KEY байхгүй — push subscription алгасъя");
      return;
    }
    try {
      const reg = await navigator.serviceWorker.ready;
      let sub = await reg.pushManager.getSubscription();

      if (!sub) {
        sub = await reg.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
        });
      }

      const subJson = sub.toJSON();
      // Хадгалах
      await supabase.from("push_subscriptions").upsert({
        user_id: userId,
        endpoint: subJson.endpoint,
        p256dh: subJson.keys.p256dh,
        auth: subJson.keys.auth,
        user_agent: navigator.userAgent,
        last_used_at: new Date().toISOString(),
      }, { onConflict: "user_id,endpoint" });
    } catch (e) {
      console.error("Push subscribe error:", e);
    }
  };

  const requestPermission = async () => {
    setShowPrompt(false);
    try {
      const result = await Notification.requestPermission();
      setPermState(result);
      if (result === "granted") {
        await subscribeUser(profile.id);
      }
    } catch (e) {
      console.error(e);
    }
  };

  const dismissPrompt = () => {
    setShowPrompt(false);
    localStorage.setItem("orgoo-notif-dismissed", "1");
  };

  const markRead = async (id) => {
    await supabase.from("notifications").update({ read: true }).eq("id", id);
  };

  return (
    <>
      {/* Permission prompt */}
      {showPrompt && permState === "default" && (
        <div className="fixed top-4 left-1/2 -translate-x-1/2 z-50 max-w-md w-[95%] slide-up">
          <div className="glass-strong rounded-2xl p-4 flex items-start gap-3"
               style={{ boxShadow: "0 12px 40px rgba(99, 102, 241, 0.25)" }}>
            <div style={{
              background: "#0E9C8E",
              boxShadow: "0 4px 12px rgba(99, 102, 241, 0.4)",
            }} className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0">
              <span style={{ fontSize: 18 }}>🔔</span>
            </div>
            <div className="flex-1 min-w-0">
              <div style={{ fontFamily: FS, fontWeight: 600 }} className="text-sm mb-1">Мэдэгдэл идэвхжүүлэх үү?</div>
              <p style={{ color: T.muted }} className="text-[11px] leading-relaxed mb-3">
                Чөлөө/хүсэлт зөвшөөрөгдсөн үед автомат мэдэгдэл хүлээж авна
              </p>
              <div className="flex gap-2">
                <button onClick={dismissPrompt}
                  className="glass-soft press-btn flex-1 py-2 rounded-lg text-[10px] uppercase tracking-[0.15em]"
                  style={{ fontFamily: FM, color: T.muted }}>
                  Үгүй
                </button>
                <button onClick={requestPermission}
                  className="glow-primary press-btn flex-1 py-2 rounded-lg text-[10px] uppercase tracking-[0.15em] font-medium"
                  style={{ fontFamily: FM }}>
                  Зөвшөөрөх
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* In-app toast */}
      {toast && (
        <div className="fixed top-4 right-4 z-50 max-w-sm w-[95%] sm:w-auto slide-up">
          <button onClick={() => { markRead(toast.id); setToast(null); }}
            className="glass-strong rounded-2xl p-4 flex items-start gap-3 w-full text-left lift"
            style={{ boxShadow: "0 12px 40px rgba(99, 102, 241, 0.3)", borderColor: "rgba(99,102,241,0.3)" }}>
            <div style={{
              background: "#0E9C8E",
              boxShadow: "0 4px 12px rgba(99, 102, 241, 0.4)",
            }} className="w-10 h-10 rounded-xl flex items-center justify-center shrink-0">
              <span style={{ fontSize: 18 }}>🔔</span>
            </div>
            <div className="flex-1 min-w-0">
              <div style={{ fontFamily: FS, fontWeight: 600 }} className="text-sm mb-0.5">{toast.title}</div>
              {toast.body && <p style={{ color: T.muted }} className="text-xs leading-relaxed line-clamp-2">{toast.body}</p>}
            </div>
            <button onClick={(e) => { e.stopPropagation(); setToast(null); }}
              style={{ color: T.muted }} className="p-1 rounded-full hover:bg-black/10 shrink-0">
              <X size={14} />
            </button>
          </button>
        </div>
      )}
    </>
  );
}

