// ═══════════════════════════════════════════════════════════════════════════
//  OPERATOR KPI VIEW — Хувийн дашборд
// ═══════════════════════════════════════════════════════════════════════════
function OperatorKPIView({ profile }) {
  const [calls, setCalls] = useState([]);
  const [orders, setOrders] = useState([]);
  const [phoneFirstOp, setPhoneFirstOp] = useState({}); // утас → анх бүртгэсэн оператор id
  const [loading, setLoading] = useState(true);

  const [period, setPeriod] = useState(() => {
    try { return localStorage.getItem("orgoo-operator-period") || "today"; } catch { return "today"; }
  });
  const [customStart, setCustomStart] = useState(() => new Date().toISOString().slice(0, 10));
  const [customEnd, setCustomEnd] = useState(() => new Date().toISOString().slice(0, 10));

  useEffect(() => {
    try { localStorage.setItem("orgoo-operator-period", period); } catch {}
  }, [period]);

  const periodRange = useMemo(() => {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0, 0);
    const tomorrow = new Date(today); tomorrow.setDate(today.getDate() + 1);

    if (period === "today") return { start: today, end: tomorrow, label: "Өнөөдөр" };
    if (period === "yesterday") {
      const y = new Date(today); y.setDate(today.getDate() - 1);
      return { start: y, end: today, label: "Өчигдөр" };
    }
    if (period === "week") {
      const start = new Date(today); start.setDate(today.getDate() - 6);
      return { start, end: tomorrow, label: "7 хоног" };
    }
    if (period === "month") {
      const start = new Date(today.getFullYear(), today.getMonth(), 1);
      return { start, end: tomorrow, label: "Энэ сар" };
    }
    if (period === "custom") {
      const [sy, sm, sd] = customStart.split("-").map(Number);
      const [ey, em, ed] = customEnd.split("-").map(Number);
      return {
        start: new Date(sy, sm - 1, sd, 0, 0, 0),
        end: new Date(ey, em - 1, ed + 1, 0, 0, 0),
        label: `${customStart} – ${customEnd}`,
      };
    }
    return { start: new Date(0), end: new Date(8640000000000000), label: "Бүгд" };
  }, [period, customStart, customEnd]);

  useEffect(() => {
    (async () => {
      setLoading(true);
      try {
        // Дуудлагууд
        const { data: callData } = await supabase.from("biz_calls").select("*").eq("created_by", profile.id);
        // Захиалгууд — taken_by ЭСВЭЛ operator_id (driver-аас оноосон)
        const { data: ordData } = await supabase.from("biz_orders").select("*").or(`taken_by.eq.${profile.id},operator_id.eq.${profile.id}`);
        setCalls(callData || []);
        setOrders(ordData || []);

        // 🔗 "Бүртгэсэн дугаар" Admin-тай ижил болгох: өөрийн pending утаснуудыг
        //    ӨӨР хэн нэгэн түүнээс өмнө бүртгэсэн эсэхийг шалгах (давхардлаас сэргийлнэ).
        const myPendingPhones = [...new Set(
          (callData || [])
            .filter((c) => (c.call_status === "pending" || !c.call_status) && c.phone)
            .map((c) => c.phone)
        )];
        if (myPendingPhones.length > 0) {
          const allForPhones = await fetchInChunks("biz_calls", myPendingPhones, {
            select: "phone, created_by, call_status, created_at",
            filterColumn: "phone",
          });
          // Утас бүрийн анхны pending бүртгэгч
          const firstOp = {};
          (allForPhones || [])
            .filter((c) => c.phone && c.created_by && (c.call_status === "pending" || !c.call_status))
            .sort((a, b) => new Date(a.created_at) - new Date(b.created_at))
            .forEach((c) => { if (!firstOp[c.phone]) firstOp[c.phone] = c.created_by; });
          setPhoneFirstOp(firstOp);
        }
      } catch (e) { console.error(e); }
      finally { setLoading(false); }
    })();
  }, [profile.id]);

  // Period-ээр шүүх
  const filteredCalls = useMemo(() => calls.filter((c) => {
    const d = new Date(c.created_at);
    return d >= periodRange.start && d < periodRange.end;
  }), [calls, periodRange]);

  const filteredOrders = useMemo(() => orders.filter((o) => {
    const d = new Date(o.created_at);
    return d >= periodRange.start && d < periodRange.end;
  }), [orders, periodRange]);

  // Stats — "Бүртгэсэн дугаар" = өөрийн АНХ бүртгэсэн (pending) дуудлагын unique утас.
  //   ⚠ Admin-тай ижил: зөвхөн ӨӨР хэн нэгэн өмнө бүртгээгүй (анх би бүртгэсэн) утас.
  const uniquePhones = new Set(
    filteredCalls
      .filter((c) => (c.call_status === "pending" || !c.call_status) && c.phone)
      .filter((c) => !phoneFirstOp[c.phone] || phoneFirstOp[c.phone] === profile.id)
      .map((c) => c.phone)
  ).size;
  // ☎ "Нийт залгалт" = оператор ҮНЭХЭЭР залгасан (pending = зүгээр бүртгэсэн, хасна) — Admin-тай ижил
  const totalCalls = filteredCalls.filter((c) =>
    c.call_status === "no_answer" || c.call_status === "unreachable" ||
    c.call_status === "callback" || c.call_status === "ordered" ||
    c.call_status === "cancelled"
  ).length;
  const totalOrders = filteredOrders.filter((o) => o.status !== "cancelled").length; // Захиалга = цуцлагдаагүй (Admin-тай ижил)
  const deliveredOrders = filteredOrders.filter((o) => o.status === "delivered").length;
  const pendingOrders = filteredOrders.filter((o) => o.status === "new" || o.status === "pending" || o.status === "assigned").length;
  const cancelledOrders = filteredOrders.filter((o) => o.status === "cancelled").length;
  // Хувь тооцоход нийт захиалга (цуцлагдсаныг ОРУУЛНА) ашиглана
  const allOrdersCount = filteredOrders.length;
  const successRate = allOrdersCount > 0 ? Math.round((deliveredOrders / allOrdersCount) * 100) : 0;
  const cancelRate = allOrdersCount > 0 ? Math.round((cancelledOrders / allOrdersCount) * 100) : 0;
  const pendingRate = allOrdersCount > 0 ? Math.round((pendingOrders / allOrdersCount) * 100) : 0;
  const totalRevenue = filteredOrders
    .filter((o) => o.status === "delivered")
    .reduce((s, o) => s + Number(o.total_amount || 0), 0);
  const conversion = uniquePhones > 0 ? Math.round((totalOrders / uniquePhones) * 100) : 0;
  
  // ⭐ Үнэлгээний stats — driver-аас үнэлсэн захиалгууд
  const ratedOrders = filteredOrders.filter((o) => o.operator_rating != null);
  const totalRatings = ratedOrders.length;
  const avgRating = totalRatings > 0 
    ? (ratedOrders.reduce((s, o) => s + Number(o.operator_rating || 0), 0) / totalRatings).toFixed(1)
    : "—";
  const ratingDistribution = [1, 2, 3, 4, 5].reduce((acc, star) => {
    acc[star] = ratedOrders.filter((o) => o.operator_rating === star).length;
    return acc;
  }, {});

  return (
    <div className="space-y-3">
      {/* Operator header */}
      <div style={{ background: "linear-gradient(135deg, #6366f1, #8b5cf6)", color: "white" }}
        className="rounded-2xl p-5 flex items-center gap-4">
        <div style={{ background: "rgba(255,255,255,0.2)", color: "white" }}
          className="w-14 h-14 rounded-full flex items-center justify-center text-2xl flex-shrink-0">
          🎧
        </div>
        <div className="flex-1 min-w-0">
          <h2 style={{ fontFamily: FS, fontWeight: 700 }} className="text-xl">
            {profile.name || "Оператор"}
          </h2>
          <div style={{ opacity: 0.85, fontFamily: FM }} className="text-xs">
            {profile.job_title || "Оператор"}
          </div>
        </div>
      </div>

      {/* Period selector */}
      <div className="glass rounded-2xl p-3">
        <div className="flex items-center gap-2 flex-wrap">
          <span style={{ color: T.muted, fontFamily: FM }} className="text-xs">🕐 Хугацаа:</span>
          {[
            { id: "today", label: "Өнөөдөр" },
            { id: "yesterday", label: "Өчигдөр" },
            { id: "week", label: "7 хоног" },
            { id: "month", label: "Энэ сар" },
            { id: "all", label: "Бүгд" },
            { id: "custom", label: "📅 Гараар" },
          ].map((p) => (
            <button key={p.id} onClick={() => setPeriod(p.id)}
              className="press-btn px-3 py-1.5 rounded-full text-xs"
              style={{
                background: period === p.id ? T.highlight : T.surfaceAlt,
                color: period === p.id ? "white" : T.ink,
                fontFamily: FS, fontWeight: 600,
              }}>
              {p.label}
            </button>
          ))}
          {period === "custom" && (
            <div className="flex items-center gap-1">
              <input type="date" value={customStart} onChange={(e) => setCustomStart(e.target.value)}
                style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FM }}
                className="px-2 py-1 rounded text-xs" />
              <span style={{ color: T.muted }}>→</span>
              <input type="date" value={customEnd} onChange={(e) => setCustomEnd(e.target.value)}
                style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FM }}
                className="px-2 py-1 rounded text-xs" />
            </div>
          )}
        </div>
      </div>

      {loading ? (
        <div className="glass rounded-2xl p-8 text-center">
          <Loader2 className="spin mx-auto" size={20} style={{ color: T.muted }} />
        </div>
      ) : (
        <>
          {/* 4 том стат карт */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
            <div className="glass rounded-2xl p-4" style={{ borderLeft: `3px solid ${T.highlight}` }}>
              <div style={{ background: T.highlightSoft, color: T.highlight }}
                className="w-9 h-9 rounded-xl flex items-center justify-center mb-2">
                <Phone size={16} />
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }} className="text-4xl tabular-nums">
                {uniquePhones}
              </div>
              <div style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-sm mt-1">
                Бүртгэсэн дугаар
              </div>
            </div>

            <div className="glass rounded-2xl p-4" style={{ borderLeft: `3px solid #9333ea` }}>
              <div style={{ background: "rgba(147,51,234,0.1)", color: "#9333ea" }}
                className="w-9 h-9 rounded-xl flex items-center justify-center mb-2">
                <ShoppingBag size={16} />
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: "#9333ea" }} className="text-4xl tabular-nums">
                {totalOrders}
              </div>
              <div style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-sm mt-1">
                Бүртгэсэн захиалга
              </div>
            </div>

            <div className="glass rounded-2xl p-4" style={{ borderLeft: `3px solid ${T.ok}` }}>
              <div style={{ background: "rgba(16,185,129,0.1)", color: T.ok }}
                className="w-9 h-9 rounded-xl flex items-center justify-center mb-2">
                <CheckCircle2 size={16} />
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.ok }} className="text-4xl tabular-nums">
                {deliveredOrders}
              </div>
              <div style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-sm mt-1">
                Амжилттай хүргэгдсэн
              </div>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] mt-0.5">
                {successRate}% амжилт
              </div>
            </div>

            <div className="glass rounded-2xl p-4" style={{ borderLeft: `3px solid ${T.err}` }}>
              <div style={{ background: T.errSoft, color: T.err }}
                className="w-9 h-9 rounded-xl flex items-center justify-center mb-2">
                <X size={16} />
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.err }} className="text-4xl tabular-nums">
                {cancelledOrders}
              </div>
              <div style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-sm mt-1">
                Амжилтгүй
              </div>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] mt-0.5">
                Цуцлагдсан / татгалзсан
              </div>
            </div>
          </div>

          {/* Гүйцэтгэлийн харьцаа */}
          <div className="glass rounded-2xl p-4">
            <div style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-sm mb-3 flex items-center gap-2">
              📊 Гүйцэтгэлийн харьцаа
            </div>
            <div className="space-y-3">
              <div>
                <div className="flex items-center justify-between mb-1">
                  <div className="flex items-center gap-2">
                    <span style={{ background: T.ok }} className="w-2 h-2 rounded-full" />
                    <span style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-xs">Хүргэгдсэн</span>
                    <span style={{ color: T.muted, fontFamily: FD, fontWeight: 600 }} className="text-xs tabular-nums">{deliveredOrders}</span>
                  </div>
                  <span style={{ color: T.ok, fontFamily: FD, fontWeight: 700 }} className="text-xs tabular-nums">{successRate}%</span>
                </div>
                <div style={{ background: T.surfaceAlt, height: 6, borderRadius: 3 }}>
                  <div style={{ width: `${successRate}%`, height: "100%", background: T.ok, borderRadius: 3, transition: "width 0.5s" }} />
                </div>
              </div>

              <div>
                <div className="flex items-center justify-between mb-1">
                  <div className="flex items-center gap-2">
                    <span style={{ background: T.warn }} className="w-2 h-2 rounded-full" />
                    <span style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-xs">Хүргэлтэнд</span>
                    <span style={{ color: T.muted, fontFamily: FD, fontWeight: 600 }} className="text-xs tabular-nums">{pendingOrders}</span>
                  </div>
                  <span style={{ color: T.warn, fontFamily: FD, fontWeight: 700 }} className="text-xs tabular-nums">{pendingRate}%</span>
                </div>
                <div style={{ background: T.surfaceAlt, height: 6, borderRadius: 3 }}>
                  <div style={{ width: `${pendingRate}%`, height: "100%", background: T.warn, borderRadius: 3, transition: "width 0.5s" }} />
                </div>
              </div>

              <div>
                <div className="flex items-center justify-between mb-1">
                  <div className="flex items-center gap-2">
                    <span style={{ background: T.err }} className="w-2 h-2 rounded-full" />
                    <span style={{ color: T.ink, fontFamily: FS, fontWeight: 500 }} className="text-xs">Цуцлагдсан</span>
                    <span style={{ color: T.muted, fontFamily: FD, fontWeight: 600 }} className="text-xs tabular-nums">{cancelledOrders}</span>
                  </div>
                  <span style={{ color: T.err, fontFamily: FD, fontWeight: 700 }} className="text-xs tabular-nums">{cancelRate}%</span>
                </div>
                <div style={{ background: T.surfaceAlt, height: 6, borderRadius: 3 }}>
                  <div style={{ width: `${cancelRate}%`, height: "100%", background: T.err, borderRadius: 3, transition: "width 0.5s" }} />
                </div>
              </div>
            </div>
          </div>

          {/* Доод стат */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-2">
            <div className="glass rounded-xl p-3 text-center">
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider">Нийт залгалт</div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: "#3b82f6" }} className="text-xl tabular-nums">
                {totalCalls}
              </div>
            </div>
            <div className="glass rounded-xl p-3 text-center">
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider">Нийт орлого</div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.ok }} className="text-xl tabular-nums">
                {totalRevenue.toLocaleString()}₮
              </div>
            </div>
            <div className="glass rounded-xl p-3 text-center">
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider">Conversion</div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }} className="text-xl tabular-nums">
                {conversion}%
              </div>
            </div>
            <div className="glass rounded-xl p-3 text-center">
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider">Хүлээгдэж</div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.warn }} className="text-xl tabular-nums">
                {pendingOrders}
              </div>
            </div>
          </div>

          {/* ⭐ Үнэлгээ хэсэг */}
          <div className="glass rounded-2xl p-4" style={{ borderLeft: `3px solid ${avgRating !== "—" && Number(avgRating) >= 4 ? T.ok : avgRating !== "—" && Number(avgRating) >= 3 ? T.warn : T.err}` }}>
            <div className="flex items-center justify-between mb-3">
              <div style={{ color: T.ink, fontFamily: FS, fontWeight: 700 }} className="text-base flex items-center gap-2">
                ⭐ Хүргэгчийн үнэлгээ
              </div>
              <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                {totalRatings} үнэлгээ
              </span>
            </div>
            
            {totalRatings === 0 ? (
              <div className="text-center py-4">
                <div className="text-3xl mb-1 opacity-40">☆</div>
                <div style={{ color: T.muted, fontFamily: FS }} className="text-xs">
                  Хараахан үнэлгээ ороогүй
                </div>
              </div>
            ) : (
              <>
                {/* Дундаж үнэлгээ */}
                <div className="flex items-center gap-3 mb-3">
                  <div className="flex-shrink-0">
                    <div style={{ 
                      fontFamily: FD, fontWeight: 700,
                      color: Number(avgRating) >= 4 ? T.ok : Number(avgRating) >= 3 ? T.warn : T.err,
                    }} className="text-4xl tabular-nums leading-none">
                      {avgRating}
                    </div>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] mt-1">
                      / 5.0
                    </div>
                  </div>
                  <div className="flex-1">
                    <div className="flex gap-0.5 mb-1">
                      {[1, 2, 3, 4, 5].map((star) => (
                        <span key={star} style={{ 
                          fontSize: 18,
                          opacity: Number(avgRating) >= star ? 1 : 0.25,
                        }}>
                          ⭐
                        </span>
                      ))}
                    </div>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px]">
                      Дундаж үнэлгээ
                    </div>
                  </div>
                </div>

                {/* Тарагуул — star тус бүрд барик */}
                <div className="space-y-1">
                  {[5, 4, 3, 2, 1].map((star) => {
                    const count = ratingDistribution[star] || 0;
                    const pct = totalRatings > 0 ? Math.round((count / totalRatings) * 100) : 0;
                    return (
                      <div key={star} className="flex items-center gap-2">
                        <span style={{ fontFamily: FD, fontWeight: 600, color: T.ink, width: 20 }} className="text-xs tabular-nums">
                          {star}⭐
                        </span>
                        <div style={{ flex: 1, background: T.surfaceAlt, height: 8, borderRadius: 4, overflow: "hidden" }}>
                          <div style={{
                            width: `${pct}%`,
                            height: "100%",
                            background: star >= 4 ? T.ok : star >= 3 ? T.warn : T.err,
                            transition: "width 0.3s",
                          }} />
                        </div>
                        <span style={{ fontFamily: FD, color: T.muted, width: 32, textAlign: "right" }} className="text-[10px] tabular-nums">
                          {count}
                        </span>
                      </div>
                    );
                  })}
                </div>

                {/* Сүүлийн комментууд */}
                {ratedOrders.filter((o) => o.operator_rating_note).length > 0 && (
                  <div className="mt-3 pt-3" style={{ borderTop: `1px solid ${T.border}` }}>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mb-2">
                      💬 Сүүлийн тэмдэглэлүүд
                    </div>
                    <div className="space-y-1.5 max-h-40 overflow-y-auto">
                      {ratedOrders
                        .filter((o) => o.operator_rating_note)
                        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at))
                        .slice(0, 5)
                        .map((o) => (
                          <div key={o.id} className="rounded-lg p-2" style={{ background: T.surfaceAlt }}>
                            <div className="flex items-center justify-between mb-0.5">
                              <span style={{ fontSize: 12 }}>
                                {Array(o.operator_rating).fill("⭐").join("")}
                              </span>
                              <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">
                                {new Date(o.created_at).toLocaleDateString("mn-MN")}
                              </span>
                            </div>
                            <div style={{ color: T.ink, fontFamily: FS, fontStyle: "italic" }} className="text-[11px]">
                              "{o.operator_rating_note}"
                            </div>
                          </div>
                        ))}
                    </div>
                  </div>
                )}
              </>
            )}
          </div>
        </>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  DRIVER DASHBOARD — Зөвхөн өөрт оноосон хүргэлт
// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
//  DRIVER WAREHOUSE VIEW — Driver-ийн өөрийн агуулахын нөөц
// ═══════════════════════════════════════════════════════════════════════════
function DriverWarehouseView({ profile }) {
  const [warehouse, setWarehouse] = useState(null);
  const [stock, setStock] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [showZero, setShowZero] = useState(false); // 📦 Үлдэгдэлгүй бараа харуулах эсэх

  const loadAll = async () => {
    setLoading(true);
    try {
      const { data: whData } = await supabase
        .from("inv_warehouses")
        .select("*")
        .eq("driver_id", profile.id)
        .single();
      setWarehouse(whData);

      if (whData) {
        const [{ data: stkData }, { data: prdData }] = await Promise.all([
          supabase.from("inv_stock").select("*").eq("warehouse_id", whData.id),
          supabase.from("inv_products").select("id, name, sku, image_url").eq("is_active", true),
        ]);
        setStock(stkData || []);
        setProducts(prdData || []);
      }
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { loadAll(); }, []);

  const stockData = stock
    .map((s) => ({ ...s, product: products.find((p) => p.id === s.product_id) }))
    .filter((x) => x.product);

  // 🎯 Үлдэгдэлтэй бараа л үзүүлэх (default), эс бол бүгд
  const stockDataVisible = showZero
    ? stockData
    : stockData.filter((x) => Number(x.quantity || 0) > 0);

  const filtered = search.trim()
    ? stockDataVisible.filter((s) =>
        s.product.name?.toLowerCase().includes(search.toLowerCase()) ||
        s.product.sku?.toLowerCase().includes(search.toLowerCase())
      )
    : stockDataVisible;

  if (loading) {
    return (
      <div className="glass rounded-2xl p-8 text-center">
        <Loader2 className="spin mx-auto" size={20} style={{ color: T.muted }} />
      </div>
    );
  }

  if (!warehouse) {
    return (
      <div className="glass rounded-2xl p-8 text-center">
        <div className="text-4xl mb-2">⚠</div>
        <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
          Танд агуулах байгуулагдаагүй байна
        </div>
      </div>
    );
  }

  const totalQty = stockData.reduce((s, x) => s + Number(x.quantity || 0), 0);
  const lowStock = stockData.filter((x) => Number(x.quantity) > 0 && Number(x.quantity) <= 5).length;
  const outStock = stockData.filter((x) => Number(x.quantity) <= 0).length;

  return (
    <div className="space-y-3">
      {/* Header */}
      <div className="glass rounded-2xl p-3 flex items-center gap-3">
        <div style={{ background: "linear-gradient(135deg, #0ea5e9, #0284c7)", color: "white" }}
          className="w-10 h-10 rounded-full flex items-center justify-center text-base font-bold flex-shrink-0">
          🚚
        </div>
        <div className="flex-1 min-w-0">
          <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-sm">
            {warehouse.name}
          </div>
          <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px]">
            Миний агуулах
          </div>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-2">
        <div className="glass rounded-2xl p-3 text-center">
          <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase">Нийт</div>
          <div style={{ fontFamily: FD, fontWeight: 700, color: "#0ea5e9" }} className="text-2xl tabular-nums">
            {totalQty}
          </div>
        </div>
        <div className="glass rounded-2xl p-3 text-center">
          <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase">⚠ Бага</div>
          <div style={{ fontFamily: FD, fontWeight: 700, color: T.warn }} className="text-2xl tabular-nums">
            {lowStock}
          </div>
        </div>
        <div className="glass rounded-2xl p-3 text-center">
          <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase">✕ Дууссан</div>
          <div style={{ fontFamily: FD, fontWeight: 700, color: T.err }} className="text-2xl tabular-nums">
            {outStock}
          </div>
        </div>
      </div>

      {/* Search */}
      {stockData.length > 5 && (
        <input value={search} onChange={(e) => setSearch(e.target.value)}
          placeholder="🔍 Бараа хайх..."
          style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS }}
          className="w-full px-3 py-2 rounded-lg text-sm" />
      )}

      {/* 🎯 Үлдэгдэлгүй бараа toggle */}
      {stockData.some((x) => Number(x.quantity || 0) <= 0) && (
        <button onClick={() => setShowZero(!showZero)}
          className="press-btn w-full px-3 py-2 rounded-lg text-xs flex items-center justify-between"
          style={{
            background: showZero ? T.warnSoft : T.surfaceAlt,
            border: `1px solid ${showZero ? T.warn : T.border}`,
            color: T.ink, fontFamily: FS, fontWeight: 600,
          }}>
          <span className="flex items-center gap-2">
            <span>{showZero ? "👁" : "🙈"}</span>
            <span>{showZero ? "Бүх бараа харуулж байна" : "Үлдэгдэлгүй бараа нуусан"}</span>
          </span>
          <span style={{ color: T.muted, fontSize: 10 }}>
            {showZero ? "Нуух →" : "Харуулах →"}
          </span>
        </button>
      )}

      {/* Stock list */}
      {filtered.length === 0 ? (
        <div className="glass rounded-2xl p-8 text-center">
          <div className="text-4xl mb-2">📦</div>
          <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
            {search ? "Олдсонгүй" : "Бараа байхгүй"}
          </div>
        </div>
      ) : (
        <div className="space-y-1.5">
          {filtered
            .sort((a, b) => Number(a.quantity) - Number(b.quantity))
            .map((s) => (
              <div key={s.id} className="glass rounded-xl p-2.5 flex items-center gap-3">
                {s.product.image_url && (
                  <img src={s.product.image_url} alt=""
                    style={{ width: 36, height: 48, objectFit: "cover", borderRadius: 6 }} />
                )}
                <div className="flex-1 min-w-0">
                  <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-sm truncate">
                    {s.product.name}
                  </div>
                  {s.product.sku && (
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                      {s.product.sku}
                    </div>
                  )}
                </div>
                <div className="text-right flex-shrink-0">
                  <div style={{
                    fontFamily: FD, fontWeight: 700,
                    color: Number(s.quantity) <= 0 ? T.err : Number(s.quantity) <= 5 ? T.warn : T.ok,
                  }} className="text-lg tabular-nums">
                    {Number(s.quantity)}
                  </div>
                  <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">ширхэг</div>
                </div>
              </div>
            ))}
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  DRIVER REQUESTS VIEW — Хүргэгчийн бараа хүсэлт
// ═══════════════════════════════════════════════════════════════════════════
function DriverRequestsView({ profile }) {
  const [requests, setRequests] = useState([]);
  const [items, setItems] = useState({});
  const [warehouses, setWarehouses] = useState([]);
  const [products, setProducts] = useState([]);
  const [stock, setStock] = useState([]);
  const [myWarehouse, setMyWarehouse] = useState(null);
  const [loading, setLoading] = useState(true);
  const [showNewModal, setShowNewModal] = useState(false);
  const [isReturn, setIsReturn] = useState(false);
  const [activeRequest, setActiveRequest] = useState(null); // detail modal-руу нээх хүсэлт

  const loadAll = async () => {
    setLoading(true);
    try {
      // Эхлээд driver-ийн warehouse-ыг олох
      const { data: whData, error: whErr } = await supabase.from("inv_warehouses").select("*");
      if (whErr) console.error("Warehouse fetch error:", whErr);
      const myWh = (whData || []).find((w) => w.driver_id === profile.id);
      
      // Хүсэлтүүдийг татах:
      // 1. Driver өөрөө үүсгэсэн (requester_id = profile.id)
      // 2. Driver-ийн агуулахтай холбогдсон (admin-аас үүссэн)
      let reqQuery = supabase.from("inv_transfer_requests").select("*");
      if (myWh) {
        reqQuery = reqQuery.or(
          `requester_id.eq.${profile.id},from_warehouse_id.eq.${myWh.id},to_warehouse_id.eq.${myWh.id}`
        );
      } else {
        reqQuery = reqQuery.eq("requester_id", profile.id);
      }
      
      const [{ data: reqData, error: reqErr }, { data: prdData, error: prdErr }, { data: stkData, error: stkErr }] = await Promise.all([
        reqQuery.order("created_at", { ascending: false }),
        supabase.from("inv_products").select("id, name, sku, image_url, sale_price, category_id").eq("is_active", true),
        supabase.from("inv_stock").select("*"),
      ]);
      if (reqErr) console.error("Request fetch error:", reqErr);
      if (prdErr) console.error("Product fetch error:", prdErr);
      if (stkErr) console.error("Stock fetch error:", stkErr);
      logDev("Loaded:", {
        requests: reqData?.length,
        warehouses: whData?.length,
        products: prdData?.length,
        stock: stkData?.length,
      });
      setRequests(reqData || []);
      setWarehouses(whData || []);
      setProducts(prdData || []);
      setStock(stkData || []);
      setMyWarehouse(myWh);

      if (reqData && reqData.length > 0) {
        const ids = reqData.map((r) => r.id);
        const itemData = await fetchInChunks("inv_transfer_items", ids, {
          select: "*", filterColumn: "request_id", chunkSize: 200,
        });
        const map = {};
        (itemData || []).forEach((i) => {
          if (!map[i.request_id]) map[i.request_id] = [];
          map[i.request_id].push(i);
        });
        setItems(map);
      }
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { loadAll(); }, []);

  // Realtime — admin хүсэлт үүсгэхэд driver шууд харах
  useEffect(() => {
    const channel = supabase
      .channel("driver-transfer-requests-realtime")
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "inv_transfer_requests" },
        () => { loadAll(); }
      )
      .subscribe();
    return () => { supabase.removeChannel(channel); };
  }, []);


  return (
    <div className="space-y-3">
      {/* Action buttons */}
      <div className="grid grid-cols-2 gap-2">
        <button onClick={() => { setIsReturn(false); setShowNewModal(true); }}
          className="press-btn glass lift rounded-2xl p-3 flex flex-col items-center gap-1.5"
          style={{ borderLeft: `3px solid #0ea5e9` }}>
          <div style={{ background: "rgba(14,165,233,0.1)", color: "#0ea5e9" }}
            className="w-10 h-10 rounded-full flex items-center justify-center text-lg">
            📨
          </div>
          <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-xs">
            Бараа авах
          </div>
          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] text-center">
            Төв агуулахаас авах хүсэлт
          </div>
        </button>
        <button onClick={() => { setIsReturn(true); setShowNewModal(true); }}
          className="press-btn glass lift rounded-2xl p-3 flex flex-col items-center gap-1.5"
          style={{ borderLeft: `3px solid ${T.warn}` }}>
          <div style={{ background: T.warnSoft, color: T.warn }}
            className="w-10 h-10 rounded-full flex items-center justify-center text-lg">
            🔄
          </div>
          <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-xs">
            Бараа буцаах
          </div>
          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] text-center">
            Төв агуулах руу буцаах
          </div>
        </button>
      </div>

      {/* Requests list */}
      {loading ? (
        <div className="glass rounded-2xl p-8 text-center">
          <Loader2 className="spin mx-auto" size={20} style={{ color: T.muted }} />
        </div>
      ) : requests.length === 0 ? (
        <div className="glass rounded-2xl p-8 text-center">
          <div className="text-4xl mb-2">📨</div>
          <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
            Хүсэлт байхгүй
          </div>
        </div>
      ) : (
        <div className="space-y-2">
          {requests.map((req) => {
            const reqItems = items[req.id] || [];
            const isFromAdmin = req.requester_id !== profile.id;
            const isPending = req.status === "pending";
            // Энэ хүсэлт driver-руу зориулагдсан уу? (admin-аас орж ирсэн)
            const isForMe = isFromAdmin && (
              (req.is_return && req.from_warehouse_id === myWarehouse?.id) ||  // admin: bara авах (driver агуулахаас)
              (!req.is_return && req.to_warehouse_id === myWarehouse?.id)      // admin: bara өгөх (driver агуулах руу)
            );
            return (
              <div key={req.id} className="glass rounded-2xl overflow-hidden"
                style={{
                  borderLeft: `4px solid ${
                    req.status === "pending" ? T.warn :
                    req.status === "completed" ? T.ok : T.err
                  }`,
                }}>
                {/* Header — clickable */}
                <div onClick={() => setActiveRequest(req)}
                  className="press-btn cursor-pointer p-3 pb-0">
                  <div className="flex items-center gap-2 mb-2">
                    <div style={{
                      background: req.is_return ? T.warnSoft : "rgba(14,165,233,0.1)",
                      color: req.is_return ? T.warn : "#0ea5e9",
                    }} className="w-9 h-9 rounded-full flex items-center justify-center text-base flex-shrink-0">
                      {req.is_return ? "🔄" : "📨"}
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-1.5 flex-wrap">
                        <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-sm">
                          {req.is_return ? "Бараа буцаах" : "Бараа авах"}
                        </div>
                        {isFromAdmin && (
                          <span style={{ 
                            background: "rgba(147,51,234,0.15)", 
                            color: "#9333ea", 
                            fontFamily: FS, fontWeight: 700 
                          }}
                            className="text-[9px] px-1.5 py-0.5 rounded-full">
                            👤 АДМИНААС
                          </span>
                        )}
                      </div>
                      <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                        {new Date(req.created_at).toLocaleString("mn-MN")}
                      </div>
                    </div>
                    <span style={{
                      background: req.status === "pending" ? T.warnSoft : req.status === "completed" ? "rgba(16,185,129,0.1)" : T.errSoft,
                      color: req.status === "pending" ? T.warn : req.status === "completed" ? T.ok : T.err,
                      fontFamily: FS, fontWeight: 600,
                    }} className="text-[10px] px-2 py-0.5 rounded-full">
                      {req.status === "pending" ? "⏳ Хүлээгдэж" : req.status === "completed" ? "✓ Зөвшөөрсөн" : "✕ Татгалзсан"}
                    </span>
                  </div>
                </div>

                {/* Бараанууд — тусдаа scroll-той (button-аас гадуур) */}
                <div className="flex gap-1.5 overflow-x-auto px-3 pb-1"
                  style={{ scrollbarWidth: "thin", WebkitOverflowScrolling: "touch" }}>
                  {reqItems.map((it) => {
                    const product = products.find((p) => p.id === it.product_id);
                    const imgUrl = product?.image_url;
                    return (
                      <div key={it.id} className="rounded-lg overflow-hidden flex-shrink-0"
                        style={{ background: T.surface, border: `1px solid ${T.border}`, width: 90 }}>
                        <div style={{ width: "100%", aspectRatio: "1/1", background: T.surfaceAlt }}>
                          {imgUrl ? (
                            <img src={imgUrl} alt={it.product_name}
                              style={{ width: "100%", height: "100%", objectFit: "contain" }} />
                          ) : (
                            <div style={{
                              width: "100%", height: "100%",
                              display: "flex", alignItems: "center", justifyContent: "center",
                              fontSize: 22,
                            }}>📦</div>
                          )}
                        </div>
                        <div className="p-1">
                          <div style={{ fontFamily: FS, fontWeight: 500, color: T.ink, minHeight: 22 }}
                            className="text-[9px] line-clamp-2">
                            {it.product_name}
                          </div>
                          <div style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }}
                            className="text-[10px] tabular-nums mt-0.5">
                            ×{Number(it.quantity)}
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>

                {req.notes && (
                  <div onClick={() => setActiveRequest(req)}
                    className="cursor-pointer px-3"
                    style={{ color: T.muted, fontFamily: FS, fontStyle: "italic" }}>
                    <div className="text-[11px] mt-2">"{req.notes}"</div>
                  </div>
                )}

                {/* Padding bottom (action товчнуудтай тохирох зориулалттай) */}
                <div className="h-2"></div>

                {/* Action товчнууд (зөвхөн admin-аас irсен pending хүсэлтэд) */}
                {isForMe && isPending && (
                  <div className="grid grid-cols-2 gap-2 p-3 pt-0">
                    <button onClick={async (e) => {
                      e.stopPropagation();
                      if (!confirm(`${req.is_return ? "Барааг буцаах" : "Барааг хүлээн авах"} уу?`)) return;
                      try {
                        // Stock movements үүсгэх
                        const movements = reqItems.map((it) => ({
                          product_id: it.product_id,
                          warehouse_id: req.from_warehouse_id,
                          to_warehouse_id: req.to_warehouse_id,
                          movement_type: "transfer",
                          quantity: Number(it.quantity),
                          reason: "approve_request",
                          notes: `Хүсэлт #${req.id.slice(0,8)} зөвшөөрсөн`,
                          created_by: profile.id,
                        }));
                        const { error: mvErr } = await supabase.from("inv_movements").insert(movements);
                        if (mvErr) throw mvErr;
                        
                        // Status шинэчлэх
                        const { error: updErr } = await supabase
                          .from("inv_transfer_requests")
                          .update({ status: "completed", approved_at: new Date().toISOString(), approved_by: profile.id })
                          .eq("id", req.id);
                        if (updErr) throw updErr;
                        
                        alert("✅ Хүсэлт зөвшөөрөгдлөө");
                        await loadAll();
                      } catch (e) {
                        if (e.message?.includes("үлдэгдэл хүрэлцэхгүй")) {
                          alert("⚠ Барааны үлдэгдэл хүрэлцэхгүй байна");
                        } else {
                          alert("Алдаа: " + e.message);
                        }
                      }
                    }}
                      className="press-btn py-2 rounded-lg text-xs font-semibold"
                      style={{ background: T.ok, color: "white", fontFamily: FS, fontWeight: 700 }}>
                      ✓ Зөвшөөрөх
                    </button>
                    <button onClick={async (e) => {
                      e.stopPropagation();
                      if (!confirm("Хүсэлтийг татгалзах уу?")) return;
                      try {
                        const { error } = await supabase
                          .from("inv_transfer_requests")
                          .update({ status: "rejected", approved_at: new Date().toISOString(), approved_by: profile.id })
                          .eq("id", req.id);
                        if (error) throw error;
                        alert("✕ Хүсэлт татгалзав");
                        await loadAll();
                      } catch (e) {
                        alert("Алдаа: " + e.message);
                      }
                    }}
                      className="press-btn py-2 rounded-lg text-xs font-semibold"
                      style={{ background: T.errSoft, color: T.err, border: `1px solid ${T.err}`, fontFamily: FS, fontWeight: 700 }}>
                      ✕ Татгалзах
                    </button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
      
      {/* Detail Modal */}
      {activeRequest && createPortal(
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 10000,
          display: "flex", alignItems: "flex-start", justifyContent: "center", padding: 12,
          background: "rgba(0,0,0,0.5)", backdropFilter: "blur(4px)",
          overflowY: "auto",
        }}
          onClick={() => setActiveRequest(null)}>
          <div style={{
            background: T.bg, borderRadius: 16, width: "100%", maxWidth: 480,
            marginTop: 12, marginBottom: 12,
            boxShadow: "0 24px 48px rgba(0,0,0,0.3)",
            maxHeight: "90vh", overflowY: "auto",
          }}
            onClick={(e) => e.stopPropagation()}>
            <div className="p-4">
              <div className="flex items-center justify-between mb-3">
                <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-base flex items-center gap-2">
                  <span>{activeRequest.is_return ? "🔄" : "📨"}</span>
                  <span>{activeRequest.is_return ? "Бараа буцаах хүсэлт" : "Бараа авах хүсэлт"}</span>
                </div>
                <button onClick={() => setActiveRequest(null)} style={{ color: T.muted }}>
                  <X size={18} />
                </button>
              </div>

              {/* Status row */}
              <div className="grid grid-cols-2 gap-2 mb-3">
                <div className="rounded-lg p-2" style={{ background: T.surfaceAlt }}>
                  <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase mb-0.5">Статус</div>
                  <div style={{ 
                    color: activeRequest.status === "pending" ? T.warn : activeRequest.status === "completed" ? T.ok : T.err,
                    fontFamily: FS, fontWeight: 700,
                  }} className="text-xs">
                    {activeRequest.status === "pending" ? "⏳ Хүлээгдэж буй" : activeRequest.status === "completed" ? "✓ Зөвшөөрсөн" : "✕ Татгалзсан"}
                  </div>
                </div>
                <div className="rounded-lg p-2" style={{ background: T.surfaceAlt }}>
                  <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase mb-0.5">Үүсгэсэн</div>
                  <div style={{ color: T.ink, fontFamily: FD, fontWeight: 600 }} className="text-xs">
                    {new Date(activeRequest.created_at).toLocaleDateString("mn-MN")} {new Date(activeRequest.created_at).toLocaleTimeString("mn-MN", { hour: '2-digit', minute: '2-digit' })}
                  </div>
                </div>
              </div>

              {/* Хаанаас → Хаашаа */}
              <div className="rounded-lg p-3 mb-3" style={{ background: T.surfaceAlt }}>
                <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase mb-2">📍 Шилжлэг</div>
                <div className="flex items-center justify-between gap-2">
                  <div className="flex-1 text-center">
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] mb-0.5">Хаанаас</div>
                    <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-xs">
                      {warehouses.find((w) => w.id === activeRequest.from_warehouse_id)?.name || "—"}
                    </div>
                  </div>
                  <div style={{ color: T.muted, fontFamily: FD }} className="text-2xl">→</div>
                  <div className="flex-1 text-center">
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] mb-0.5">Хаашаа</div>
                    <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-xs">
                      {warehouses.find((w) => w.id === activeRequest.to_warehouse_id)?.name || "—"}
                    </div>
                  </div>
                </div>
              </div>

              {/* Items list */}
              <div className="mb-3">
                <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mb-2">
                  📦 Бараанууд ({(items[activeRequest.id] || []).length})
                </div>
                <div className="space-y-1.5">
                  {(items[activeRequest.id] || []).map((it) => {
                    const product = products.find((p) => p.id === it.product_id);
                    const imgUrl = product?.image_url;
                    const price = product?.sale_price || 0;
                    return (
                      <div key={it.id} className="rounded-lg p-2 flex items-center gap-2"
                        style={{ background: T.surfaceAlt, border: `1px solid ${T.border}` }}>
                        <div className="w-12 h-12 rounded overflow-hidden flex-shrink-0"
                          style={{ background: T.bg }}>
                          {imgUrl ? (
                            <img src={imgUrl} alt={it.product_name}
                              style={{ width: "100%", height: "100%", objectFit: "contain" }}
                              onError={(e) => { e.target.style.display = "none"; }} />
                          ) : (
                            <div className="w-full h-full flex items-center justify-center text-2xl">📦</div>
                          )}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-xs truncate">
                            {it.product_name}
                          </div>
                          {it.product_sku && (
                            <div style={{ color: T.muted, fontFamily: FD }} className="text-[10px]">
                              {it.product_sku}
                              {price > 0 && ` · ${Number(price).toLocaleString()}₮`}
                            </div>
                          )}
                        </div>
                        <div className="text-right flex-shrink-0">
                          <div style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }} className="text-base tabular-nums">
                            ×{Number(it.quantity)}
                          </div>
                          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">ширхэг</div>
                        </div>
                      </div>
                    );
                  })}
                </div>
                {/* Нийт */}
                <div className="rounded-lg p-2 mt-2 flex justify-between items-center"
                  style={{ background: T.highlightSoft, border: `1px solid ${T.highlight}` }}>
                  <span style={{ fontFamily: FS, fontWeight: 600, color: T.highlight }} className="text-xs">
                    Нийт ширхэг
                  </span>
                  <span style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }} className="text-base tabular-nums">
                    {(items[activeRequest.id] || []).reduce((s, it) => s + Number(it.quantity || 0), 0)} ширхэг
                  </span>
                </div>
              </div>

              {activeRequest.notes && (
                <div className="rounded-lg p-2 mb-3" style={{ background: T.warnSoft, border: `1px solid ${T.warn}` }}>
                  <div style={{ color: T.warn, fontFamily: FM }} className="text-[9px] uppercase mb-0.5">📝 Тэмдэглэл</div>
                  <div style={{ color: T.ink, fontFamily: FS, fontStyle: "italic" }} className="text-xs">
                    "{activeRequest.notes}"
                  </div>
                </div>
              )}

              {/* Close button */}
              <button onClick={() => setActiveRequest(null)}
                className="press-btn w-full py-2.5 rounded-xl text-sm font-semibold"
                style={{ background: T.surfaceAlt, color: T.muted, border: `1px solid ${T.border}`, fontFamily: FS }}>
                Хаах
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* New request modal */}
      {showNewModal && myWarehouse && (
        <NewTransferRequestModal
          isReturn={isReturn}
          myWarehouse={myWarehouse}
          warehouses={warehouses}
          products={products}
          stock={stock}
          profile={profile}
          onSave={async () => {
            setShowNewModal(false);
            await loadAll();
          }}
          onClose={() => setShowNewModal(false)}
        />
      )}
    </div>
  );
}

// ─── Шинэ хүсэлт modal — Categories + Grid layout ────────────────
function NewTransferRequestModal({ isReturn, myWarehouse, warehouses, products, stock, profile, onSave, onClose }) {
  const mainWarehouse = warehouses.find((w) => w.type === "main");
  const [selectedItems, setSelectedItems] = useState([]);
  const [notes, setNotes] = useState("");
  const [search, setSearch] = useState("");
  const [busy, setBusy] = useState(false);
  const [calculating, setCalculating] = useState(true);
  const [autoNote, setAutoNote] = useState("");
  const [orderSummary, setOrderSummary] = useState(null);
  const [categories, setCategories] = useState([]);
  const [activeCat, setActiveCat] = useState("all");
  const [showSidebar, setShowSidebar] = useState(false); // mobile
  const [showAllProducts, setShowAllProducts] = useState(false); // false = зөвхөн хэрэгтэй, true = бүх бараа
  
  // Хүргэгчийн агуулахаас бусад агуулахуудыг сонгох боломжтой жагсаалт
  const otherWarehouses = warehouses.filter((w) => w.id !== myWarehouse?.id);
  
  // Default-аар үндсэн агуулах эсвэл эхний боломжит
  const [selectedOtherWhId, setSelectedOtherWhId] = useState(
    mainWarehouse?.id || otherWarehouses[0]?.id || null
  );

  const sourceWh = isReturn ? myWarehouse : warehouses.find((w) => w.id === selectedOtherWhId);
  const targetWh = isReturn ? warehouses.find((w) => w.id === selectedOtherWhId) : myWarehouse;

  // Categories load
  useEffect(() => {
    (async () => {
      const { data } = await supabase.from("inv_categories").select("id, name").order("name");
      setCategories(data || []);
    })();
  }, []);

  // Auto calculate
  useEffect(() => {
    (async () => {
      setCalculating(true);
      try {
        if (isReturn) {
          // БУЦААХ
          const myStock = stock.filter((s) => s.warehouse_id === myWarehouse?.id && Number(s.quantity) > 0);
          const items = myStock.map((s) => {
            const product = products.find((p) => p.id === s.product_id);
            return {
              product_id: s.product_id,
              product_name: product?.name || "",
              product_sku: product?.sku || "",
              product_image: product?.image_url || null,
              product_price: Number(product?.sale_price || 0),
              quantity: Number(s.quantity),
              maxQty: Number(s.quantity),
            };
          });
          setSelectedItems(items);
          setAutoNote(items.length > 0 ? `🔄 ${items.length} төрлийн бүх барааг автомат сонгосон` : "Агуулахад буцаах бараа байхгүй");
        } else {
          // АВАХ
          const { data: ordData } = await supabase
            .from("biz_orders").select("id")
            .eq("driver_id", profile.id).in("status", ["new", "pending", "assigned"]);
          const orderIds = (ordData || []).map((o) => o.id);

          if (orderIds.length === 0) {
            setAutoNote("⚠ Хүргэх захиалга байхгүй");
            setOrderSummary({ orderCount: 0, totalQty: 0, breakdown: [] });
            setCalculating(false);
            return;
          }

          // 🧩 Chunk-аар асуух (URL хязгаараас хальдгийг засна)
          const itemData = await fetchInChunks("biz_order_items", orderIds, {
            select: "product_id, product_name, quantity",
            filterColumn: "order_id",
            chunkSize: 200,
          });

          const requiredMap = {};
          (itemData || []).forEach((it) => {
            if (!it.product_id) return;
            if (!requiredMap[it.product_id]) {
              requiredMap[it.product_id] = { product_id: it.product_id, product_name: it.product_name, requiredQty: 0 };
            }
            requiredMap[it.product_id].requiredQty += Number(it.quantity || 0);
          });

          const breakdown = Object.values(requiredMap).map((r) => {
            const myStock = stock.find((s) => s.warehouse_id === myWarehouse?.id && s.product_id === r.product_id);
            const myQty = Number(myStock?.quantity || 0);
            return {
              product_id: r.product_id, product_name: r.product_name,
              required: r.requiredQty, myStock: myQty,
              missing: Math.max(0, r.requiredQty - myQty),
            };
          });
          setOrderSummary({
            orderCount: orderIds.length,
            totalQty: Object.values(requiredMap).reduce((s, r) => s + r.requiredQty, 0),
            breakdown,
          });

          const items = [];
          let satisfied = 0;
          breakdown.forEach((b) => {
            if (b.missing <= 0) { satisfied++; return; }
            const sourceStock = stock.find((s) => s.warehouse_id === sourceWh?.id && s.product_id === b.product_id);
            const avail = Number(sourceStock?.quantity || 0);
            if (avail <= 0) return;
            const product = products.find((p) => p.id === b.product_id);
            if (!product) return;
            items.push({
              product_id: b.product_id, product_name: product.name, product_sku: product.sku,
              product_image: product.image_url, product_price: Number(product.sale_price || 0),
              quantity: Math.min(b.missing, avail), maxQty: avail,
            });
          });
          setSelectedItems(items);
          if (items.length > 0) {
            setAutoNote(`📋 ${orderIds.length} захиалга → ${items.length} дутуу бараа автомат тооцсон` + (satisfied > 0 ? ` (${satisfied} төрөл хангалттай)` : ""));
          } else if (Object.keys(requiredMap).length === 0) {
            setAutoNote("Захиалгад бараа байхгүй");
          } else {
            setAutoNote("✓ Бүх бараа хангалттай");
          }
        }
      } catch (e) { console.error(e); }
      finally { setCalculating(false); }
    })();
  }, [isReturn, selectedOtherWhId]);

  // Filter products by category + search
  const filteredProducts = useMemo(() => {
    let result = [...products];
    if (activeCat !== "all") result = result.filter((p) => p.category_id === activeCat);
    if (search.trim()) {
      const q = search.toLowerCase();
      result = result.filter((p) => p.name?.toLowerCase().includes(q) || p.sku?.toLowerCase().includes(q));
    }
    
    // showAllProducts === false бол зөвхөн хэрэгтэй бараа харуулна (хайлт нь хэрэглэгчийн илт хүсэл бол bypass)
    if (!showAllProducts && !search.trim()) {
      const neededIds = new Set();
      if (isReturn) {
        // Буцаах: миний агуулахад байгаа бүх бараа хэрэгтэй
        stock.filter((s) => s.warehouse_id === myWarehouse?.id && Number(s.quantity) > 0)
          .forEach((s) => neededIds.add(s.product_id));
      } else {
        // Авах: orderSummary дотор байгаа барааны IDs (миний дутуу бараа)
        (orderSummary?.breakdown || []).forEach((b) => {
          if (b.missing > 0) neededIds.add(b.product_id);
        });
      }
      // Аль хэдийн сонгосон барааг үргэлж харуулна
      selectedItems.forEach((it) => neededIds.add(it.product_id));
      result = result.filter((p) => neededIds.has(p.id));
    }
    
    // Sort: in-stock first
    return result.sort((a, b) => {
      const sA = Number(stock.find((x) => x.warehouse_id === sourceWh?.id && x.product_id === a.id)?.quantity || 0);
      const sB = Number(stock.find((x) => x.warehouse_id === sourceWh?.id && x.product_id === b.id)?.quantity || 0);
      if (sA > 0 && sB <= 0) return -1;
      if (sA <= 0 && sB > 0) return 1;
      return (a.name || "").localeCompare(b.name || "");
    });
  }, [products, activeCat, search, stock, sourceWh, showAllProducts, isReturn, orderSummary, selectedItems, myWarehouse]);

  const updateQty = (productId, delta) => {
    setSelectedItems((prev) => {
      const existing = prev.find((x) => x.product_id === productId);
      if (existing) {
        const newQty = existing.quantity + delta;
        if (newQty <= 0) return prev.filter((x) => x.product_id !== productId);
        if (newQty > existing.maxQty) return prev;
        return prev.map((x) => x.product_id === productId ? { ...x, quantity: newQty } : x);
      } else if (delta > 0) {
        const product = products.find((p) => p.id === productId);
        const stockInfo = stock.find((x) => x.warehouse_id === sourceWh?.id && x.product_id === productId);
        const maxQty = Number(stockInfo?.quantity || 0);
        if (maxQty <= 0) return prev;
        return [...prev, {
          product_id: productId, product_name: product.name, product_sku: product.sku,
          product_image: product.image_url, product_price: Number(product.sale_price || 0),
          quantity: 1, maxQty: maxQty,
        }];
      }
      return prev;
    });
  };

  const removeItem = (productId) => {
    setSelectedItems(selectedItems.filter((it) => it.product_id !== productId));
  };

  const totalQty = selectedItems.reduce((s, x) => s + x.quantity, 0);
  const totalPrice = selectedItems.reduce((s, x) => s + (x.quantity * x.product_price), 0);

  const handleSubmit = async () => {
    if (!sourceWh || !targetWh) { alert("Агуулах сонгоно уу"); return; }
    if (selectedItems.length === 0) { alert("Бараа сонгоно уу"); return; }
    setBusy(true);
    try {
      const { data: req, error: reqErr } = await supabase.from("inv_transfer_requests").insert({
        requester_id: profile.id,
        from_warehouse_id: sourceWh.id,
        to_warehouse_id: targetWh.id,
        status: "pending", is_return: isReturn,
        notes: notes.trim() || null,
      }).select().single();
      if (reqErr) throw reqErr;

      const itemsToInsert = selectedItems.map((it) => ({
        request_id: req.id, product_id: it.product_id,
        product_name: it.product_name, product_sku: it.product_sku,
        quantity: it.quantity,
      }));
      const { error: itemsErr } = await supabase.from("inv_transfer_items").insert(itemsToInsert);
      if (itemsErr) throw itemsErr;

      alert("✅ Хүсэлт илгээгдлээ!");
      onSave();
    } catch (e) { alert("Алдаа: " + e.message); }
    finally { setBusy(false); }
  };

  // Category counts
  const catCounts = useMemo(() => {
    const counts = { all: products.length };
    categories.forEach((c) => {
      counts[c.id] = products.filter((p) => p.category_id === c.id).length;
    });
    return counts;
  }, [products, categories]);

  return createPortal(
    <div style={{
      position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 9999,
      background: "rgba(14, 156, 142, 0.15)", backdropFilter: "blur(8px)",
    }} onClick={onClose}>
      <div style={{
        background: "rgba(255, 255, 255, 0.98)", backdropFilter: "blur(24px)",
        border: "1px solid rgba(255, 255, 255, 0.8)",
        boxShadow: "0 24px 48px rgba(14, 156, 142, 0.3)",
        borderRadius: 16,
        position: "absolute", top: 8, left: 8, right: 8, bottom: 8,
        display: "flex", flexDirection: "column",
        overflow: "hidden",
      }} onClick={(e) => e.stopPropagation()}>
        {/* Header */}
        <div className="px-4 py-3 flex items-center justify-between gap-2"
          style={{ borderBottom: `1px solid ${T.border}` }}>
          <h3 style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-base flex items-center gap-2">
            {isReturn ? "🔄 Бараа буцаах" : "📨 Бараа авах"}
          </h3>
          <div className="flex items-center gap-2">
            {selectedItems.length > 0 && (
              <button onClick={() => setShowSidebar(!showSidebar)}
                className="md:hidden press-btn relative px-3 py-1.5 rounded-full text-xs flex items-center gap-1"
                style={{ background: T.highlight, color: "white", fontFamily: FS, fontWeight: 600 }}>
                🛒 {selectedItems.length}
              </button>
            )}
            <button onClick={onClose} style={{ color: T.muted }}>
              <X size={18} />
            </button>
          </div>
        </div>

        <div className="flex-1 flex overflow-hidden">
          {/* LEFT — Products */}
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* Warehouse selector */}
            <div style={{ padding: 8, borderBottom: `1px solid ${T.borderSoft}`, background: T.surfaceAlt }}>
              <label style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider block mb-1">
                {isReturn ? "📤 Хаашаа буцаах вэ?" : "📥 Хаанаас авах вэ?"}
              </label>
              <select value={selectedOtherWhId || ""} 
                onChange={(e) => {
                  setSelectedOtherWhId(e.target.value);
                  setSelectedItems([]); // агуулах солих үед сонгосон бараагаа цэвэрлэх
                }}
                style={{ background: T.surface, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS, fontWeight: 600 }}
                className="w-full px-3 py-2 rounded-lg text-sm">
                {otherWarehouses.length === 0 ? (
                  <option value="">Бусад агуулах байхгүй</option>
                ) : (
                  otherWarehouses.map((w) => {
                    const isMain = w.type === "main";
                    const isDriver = !!w.driver_id;
                    const icon = isMain ? "🏬" : isDriver ? "🚚" : "📦";
                    return (
                      <option key={w.id} value={w.id}>
                        {icon} {w.name}{isMain ? " (Үндсэн)" : ""}
                      </option>
                    );
                  })
                )}
              </select>
              {selectedOtherWhId && (
                <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] mt-1 flex items-center gap-1">
                  {isReturn ? (
                    <>🚚 <strong style={{ color: T.ink }}>{myWarehouse?.name}</strong> → 📤 <strong style={{ color: T.ink }}>{warehouses.find((w) => w.id === selectedOtherWhId)?.name}</strong></>
                  ) : (
                    <>📥 <strong style={{ color: T.ink }}>{warehouses.find((w) => w.id === selectedOtherWhId)?.name}</strong> → 🚚 <strong style={{ color: T.ink }}>{myWarehouse?.name}</strong></>
                  )}
                </div>
              )}
            </div>

            {/* Search + toggle + auto note */}
            <div style={{ padding: 8, borderBottom: `1px solid ${T.borderSoft}` }} className="space-y-2">
              <div className="flex gap-2">
                <input value={search} onChange={(e) => setSearch(e.target.value)}
                  placeholder={showAllProducts ? "🔍 Бараа хайх..." : "🔍 Бараа нэмэхийн тулд хайна уу..."}
                  style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS }}
                  className="flex-1 px-3 py-2 rounded-lg text-sm" />
                <button onClick={() => setShowAllProducts(!showAllProducts)}
                  className="press-btn px-3 py-2 rounded-lg text-[10px] flex-shrink-0"
                  style={{
                    background: showAllProducts ? T.highlight : T.surfaceAlt,
                    color: showAllProducts ? "white" : T.ink,
                    fontFamily: FS, fontWeight: 600,
                    border: `1px solid ${showAllProducts ? T.highlight : T.border}`,
                  }}
                  title={showAllProducts ? "Зөвхөн хэрэгтэй бараа харах" : "Бүх бараа харах"}>
                  {showAllProducts ? "✓ Бүх бараа" : "📋 Бүх бараа"}
                </button>
              </div>

              {calculating ? (
                <div className="flex items-center gap-2 px-2">
                  <Loader2 size={12} className="spin" style={{ color: "#0ea5e9" }} />
                  <span style={{ color: "#0ea5e9", fontFamily: FS }} className="text-[10px]">Тооцоолж байна...</span>
                </div>
              ) : autoNote ? (
                <div className="px-2 py-1.5 rounded-lg flex items-start gap-1.5"
                  style={{
                    background: selectedItems.length > 0 ? "rgba(14,165,233,0.1)" : "rgba(245,158,11,0.1)",
                  }}>
                  <span className="text-xs">{selectedItems.length > 0 ? "✨" : "ℹ"}</span>
                  <span style={{ color: selectedItems.length > 0 ? "#0ea5e9" : T.warn, fontFamily: FS, fontWeight: 600 }}
                    className="text-[10px] flex-1">{autoNote}</span>
                </div>
              ) : null}

              {/* Mode hint */}
              {!showAllProducts && !search.trim() && (
                <div className="px-2 py-1 rounded text-[10px]"
                  style={{ background: T.surfaceAlt, color: T.muted, fontFamily: FM }}>
                  💡 Зөвхөн хэрэгтэй бараа харагдаж байна. Илүү бараа хэрэгтэй бол <strong style={{ color: T.ink }}>хайлт</strong> хийнэ үү эсвэл <strong style={{ color: T.ink }}>"Бүх бараа"</strong> товч даргана уу.
                </div>
              )}
            </div>

            {/* Categories */}
            <div style={{ padding: "8px", borderBottom: `1px solid ${T.borderSoft}`, overflowX: "auto" }}>
              <div className="flex gap-1.5" style={{ minWidth: "max-content" }}>
                <button onClick={() => setActiveCat("all")}
                  className="press-btn px-3 py-1.5 rounded-full text-[10px] flex items-center gap-1 whitespace-nowrap"
                  style={{
                    background: activeCat === "all" ? T.highlight : T.surfaceAlt,
                    color: activeCat === "all" ? "white" : T.ink,
                    fontFamily: FS, fontWeight: 600,
                  }}>
                  <span>Бүгд</span>
                  <span style={{
                    background: activeCat === "all" ? "rgba(255,255,255,0.2)" : T.surface,
                    color: activeCat === "all" ? "white" : T.muted,
                  }} className="text-[9px] px-1.5 rounded-full">{catCounts.all}</span>
                </button>
                {categories.map((c) => catCounts[c.id] > 0 && (
                  <button key={c.id} onClick={() => setActiveCat(c.id)}
                    className="press-btn px-3 py-1.5 rounded-full text-[10px] flex items-center gap-1 whitespace-nowrap"
                    style={{
                      background: activeCat === c.id ? T.highlight : T.surfaceAlt,
                      color: activeCat === c.id ? "white" : T.ink,
                      fontFamily: FS, fontWeight: 600,
                    }}>
                    <span>{c.name}</span>
                    <span style={{
                      background: activeCat === c.id ? "rgba(255,255,255,0.2)" : T.surface,
                      color: activeCat === c.id ? "white" : T.muted,
                    }} className="text-[9px] px-1.5 rounded-full">{catCounts[c.id]}</span>
                  </button>
                ))}
              </div>
            </div>

            {/* Product list */}
            <div className="flex-1 overflow-y-auto p-2 space-y-1.5">
              {filteredProducts.length === 0 ? (
                <div className="text-center py-8">
                  <div className="text-4xl mb-2">📦</div>
                  <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
                    {products.length === 0 ? "Бараа бүртгэгдээгүй" : 
                     !showAllProducts && !search.trim() ? "Хэрэгтэй бараа байхгүй" : "Олдсонгүй"}
                  </div>
                  {!showAllProducts && !search.trim() && products.length > 0 && (
                    <button onClick={() => setShowAllProducts(true)}
                      className="press-btn mt-3 px-4 py-2 rounded-lg text-xs"
                      style={{ background: T.highlight, color: "white", fontFamily: FS, fontWeight: 600 }}>
                      📋 Бүх бараа харах
                    </button>
                  )}
                </div>
              ) : (
                filteredProducts.map((p) => {
                  const stockInfo = stock.find((x) => x.warehouse_id === sourceWh?.id && x.product_id === p.id);
                  const inStock = Number(stockInfo?.quantity || 0);
                  const noStock = inStock <= 0;
                  const selected = selectedItems.find((x) => x.product_id === p.id);
                  const cat = categories.find((c) => c.id === p.category_id);

                  return (
                    <div key={p.id} className="rounded-xl p-2 flex items-center gap-2.5"
                      style={{
                        background: selected ? "rgba(14,165,233,0.05)" : T.surfaceAlt,
                        border: selected ? `1px solid rgba(14,165,233,0.3)` : `1px solid ${T.border}`,
                        opacity: noStock && !selected ? 0.5 : 1,
                      }}>
                      {p.image_url ? (
                        <img src={p.image_url} alt=""
                          style={{
                            width: 48, height: 48, objectFit: "cover", borderRadius: 8,
                            filter: noStock ? "grayscale(100%)" : "none",
                          }} />
                      ) : (
                        <div style={{ width: 48, height: 48, background: T.border, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center" }}>
                          📦
                        </div>
                      )}

                      <div className="flex-1 min-w-0">
                        <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-xs truncate">
                          {p.name}
                        </div>
                        <div className="flex items-center gap-1.5 mt-0.5">
                          {cat && (
                            <span style={{ background: "rgba(16,185,129,0.1)", color: T.ok, fontFamily: FS, fontWeight: 600 }}
                              className="text-[9px] px-1.5 py-0.5 rounded-full">
                              {cat.name}
                            </span>
                          )}
                          {p.sku && (
                            <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">
                              #{p.sku}
                            </span>
                          )}
                          <span style={{
                            background: noStock ? T.errSoft : inStock <= 5 ? T.warnSoft : "rgba(16,185,129,0.1)",
                            color: noStock ? T.err : inStock <= 5 ? T.warn : T.ok,
                            fontFamily: FS, fontWeight: 600,
                          }} className="text-[9px] px-1.5 py-0.5 rounded-full">
                            Үлд {inStock}
                          </span>
                        </div>
                        {Number(p.sale_price) > 0 && (
                          <div style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }} className="text-xs mt-0.5 tabular-nums">
                            {Number(p.sale_price).toLocaleString()}₮
                          </div>
                        )}
                      </div>

                      {/* Qty controls */}
                      <div className="flex items-center gap-1 flex-shrink-0">
                        <button onClick={() => updateQty(p.id, -1)}
                          disabled={!selected}
                          className="press-btn w-7 h-7 rounded-full flex items-center justify-center text-base font-bold"
                          style={{
                            background: selected ? T.surfaceAlt : "transparent",
                            color: selected ? T.ink : T.muted,
                            opacity: selected ? 1 : 0.3,
                          }}>−</button>
                        <span style={{ fontFamily: FD, fontWeight: 700, color: T.ink, minWidth: 28 }}
                          className="text-sm text-center tabular-nums">
                          {selected ? selected.quantity : 0}
                        </span>
                        <button onClick={() => updateQty(p.id, +1)}
                          disabled={noStock || (selected && selected.quantity >= selected.maxQty)}
                          className="press-btn w-7 h-7 rounded-full flex items-center justify-center text-base font-bold"
                          style={{
                            background: noStock ? T.surfaceAlt : T.highlight,
                            color: noStock ? T.muted : "white",
                            opacity: noStock ? 0.3 : 1,
                          }}>+</button>
                        {selected && (
                          <button onClick={() => removeItem(p.id)}
                            className="press-btn w-7 h-7 rounded-full flex items-center justify-center"
                            style={{ color: T.err }}>
                            <X size={14} />
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })
              )}
            </div>
          </div>

          {/* RIGHT — Summary sidebar (desktop) */}
          <div className="hidden md:flex flex-col" style={{ width: 280, borderLeft: `1px solid ${T.border}`, background: T.surfaceAlt }}>
            <div className="px-3 py-3" style={{ borderBottom: `1px solid ${T.border}` }}>
              <div className="flex items-center justify-between mb-2">
                <span style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-sm">
                  Хүсэлт
                </span>
                <span style={{ background: T.highlight, color: "white", fontFamily: FD, fontWeight: 700 }}
                  className="text-[10px] px-2 py-0.5 rounded-full">
                  {selectedItems.length}
                </span>
              </div>
              <div className="flex items-center justify-between text-xs">
                <span style={{ color: T.muted, fontFamily: FM }}>Бараа</span>
                <span style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="tabular-nums">
                  {totalQty} ширхэг
                </span>
              </div>
              <div className="flex items-center justify-between text-xs mt-1">
                <span style={{ color: T.muted, fontFamily: FM }}>Нийт дүн</span>
                <span style={{ fontFamily: FD, fontWeight: 700, color: T.highlight }} className="text-base tabular-nums">
                  {totalPrice.toLocaleString()}₮
                </span>
              </div>
            </div>

            <div className="px-3 py-2" style={{ background: T.surface, borderBottom: `1px solid ${T.border}` }}>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] mb-0.5">Хаанаас</div>
              <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-xs">
                {sourceWh?.type === "main" ? "🏢" : "🚚"} {sourceWh?.name}
              </div>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] mt-1.5 mb-0.5">Хаашаа</div>
              <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-xs">
                {targetWh?.type === "main" ? "🏢" : "🚚"} {targetWh?.name}
              </div>
            </div>

            <div className="flex-1 overflow-y-auto p-2 space-y-1">
              {selectedItems.length === 0 ? (
                <div className="text-center py-6">
                  <div className="text-2xl mb-1">🛒</div>
                  <div style={{ color: T.muted, fontFamily: FS }} className="text-[10px]">
                    Бараа сонгоогүй
                  </div>
                </div>
              ) : (
                selectedItems.map((it) => (
                  <div key={it.product_id} className="flex items-center gap-1.5 p-1.5 rounded-lg"
                    style={{ background: T.surface, border: `1px solid ${T.border}` }}>
                    {it.product_image && (
                      <img src={it.product_image} alt=""
                        style={{ width: 28, height: 28, objectFit: "cover", borderRadius: 4, flexShrink: 0 }} />
                    )}
                    <div className="flex-1 min-w-0">
                      <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-[10px] truncate">
                        {it.product_name}
                      </div>
                      <div style={{ color: T.muted, fontFamily: FD }} className="text-[9px] tabular-nums">
                        ×{it.quantity}{it.product_price > 0 ? ` · ${(it.quantity * it.product_price).toLocaleString()}₮` : ""}
                      </div>
                    </div>
                    <button onClick={() => removeItem(it.product_id)}
                      className="press-btn w-5 h-5 rounded-full flex items-center justify-center"
                      style={{ color: T.err }}>
                      <X size={10} />
                    </button>
                  </div>
                ))
              )}
            </div>

            <div className="p-2" style={{ borderTop: `1px solid ${T.border}` }}>
              <textarea value={notes} onChange={(e) => setNotes(e.target.value)}
                placeholder="Тэмдэглэл..."
                rows={2}
                style={{ background: T.surface, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS }}
                className="w-full px-2 py-1.5 rounded-lg text-[11px] resize-none mb-2" />
              <button onClick={handleSubmit} disabled={busy || selectedItems.length === 0}
                className="press-btn w-full py-2.5 rounded-xl text-sm font-semibold flex items-center justify-center gap-1.5"
                style={{
                  background: selectedItems.length === 0 ? T.surfaceAlt : "linear-gradient(135deg, #0ea5e9, #0284c7)",
                  color: selectedItems.length === 0 ? T.muted : "white",
                  fontFamily: FS, opacity: busy ? 0.6 : 1,
                }}>
                {busy ? <Loader2 size={14} className="spin" /> : "📨"} Хадгалах
              </button>
            </div>
          </div>

          {/* Mobile sidebar - bottom sheet */}
          {showSidebar && (
            <div className="md:hidden fixed inset-0 z-50 flex items-end"
              style={{ background: "rgba(0,0,0,0.4)" }}
              onClick={() => setShowSidebar(false)}>
              <div className="w-full max-h-[85vh] flex flex-col"
                style={{ background: T.surface, borderRadius: "16px 16px 0 0" }}
                onClick={(e) => e.stopPropagation()}>
                <div className="px-3 py-3 flex items-center justify-between" style={{ borderBottom: `1px solid ${T.border}` }}>
                  <div>
                    <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-sm">
                      Хүсэлт ({selectedItems.length})
                    </div>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                      {totalQty} ширхэг · {totalPrice.toLocaleString()}₮
                    </div>
                  </div>
                  <button onClick={() => setShowSidebar(false)} style={{ color: T.muted }}>
                    <X size={16} />
                  </button>
                </div>
                <div className="flex-1 overflow-y-auto p-2 space-y-1">
                  {selectedItems.map((it) => (
                    <div key={it.product_id} className="flex items-center gap-1.5 p-1.5 rounded-lg"
                      style={{ background: T.surfaceAlt }}>
                      {it.product_image && (
                        <img src={it.product_image} alt=""
                          style={{ width: 32, height: 32, objectFit: "cover", borderRadius: 4 }} />
                      )}
                      <div className="flex-1 min-w-0">
                        <div style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-xs truncate">
                          {it.product_name}
                        </div>
                        <div style={{ color: T.muted, fontFamily: FD }} className="text-[10px] tabular-nums">
                          ×{it.quantity}
                        </div>
                      </div>
                      <button onClick={() => removeItem(it.product_id)}
                        className="press-btn w-6 h-6 rounded-full flex items-center justify-center"
                        style={{ color: T.err }}>
                        <X size={12} />
                      </button>
                    </div>
                  ))}
                </div>
                <div className="p-2" style={{ borderTop: `1px solid ${T.border}` }}>
                  <textarea value={notes} onChange={(e) => setNotes(e.target.value)}
                    placeholder="Тэмдэглэл..."
                    rows={2}
                    style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS }}
                    className="w-full px-2 py-1.5 rounded-lg text-xs resize-none mb-2" />
                  <button onClick={handleSubmit} disabled={busy || selectedItems.length === 0}
                    className="press-btn w-full py-2.5 rounded-xl text-sm font-semibold flex items-center justify-center gap-1.5"
                    style={{
                      background: selectedItems.length === 0 ? T.surfaceAlt : "linear-gradient(135deg, #0ea5e9, #0284c7)",
                      color: selectedItems.length === 0 ? T.muted : "white",
                      fontFamily: FS,
                    }}>
                    {busy ? <Loader2 size={14} className="spin" /> : "📨"} Хадгалах ({selectedItems.length})
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>,
    document.body
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  DRIVER SETTLEMENTS — Хүргэгчийн өөрийн тооцоо
// ═══════════════════════════════════════════════════════════════════════════
function DriverSettlementsView({ profile, myOwed, myDeliveredTotal }) {
  const [reports, setReports] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeReport, setActiveReport] = useState(null);
  const [reportOrders, setReportOrders] = useState([]); // тухайн тооцооны захиалгууд
  const [loadingOrders, setLoadingOrders] = useState(false);

  const loadReports = async () => {
    setLoading(true);
    try {
      const { data } = await supabase
        .from("biz_settlements")
        .select("*")
        .eq("driver_id", profile.id)
        .order("settled_at", { ascending: false });
      setReports(data || []);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { loadReports(); }, []);

  // 📦 Тухайн тооцоонд хамаарах захиалгуудыг татах (settlement_id-аар)
  useEffect(() => {
    if (!activeReport) { setReportOrders([]); return; }
    let cancelled = false;
    (async () => {
      setLoadingOrders(true);
      try {
        const { data: ords } = await supabase
          .from("biz_orders")
          .select("id, order_number, customer_phone, status, total_amount, delivery_fee, delivered_at, created_at")
          .eq("settlement_id", activeReport.id)
          .order("delivered_at", { ascending: false });
        const ordList = ords || [];
        // Захиалга бүрийн бараанууд (biz_order_items) — нэр + тоо
        const ordIds = ordList.map((o) => o.id);
        const itemsByOrder = {};
        if (ordIds.length > 0) {
          const { data: items } = await supabase
            .from("biz_order_items")
            .select("order_id, product_name, quantity")
            .in("order_id", ordIds);
          (items || []).forEach((it) => {
            if (!itemsByOrder[it.order_id]) itemsByOrder[it.order_id] = [];
            itemsByOrder[it.order_id].push({ name: it.product_name || "—", qty: Number(it.quantity || 0) });
          });
        }
        const enriched = ordList.map((o) => {
          const its = itemsByOrder[o.id] || [];
          const itemCount = its.reduce((s, x) => s + x.qty, 0);
          return { ...o, items: its, itemCount };
        });
        if (!cancelled) setReportOrders(enriched);
      } catch (e) { console.error(e); if (!cancelled) setReportOrders([]); }
      finally { if (!cancelled) setLoadingOrders(false); }
    })();
    return () => { cancelled = true; };
  }, [activeReport]);

  // Detail харах
  if (activeReport) {
    const r = activeReport;
    return (
      <div className="space-y-3">
        <div className="glass rounded-2xl p-3 flex items-center gap-3">
          <button onClick={() => setActiveReport(null)}
            className="press-btn p-1.5 rounded-lg" style={{ color: T.ink }}>
            ←
          </button>
          <div style={{ background: T.ok, color: "white" }}
            className="w-10 h-10 rounded-full flex items-center justify-center text-base font-bold flex-shrink-0">
            ✓
          </div>
          <div className="flex-1 min-w-0">
            <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-base">
              Хаагдсан тооцоо
            </div>
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px]">
              {new Date(r.settled_at).toLocaleString("mn-MN")} · {r.period_label}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-2 gap-2">
          <div className="glass rounded-2xl p-3" style={{ borderLeft: `3px solid ${T.warn}` }}>
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase">Тушаасан</div>
            <div style={{ fontFamily: FD, fontWeight: 700, color: T.warn }} className="text-2xl tabular-nums">
              {Number(r.settlement_amount).toLocaleString()}₮
            </div>
          </div>
          <div className="glass rounded-2xl p-3" style={{ borderLeft: `3px solid ${T.ok}` }}>
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase">Нийт</div>
            <div style={{ fontFamily: FD, fontWeight: 700, color: T.ok }} className="text-2xl tabular-nums">
              {Number(r.total_submitted).toLocaleString()}₮
            </div>
          </div>
        </div>

        <div className="glass rounded-2xl p-3">
          <div style={{ color: T.ink, fontFamily: FS, fontWeight: 700 }} className="text-sm mb-3">
            💰 Тушаалтын задаргаа
          </div>
          <div className="space-y-2">
            <div className="flex items-start justify-between p-2 rounded-lg" style={{ background: T.surfaceAlt }}>
              <div className="flex-1">
                <div style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-sm">💵 Бэлнээр тушаасан</div>
                {r.cash_notes && (
                  <div style={{ color: T.muted, fontFamily: FS, fontStyle: "italic" }} className="text-[11px] mt-1">"{r.cash_notes}"</div>
                )}
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="text-base tabular-nums">
                {Number(r.cash_amount).toLocaleString()}₮
              </div>
            </div>
            <div className="flex items-start justify-between p-2 rounded-lg" style={{ background: T.surfaceAlt }}>
              <div className="flex-1">
                <div style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-sm">🏦 Дансаар тушаасан</div>
                {r.bank_notes && (
                  <div style={{ color: T.muted, fontFamily: FS, fontStyle: "italic" }} className="text-[11px] mt-1">"{r.bank_notes}"</div>
                )}
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="text-base tabular-nums">
                {Number(r.bank_amount).toLocaleString()}₮
              </div>
            </div>
            <div className="flex items-start justify-between p-2 rounded-lg" style={{ background: T.surfaceAlt }}>
              <div className="flex-1">
                <div style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-sm">📤 Борлуулалт</div>
                {r.expense_notes && (
                  <div style={{ color: T.muted, fontFamily: FS, fontStyle: "italic" }} className="text-[11px] mt-1">"{r.expense_notes}"</div>
                )}
              </div>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="text-base tabular-nums">
                {Number(r.expense_amount).toLocaleString()}₮
              </div>
            </div>
          </div>
        </div>

        <div className="glass rounded-2xl p-3 space-y-1.5">
          <div className="flex items-center justify-between py-1">
            <span style={{ color: T.muted, fontFamily: FS }} className="text-xs">Хүргэсэн нийт дүн</span>
            <span style={{ fontFamily: FD, fontWeight: 600, color: T.ink }} className="text-sm tabular-nums">
              {Number(r.delivered_total).toLocaleString()}₮
            </span>
          </div>
          <div className="flex items-center justify-between py-1">
            <span style={{ color: T.muted, fontFamily: FS }} className="text-xs">Захиалгын тоо</span>
            <span style={{ fontFamily: FD, fontWeight: 600, color: T.ink }} className="text-sm tabular-nums">
              {r.order_count}
            </span>
          </div>
        </div>

        {/* 📦 Хаагдсан захиалгуудын жагсаалт */}
        <div className="glass rounded-2xl p-3">
          <div style={{ color: T.ink, fontFamily: FS, fontWeight: 700 }} className="text-sm mb-3 flex items-center gap-2">
            📦 Хаагдсан захиалгууд ({reportOrders.length})
          </div>
          {loadingOrders ? (
            <div className="py-6 text-center">
              <Loader2 className="spin mx-auto" size={18} style={{ color: T.muted }} />
            </div>
          ) : reportOrders.length === 0 ? (
            <div style={{ color: T.muted, fontFamily: FS }} className="text-xs text-center py-4">
              Энэ тооцоонд захиалга алга
            </div>
          ) : (
            <div className="space-y-1.5">
              {reportOrders.map((o) => {
                const st = o.status === "delivered"
                  ? { label: "Хүргэсэн", color: T.ok, bg: "rgba(16,185,129,0.1)" }
                  : o.status === "cancelled"
                  ? { label: "Цуцалсан", color: T.err, bg: T.errSoft }
                  : { label: o.status, color: T.muted, bg: T.surfaceAlt };
                return (
                  <div key={o.id} className="p-2 rounded-lg" style={{ background: T.surfaceAlt }}>
                    <div className="flex items-center justify-between">
                    <div className="flex-1 min-w-0">
                      <div style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-xs">
                        {o.order_number || "—"} · {o.customer_phone || "—"}
                      </div>
                      <div className="flex items-center gap-2 mt-0.5 flex-wrap">
                        <span style={{ background: st.bg, color: st.color, fontFamily: FM }}
                          className="text-[9px] px-1.5 py-0.5 rounded-full font-bold">
                          {st.label}
                        </span>
                        <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">
                          📦 {o.itemCount}ш
                        </span>
                        <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">
                          🚚 {Number(o.delivery_fee || 0).toLocaleString()}₮
                        </span>
                        {o.delivered_at && (
                          <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px]">
                            {new Date(o.delivered_at).toLocaleString("mn-MN", { month: "2-digit", day: "2-digit", hour: "2-digit", minute: "2-digit" })}
                          </span>
                        )}
                      </div>
                    </div>
                    <div style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="text-sm tabular-nums flex-shrink-0">
                      {Number(o.total_amount || 0).toLocaleString()}₮
                    </div>
                    </div>
                    {/* Барааны дэлгэрэнгүй: нэр + тоо */}
                    {o.items && o.items.length > 0 && (
                      <div className="mt-1.5 pt-1.5 space-y-0.5" style={{ borderTop: `1px solid ${T.border}` }}>
                        {o.items.map((it, idx) => (
                          <div key={idx} className="flex items-center justify-between">
                            <span style={{ color: T.ink, fontFamily: FS }} className="text-[11px] truncate flex-1 min-w-0">
                              • {it.name}
                            </span>
                            <span style={{ color: T.muted, fontFamily: FD, fontWeight: 600 }} className="text-[11px] tabular-nums flex-shrink-0 ml-2">
                              {it.qty}ш
                            </span>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    );
  }

  // Жагсаалт
  return (
    <div className="space-y-3">
      {/* Одоогийн тушаах дүн */}
      <div className="glass rounded-2xl p-3" style={{ borderLeft: `4px solid ${myOwed > 0 ? T.warn : T.ok}`, background: myOwed > 0 ? T.warnSoft : "rgba(16,185,129,0.05)" }}>
        <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider mb-1">
          Одоогийн тушаах дүн
        </div>
        <div style={{ fontFamily: FD, fontWeight: 700, color: myOwed > 0 ? T.warn : T.ok }} className="text-3xl tabular-nums">
          {myOwed.toLocaleString()}₮
        </div>
        <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-1">
          Хүргэсэн дүн: {myDeliveredTotal.toLocaleString()}₮
        </div>
      </div>

      {/* Хаагдсан тооцоонуудын түүх */}
      <div>
        <div style={{ color: T.ink, fontFamily: FS, fontWeight: 700 }} className="text-sm mb-2 flex items-center gap-2">
          📊 Тооцооний тайлан ({reports.length})
        </div>

        {loading ? (
          <div className="glass rounded-2xl p-8 text-center">
            <Loader2 className="spin mx-auto" size={20} style={{ color: T.muted }} />
          </div>
        ) : reports.length === 0 ? (
          <div className="glass rounded-2xl p-8 text-center">
            <div className="text-4xl mb-2">📊</div>
            <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
              Хаагдсан тооцоо алга
            </div>
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-1">
              Удирдах ажилтан тооцоог хаасны дараа энд харагдана
            </div>
          </div>
        ) : (
          <div className="space-y-2">
            {reports.map((r) => (
              <button key={r.id} onClick={() => setActiveReport(r)}
                className="press-btn glass lift rounded-2xl p-3 w-full text-left"
                style={{ borderLeft: `4px solid ${T.ok}` }}>
                <div className="flex items-center gap-3 mb-2">
                  <div style={{ background: T.ok, color: "white" }}
                    className="w-9 h-9 rounded-full flex items-center justify-center text-sm font-bold flex-shrink-0">
                    ✓
                  </div>
                  <div className="flex-1 min-w-0">
                    <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-sm">
                      {r.period_label}
                    </div>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px]">
                      {new Date(r.settled_at).toLocaleString("mn-MN")}
                    </div>
                  </div>
                  <div className="text-right">
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase">Тушаасан</div>
                    <div style={{ fontFamily: FD, fontWeight: 700, color: T.ok }} className="text-base tabular-nums">
                      {Number(r.total_submitted).toLocaleString()}₮
                    </div>
                  </div>
                </div>
                <div className="grid grid-cols-3 gap-1.5">
                  <div style={{ background: "rgba(16,185,129,0.1)" }} className="rounded-lg p-1.5 text-center">
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[8px] uppercase">💵 Бэл.</div>
                    <div style={{ fontFamily: FD, fontWeight: 600, color: T.ink }} className="text-xs tabular-nums">
                      {Number(r.cash_amount).toLocaleString()}₮
                    </div>
                  </div>
                  <div style={{ background: "rgba(59,130,246,0.1)" }} className="rounded-lg p-1.5 text-center">
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[8px] uppercase">🏦 Данс</div>
                    <div style={{ fontFamily: FD, fontWeight: 600, color: T.ink }} className="text-xs tabular-nums">
                      {Number(r.bank_amount).toLocaleString()}₮
                    </div>
                  </div>
                  <div style={{ background: T.warnSoft }} className="rounded-lg p-1.5 text-center">
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[8px] uppercase">📤 Зарл.</div>
                    <div style={{ fontFamily: FD, fontWeight: 600, color: T.ink }} className="text-xs tabular-nums">
                      {Number(r.expense_amount).toLocaleString()}₮
                    </div>
                  </div>
                </div>
              </button>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

function DriverDashboard({ profile }) {
  const [orders, setOrders] = useState([]);
  const [items, setItems] = useState({});
  const [loading, setLoading] = useState(true);
  const [fbPagesMap, setFbPagesMap] = useState({}); // 🔗 FB Pages ID → name
  const [activeOrder, setActiveOrder] = useState(null);
  const [cancelOrder, setCancelOrder] = useState(null);
  const [cancelNote, setCancelNote] = useState("");
  const [view, setView] = useState(() => {
    try { return localStorage.getItem("orgoo-driver-view") || "orders"; } catch { return "orders"; }
  }); // orders | warehouse | requests | settlements
  useEffect(() => {
    try { localStorage.setItem("orgoo-driver-view", view); } catch {}
  }, [view]);
  const [viewMode, setViewMode] = useState("list"); // list | map (захиалгын дотор)
  const [driverSearch, setDriverSearch] = useState(""); // 🔍 Дугаар/хаягаар хайх
  const [hoveredOrderId, setHoveredOrderId] = useState(null); // 🖱 Hover effect
  const [phoneAction, setPhoneAction] = useState(null); // 📞 { phone } — Залгах/Мессеж сонголт
  const [assignOrder, setAssignOrder] = useState(null); // 🚚 Өөр driver-т хуваарилах modal
  const [drivers, setDrivers] = useState([]); // Бусад driver-ийг сонгож хуваарилах
  const [assignDriverOrder, setAssignDriverOrder] = useState(null); // driver picker нээх захиалга
  const [insufficientStockOrder, setInsufficientStockOrder] = useState(null); // { orderId, msg }
  const [ratingOrder, setRatingOrder] = useState(null); // { order, action: 'delivered'|'cancelled' }
  const [ratingValue, setRatingValue] = useState(0);
  const [ratingNote, setRatingNote] = useState("");
  const [ratingBusy, setRatingBusy] = useState(false);
  const [filter, setFilter] = useState(() => {
    try { return localStorage.getItem("orgoo-driver-filter") || "active"; } catch { return "active"; }
  });
  const [page, setPage] = useState(1);
  const PAGE_SIZE = 100;
  const [myZones, setMyZones] = useState([]); // driver-ийн polygon бүсүүд

  // Driver-ийн бүсүүдийг татах
  useEffect(() => {
    (async () => {
      try {
        const { data } = await supabase.from("biz_zones")
          .select("id, name, color, polygon")
          .eq("driver_id", profile.id)
          .eq("is_active", true);
        setMyZones(data || []);
      } catch (e) { console.error("Zones load:", e); }
    })();
  }, [profile.id]);

  useEffect(() => {
    try { localStorage.setItem("orgoo-driver-filter", filter); } catch {}
    setPage(1); // Filter солихтой адил эхний хуудас руу
  }, [filter]);

  const loadAll = async () => {
    setLoading(true);
    try {
      const [ownOrders, newOrders, unknownOrders, { data: driversData }] = await Promise.all([
        fetchAllRows(
          supabase.from("biz_orders").select("*")
            .eq("driver_id", profile.id)
            .order("created_at", { ascending: false })
        ),
        fetchAllRows(
          supabase.from("biz_orders").select("*")
            .is("driver_id", null).eq("status", "new")
            .order("created_at", { ascending: false })
        ),
        // ❓ Бүх "Тодорхойгүй" захиалгуудыг бүгд driver-руу харагдуулна
        fetchAllRows(
          supabase.from("biz_orders").select("*")
            .eq("is_unknown", true)
            .not("status", "in", "(delivered,cancelled)")
            .order("created_at", { ascending: false })
        ),
        supabase.from("profiles").select("id, name, job_title").eq("role", "driver"),
      ]);

      setDrivers(driversData || []);

      // 🔗 FB Pages татах
      const { data: fbpData } = await supabase.from("biz_fb_pages")
        .select("id, name");
      const fbMap = {};
      (fbpData || []).forEach(p => { fbMap[p.id] = p.name; });
      setFbPagesMap(fbMap);

      // Хослуулах + давхардлаас сэргийлэх
      const all = [...(ownOrders || [])];
      const ownIds = new Set(all.map((o) => o.id));
      (newOrders || []).forEach((o) => {
        if (!ownIds.has(o.id)) {
          all.push(o);
          ownIds.add(o.id);
        }
      });
      // is_unknown захиалгууд (бусад driver-ийн)
      (unknownOrders || []).forEach((o) => {
        if (!ownIds.has(o.id)) {
          all.push(o);
          ownIds.add(o.id);
        }
      });

      setOrders(all);

      if (all.length > 0) {
        const orderIds = all.map((o) => o.id);
        // 🧩 Chunk-аар асуух — 1207+ захиалгатай driver-д URL хязгаар хальж байсныг засна
        const itemData = await fetchInChunks("biz_order_items", orderIds, {
          select: "*",
          filterColumn: "order_id",
          chunkSize: 200,
        });

        const productIds = [...new Set((itemData || []).map((it) => it.product_id).filter(Boolean))];
        const { data: prodData } = productIds.length > 0
          ? await fetchInChunks("inv_products", productIds, { select: "id, image_url", filterColumn: "id", chunkSize: 200 }).then(d => ({ data: d }))
          : { data: [] };
        const prodMap = {};
        (prodData || []).forEach((p) => { prodMap[p.id] = p.image_url; });

        const itemMap = {};
        (itemData || []).forEach((it) => {
          if (!itemMap[it.order_id]) itemMap[it.order_id] = [];
          itemMap[it.order_id].push({ ...it, product_image: prodMap[it.product_id] || null });
        });
        setItems(itemMap);
      }
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { loadAll(); }, []);

  // 🔔 Badge + Realtime — Хэрэглэгч даргах хүртэл шинэчлэгдэхгүй
  const [pendingChanges, setPendingChanges] = useState(0);
  const lastLoadTime = useRef(Date.now());
  const pendingChangesRef = useRef(0); // ⚡ throttle
  const badgeFlushTimer = useRef(null);

  useEffect(() => {
    // ⚡ Throttle: олон өөрчлөлт зэрэг ирэхэд 1.5с тутамд нэг л удаа setState
    const bumpBadge = () => {
      pendingChangesRef.current += 1;
      if (badgeFlushTimer.current) return;
      badgeFlushTimer.current = setTimeout(() => {
        setPendingChanges((prev) => prev + pendingChangesRef.current);
        pendingChangesRef.current = 0;
        badgeFlushTimer.current = null;
      }, 1500);
    };
    // Realtime channel — DB өөрчлөгдөхөд badge counter +1
    const channel = supabase
      .channel(`driver-badge-${profile.id}`)
      .on(
        "postgres_changes",
        { event: "*", schema: "public", table: "biz_orders" },
        (payload) => {
          // Сүүлд татсан хугацаанаас хойш өөрчлөгдсөн бол л badge харуулах
          const evtTime = new Date(payload.commit_timestamp || Date.now()).getTime();
          if (evtTime < lastLoadTime.current) return;
          
          const o = payload.new || payload.old;
          if (!o) return;
          
          // Зөвхөн чухал өөрчлөлтийг тоолох:
          const isRelevant = 
            (!o.driver_id && o.status === "new") ||
            o.driver_id === profile.id ||
            o.is_unknown === true;
          
          if (isRelevant) {
            bumpBadge();
          }
        }
      )
      .subscribe();
    
    return () => {
      supabase.removeChannel(channel);
      if (badgeFlushTimer.current) clearTimeout(badgeFlushTimer.current);
    };
  }, [profile.id]);

  // Manual refresh — Badge даргах
  const handleRefresh = async () => {
    const scrollY = window.scrollY || document.documentElement.scrollTop;
    lastLoadTime.current = Date.now();
    setPendingChanges(0);
    await loadAll();
    requestAnimationFrame(() => { window.scrollTo(0, scrollY); });
  };

  const handleLogout = async () => {
    if (!confirm("Гарах уу?")) return;
    await supabase.auth.signOut();
  };

  const updateStatus = async (orderId, newStatus) => {
    const updates = { status: newStatus };
    if (newStatus === "delivered") {
      updates.delivered_at = new Date().toISOString();
      updates.delivered_by = profile.id;
    }
    try {
      // 🚫 Хүргэгдсэн үед заавал агуулахаас бараа хасах — алгасч болохгүй
      if (newStatus === "delivered") {
        // ⚡ АТОМИК: захиалга delivered болгох + бараа хасах нэг транзакцид (RPC).
        //    Сүлжээ тасарсан ч хагас төлөв (movement орсон ч захиалга assigned) үүсэхгүй.
        //    Аль хэдийн delivered бол давхар хасахгүй (идемпотент).
        const { data: rpcData, error: rpcErr } = await supabase.rpc("deliver_order", {
          p_order_id: orderId,
          p_driver_id: profile.id,
        });

        if (rpcErr) {
          const isShortStock = rpcErr.message?.includes("үлдэгдэл хүрэлцэхгүй");
          if (isShortStock) {
            setInsufficientStockOrder({ orderId, msg: rpcErr.message || "Барааны үлдэгдэл хүрэлцэхгүй" });
            return;
          }
          // Бусад алдаа (агуулах алга, бараа холбогдоогүй г.м) — RPC-ийн мессежийг шууд харуулна
          alert(`🚫 Хүргэгдсэн гэж тэмдэглэх боломжгүй\n\n${rpcErr.message}`);
          return;
        }

        logDev("✓ deliver_order RPC:", rpcData);
      } else {
        // 🔄 ЗАСВАР: Захиалга өмнө delivered байсан БА одоо delivered БИШ (cancelled/assigned)
        //    болж байвал — өмнө хасагдсан барааг агуулахад БУЦААЖ нэмэх (in movement).
        //    Өмнө: delivered→cancelled үед out movement үлдэж, бараа буруу хасагдсан хэвээр байсан.
        const currentOrder = orders.find((o) => o.id === orderId);
        const wasDelivered = currentOrder?.status === "delivered";
        if (wasDelivered) {
          // Driver-ийн агуулах
          const { data: driverWh } = await supabase
            .from("inv_warehouses").select("id").eq("driver_id", profile.id).maybeSingle();
          // Захиалгын бараа
          const { data: orderItems } = await supabase
            .from("biz_order_items").select("product_id, quantity, product_name").eq("order_id", orderId);
          if (driverWh && orderItems && orderItems.length > 0) {
            const returnMovements = orderItems
              .filter((it) => it.product_id)
              .map((it) => ({
                product_id: it.product_id,
                warehouse_id: driverWh.id,
                movement_type: "in",
                quantity: Number(it.quantity || 0),
                reason: "return",
                created_by: profile.id,
                notes: `Захиалга #${orderId.slice(0, 8)} ${newStatus === "cancelled" ? "цуцлагдсан" : "буцаагдсан"}: ${it.product_name || ""} (нөөц сэргээв)`,
              }));
            if (returnMovements.length > 0) {
              await supabase.from("inv_movements").insert(returnMovements);
            }
          }
        }
        // Захиалгын статус шинэчлэх
        const { error: ordErr2 } = await supabase.from("biz_orders").update(updates).eq("id", orderId);
        if (ordErr2) throw ordErr2;
      }

      // ⚡ Optimistic update — зөвхөн тухайн захиалгын state шинэчилнэ
      setOrders((prev) => prev.map((o) =>
        o.id === orderId ? { ...o, ...updates } : o
      ));
      // activeOrder нээлттэй бол хаах (хүргэгдсэн/цуцлагдсан захиалга жагсаалтаас гарна)
      if (activeOrder?.id === orderId) setActiveOrder(null);
    } catch (e) {
      const isShortStock = e.message?.includes("үлдэгдэл хүрэлцэхгүй");
      if (isShortStock) {
        setInsufficientStockOrder({ orderId, msg: e.message });
        return;
      }
      alert("Алдаа: " + (e.message || JSON.stringify(e)));
    }
  };

  // Захиалга миний бүсэд багтах эсэхийг шалгах
  const isInMyZone = (order) => {
    if (myZones.length === 0) return false;
    if (!order.delivery_lat || !order.delivery_lng) return false;
    const point = [Number(order.delivery_lat), Number(order.delivery_lng)];
    return myZones.some((z) => isPointInPolygon(point, z.polygon || []));
  };

  // 🔄 Захиалгыг бусдын бүсийн driver-руу шилжүүлэх (Тодорхойгүй tab дотроос)
  const reassignByZone = async (order) => {
    if (!order.delivery_lat || !order.delivery_lng) {
      alert("⚠ Энэ захиалгад GPS координат байхгүй — гар аргаар хуваарилна уу");
      return;
    }
    try {
      // Бүх driver-ийн бүсүүдийг шалгаж, тус координат багтах бүсийг олох
      const { data: allZones } = await supabase.from("biz_zones")
        .select("id, name, driver_id, polygon")
        .eq("is_active", true);
      
      if (!allZones || allZones.length === 0) {
        alert("⚠ Бүс үүсгэгдээгүй байна");
        return;
      }
      
      const point = [Number(order.delivery_lat), Number(order.delivery_lng)];
      const matchingZone = allZones.find((z) => 
        z.driver_id !== profile.id && isPointInPolygon(point, z.polygon || [])
      );
      
      if (!matchingZone || !matchingZone.driver_id) {
        alert("⚠ Тохирох бүс олдсонгүй\n\nЭнэ захиалга ямар бүсэд ч багтаагүй байна.");
        return;
      }
      
      // Driver нэр авах
      const { data: drv } = await supabase.from("profiles")
        .select("name").eq("id", matchingZone.driver_id).single();
      
      if (!confirm(`📤 Энэ захиалгыг шилжүүлэх үү?\n\nАажах driver: 🚚 ${drv?.name || "?"}\nБүс: ${matchingZone.name}`)) return;
      
      // Driver солих
      await supabase.from("biz_orders").update({
        driver_id: matchingZone.driver_id,
      }).eq("id", order.id);
      
      alert(`✅ Захиалга 🚚 ${drv?.name} -руу амжилттай шилжсэн!`);
      await loadAll();
    } catch (e) {
      alert("Алдаа: " + e.message);
    }
  };

  // Filter
  const filtered = orders.filter((o) => {
    if (filter === "available") return o.status === "new" && !o.driver_id && !o.is_unknown;
    if (filter === "active") return o.driver_id === profile.id && !o.is_unknown && (o.status === "new" || o.status === "pending" || o.status === "assigned");
    // 🆕 Хуваарилах — зөвхөн Шинэ хэсэгт байгаа + миний бүсэд багтсан pin-тэй
    if (filter === "myzone") {
      return o.status === "new" && !o.driver_id && !o.is_unknown && isInMyZone(o);
    }
    // ❓ Тодорхойгүй — БҮХ DRIVER хардаг
    //   1. Шинэ дотор GPS байхгүй захиалга (хуваарилагдаагүй)
    //   2. Аль ч driver "is_unknown=true" болгосон захиалгууд
    if (filter === "unknown") {
      const noGpsNew = o.status === "new" && !o.driver_id && (!o.delivery_lat || !o.delivery_lng);
      const markedUnknown = o.is_unknown === true && o.status !== "delivered" && o.status !== "cancelled";
      return noGpsNew || markedUnknown;
    }
    // Хүргэсэн ба Цуцалсан tab-аас тооцоо хаагдсан (settlement_id-тэй) захиалгуудыг хасах
    if (filter === "delivered") return o.driver_id === profile.id && o.status === "delivered" && !o.settlement_id;
    if (filter === "cancelled") return o.driver_id === profile.id && o.status === "cancelled" && !o.settlement_id;
    return true;
  }).filter((o) => {
    // 🔍 Дугаар / нэр / хаяг / захиалгын дугаараар хайх
    if (!driverSearch.trim()) return true;
    const q = driverSearch.toLowerCase();
    return (
      o.customer_phone?.includes(q) ||
      o.customer_name?.toLowerCase().includes(q) ||
      o.delivery_address?.toLowerCase().includes(q) ||
      o.order_number?.toLowerCase().includes(q)
    );
  });

  // Pagination
  const totalPages = Math.ceil(filtered.length / PAGE_SIZE) || 1;
  const pageStart = (page - 1) * PAGE_SIZE;
  const pagedFiltered = filtered.slice(pageStart, pageStart + PAGE_SIZE);

  const counts = {
    available: orders.filter((o) => o.status === "new" && !o.driver_id && !o.is_unknown).length,
    myzone: orders.filter((o) => o.status === "new" && !o.driver_id && !o.is_unknown && isInMyZone(o)).length,
    unknown: orders.filter((o) => {
      const noGpsNew = o.status === "new" && !o.driver_id && (!o.delivery_lat || !o.delivery_lng);
      const markedUnknown = o.is_unknown === true && o.status !== "delivered" && o.status !== "cancelled";
      return noGpsNew || markedUnknown;
    }).length,
    active: orders.filter((o) => o.driver_id === profile.id && !o.is_unknown && (o.status === "new" || o.status === "pending" || o.status === "assigned")).length,
    delivered: orders.filter((o) => o.driver_id === profile.id && o.status === "delivered" && !o.settlement_id).length,
    cancelled: orders.filter((o) => o.driver_id === profile.id && o.status === "cancelled" && !o.settlement_id).length,
  };

  // Тушаах дүн: зөвхөн өөрийн settle хийгдээгүй delivered захиалгуудаас
  const myOwed = orders
    .filter((o) => o.driver_id === profile.id && o.status === "delivered" && !o.settlement_id)
    .reduce((sum, o) => sum + (Number(o.total_amount || 0) - Number(o.paid_amount || 0)), 0);
  const myDeliveredTotal = orders
    .filter((o) => o.driver_id === profile.id && o.status === "delivered" && !o.settlement_id)
    .reduce((sum, o) => sum + Number(o.total_amount || 0), 0);

  // Захиалга авах (claim)
  const claimOrder = async (orderId) => {
    if (!confirm("Энэ захиалгыг өөртөө авах уу?")) return;
    try {
      const { data, error } = await supabase
        .from("biz_orders")
        .update({
          driver_id: profile.id,
          status: "assigned",      // 🚚 driver авсан → assigned (Хүргэх tab-д тогтвортой үлдэнэ)
          is_unknown: false,        // 🆕 Тодорхойгүй flag-ийг арилгах
          assigned_at: new Date().toISOString(),
          assigned_by: profile.id,
        })
        .eq("id", orderId)
        .is("driver_id", null) // race condition сэргийлэх
        .select();
      if (error) throw error;
      if (!data || data.length === 0) {
        alert("⚠ Энэ захиалгыг өөр хүн аль хэдийнэ авсан байна.");
        await loadAll();
        return;
      }
      // Optimistic update — UI шууд шинэчлэх (одоогийн tab дээр үлдэнэ)
      setOrders((prev) => prev.map((order) =>
        order.id === orderId
          ? { ...order, driver_id: profile.id, is_unknown: false, status: "assigned" }
          : order
      ));
      alert("✅ Захиалга 'Хүргэх' хэсэгт орлоо!");
      // ⚡ loadAll() ажиллуулахгүй — optimistic update хангалттай (scroll position хадгална)
    } catch (e) {
      alert("Алдаа: " + (e.message || JSON.stringify(e)));
    }
  };

  return (
    <div className="min-h-screen" style={{ background: T.bg }}>
      <header className="sticky top-0 z-20 px-4 py-3 flex items-center gap-2"
        style={{ background: T.surface, borderBottom: `1px solid ${T.border}` }}>
        <div style={{ background: "#0ea5e9", color: "white" }}
          className="w-9 h-9 rounded-full flex items-center justify-center text-base">
          🚚
        </div>
        <div className="flex-1">
          <h1 style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-base">
            🚚 Delivery
          </h1>
          <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
            {profile.name || "—"}
          </div>
        </div>
        <button onClick={handleLogout}
          className="press-btn p-2 rounded-lg"
          style={{ color: T.err }}>
          <LogOut size={16} />
        </button>
      </header>

      {/* ⏱ Цаг бүртгэх */}
      <div className="px-3 pt-3 max-w-2xl mx-auto">
        <TimeTracker profile={profile} />
      </div>

      {/* Bottom navigation tabs */}
      <div className="px-3 pt-3 max-w-2xl mx-auto">
        <div className="glass rounded-2xl p-1.5 flex gap-1">
          <button onClick={() => setView("orders")}
            className="press-btn flex-1 py-2 rounded-lg text-xs flex items-center justify-center gap-1.5"
            style={{
              background: view === "orders" ? "#0ea5e9" : "transparent",
              color: view === "orders" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
            }}>
            <ShoppingBag size={13} />
            Захиалга
          </button>
          <button onClick={() => setView("warehouse")}
            className="press-btn flex-1 py-2 rounded-lg text-xs flex items-center justify-center gap-1.5"
            style={{
              background: view === "warehouse" ? "#0ea5e9" : "transparent",
              color: view === "warehouse" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
            }}>
            <Package size={13} />
            Агуулах
          </button>
          <button onClick={() => setView("requests")}
            className="press-btn flex-1 py-2 rounded-lg text-xs flex items-center justify-center gap-1.5"
            style={{
              background: view === "requests" ? "#0ea5e9" : "transparent",
              color: view === "requests" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
            }}>
            <Send size={13} />
            Хүсэлт
          </button>
          <button onClick={() => setView("settlements")}
            className="press-btn flex-1 py-2 rounded-lg text-xs flex items-center justify-center gap-1.5"
            style={{
              background: view === "settlements" ? "#0ea5e9" : "transparent",
              color: view === "settlements" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
            }}>
            <ClipboardCheck size={13} />
            Тооцоо
          </button>
        </div>
      </div>

      <div className="p-3 max-w-2xl mx-auto space-y-3">
        {view === "orders" && (<>
        {/* Stats — 4 card */}
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-2">
          <div className="glass rounded-2xl p-3 text-center">
            <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider">Хүргэх</div>
            <div style={{ fontFamily: FD, fontWeight: 700, color: "#0ea5e9" }} className="text-2xl">
              {counts.active}
            </div>
          </div>
          <div className="glass rounded-2xl p-3 text-center">
            <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider">Хүргэсэн</div>
            <div style={{ fontFamily: FD, fontWeight: 700, color: T.ok }} className="text-2xl">
              {counts.delivered}
            </div>
          </div>
          <div className="glass rounded-2xl p-3 text-center">
            <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider">Цуцлагдсан</div>
            <div style={{ fontFamily: FD, fontWeight: 700, color: T.err }} className="text-2xl">
              {counts.cancelled}
            </div>
          </div>
          <div className="glass rounded-2xl p-3 text-center" style={{ background: myOwed > 0 ? T.warnSoft : "transparent", borderLeft: myOwed > 0 ? `3px solid ${T.warn}` : "none" }}>
            <div style={{ fontFamily: FM, color: myOwed > 0 ? T.warn : T.muted, fontWeight: myOwed > 0 ? 700 : 400 }} className="text-[9px] uppercase tracking-wider">
              ⚠ Тушаах дүн
            </div>
            <div style={{ fontFamily: FD, fontWeight: 700, color: myOwed > 0 ? T.warn : T.muted }} className="text-base tabular-nums">
              {myOwed.toLocaleString()}₮
            </div>
          </div>
        </div>

        {/* List/Map toggle */}
        <div className="glass rounded-2xl p-2 flex gap-1">
          <button onClick={() => setViewMode("list")}
            className="press-btn flex-1 py-2 rounded-lg text-xs flex items-center justify-center gap-1.5"
            style={{
              background: viewMode === "list" ? "#0ea5e9" : T.surfaceAlt,
              color: viewMode === "list" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
            }}>
            📋 Жагсаалт
          </button>
          <button onClick={() => setViewMode("map")}
            className="press-btn flex-1 py-2 rounded-lg text-xs flex items-center justify-center gap-1.5"
            style={{
              background: viewMode === "map" ? "#0ea5e9" : T.surfaceAlt,
              color: viewMode === "map" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
            }}>
            🗺 Газрын зураг
          </button>
        </div>

        {/* 🔔 Шинэчлэх badge (зөвхөн өөрчлөлт байх үед) */}
        {pendingChanges > 0 && (
          <div style={{
            position: "sticky",
            top: 8,
            zIndex: 100,
          }}>
            <button onClick={handleRefresh}
              className="press-btn w-full py-3 rounded-2xl flex items-center justify-center gap-2 shadow-lg"
              style={{
                background: "linear-gradient(135deg, #f59e0b, #f97316)",
                color: "white",
                fontFamily: FS,
                fontWeight: 700,
                boxShadow: "0 4px 16px rgba(245, 158, 11, 0.5)",
                animation: "pulse 2s infinite",
              }}>
              <span className="text-lg">🔔</span>
              <span className="text-sm">
                {pendingChanges} шинэ өөрчлөлт байна — Дарж шинэчлэх
              </span>
            </button>
          </div>
        )}

        {/* Filter tabs */}
        <div className="glass rounded-2xl p-2 flex gap-1 flex-wrap">
          <button onClick={() => setFilter("available")}
            className="press-btn px-3 py-2 rounded-xl text-xs flex items-center justify-center gap-1 relative"
            style={{
              background: filter === "available" ? "#9333ea" : T.surfaceAlt,
              color: filter === "available" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
              minWidth: "80px",
            }}>
            🆕 Шинэ ({counts.available})
            {counts.available > 0 && filter !== "available" && (
              <span style={{
                position: "absolute", top: -4, right: -4,
                background: T.err, color: "white",
                width: 16, height: 16, borderRadius: "50%",
                fontSize: 9, fontWeight: 700,
                display: "flex", alignItems: "center", justifyContent: "center",
              }}>
                {counts.available}
              </span>
            )}
          </button>

          {/* 📍 Хуваарилах (миний бүсэд) */}
          {myZones.length > 0 && (
            <button onClick={() => setFilter("myzone")}
              className="press-btn px-3 py-2 rounded-xl text-xs flex items-center justify-center gap-1 relative"
              style={{
                background: filter === "myzone" ? "#10b981" : T.surfaceAlt,
                color: filter === "myzone" ? "white" : T.ink,
                fontFamily: FS, fontWeight: 600,
                minWidth: "100px",
              }}>
              📍 Хуваарилах ({counts.myzone})
              {counts.myzone > 0 && filter !== "myzone" && (
                <span style={{
                  position: "absolute", top: -4, right: -4,
                  background: T.err, color: "white",
                  width: 16, height: 16, borderRadius: "50%",
                  fontSize: 9, fontWeight: 700,
                  display: "flex", alignItems: "center", justifyContent: "center",
                }}>
                  {counts.myzone}
                </span>
              )}
            </button>
          )}

          {/* ❓ Тодорхойгүй */}
          {counts.unknown > 0 && (
            <button onClick={() => setFilter("unknown")}
              className="press-btn px-3 py-2 rounded-xl text-xs flex items-center justify-center gap-1 relative"
              style={{
                background: filter === "unknown" ? "#f59e0b" : T.surfaceAlt,
                color: filter === "unknown" ? "white" : T.ink,
                fontFamily: FS, fontWeight: 600,
                minWidth: "100px",
              }}>
              ❓ Тодорхойгүй ({counts.unknown})
            </button>
          )}

          <button onClick={() => setFilter("active")}
            className="press-btn px-3 py-2 rounded-xl text-xs flex items-center justify-center gap-1"
            style={{
              background: filter === "active" ? "#0ea5e9" : T.surfaceAlt,
              color: filter === "active" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
              minWidth: "80px",
            }}>
            🚚 Хүргэх ({counts.active})
          </button>
          <button onClick={() => setFilter("delivered")}
            className="press-btn px-3 py-2 rounded-xl text-xs flex items-center justify-center gap-1"
            style={{
              background: filter === "delivered" ? T.ok : T.surfaceAlt,
              color: filter === "delivered" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
              minWidth: "80px",
            }}>
            ✓ Хүргэсэн ({counts.delivered})
          </button>
          <button onClick={() => setFilter("cancelled")}
            className="press-btn px-3 py-2 rounded-xl text-xs flex items-center justify-center gap-1"
            style={{
              background: filter === "cancelled" ? T.err : T.surfaceAlt,
              color: filter === "cancelled" ? "white" : T.ink,
              fontFamily: FS, fontWeight: 600,
              minWidth: "80px",
            }}>
            ✕ Цуцалсан ({counts.cancelled})
          </button>
        </div>

        {/* 🔍 Хайх — дугаар, нэр, хаяг, захиалгын ID */}
        <div className="glass rounded-2xl p-2 flex items-center gap-2">
          <span style={{ color: T.muted }} className="pl-1">🔍</span>
          <input
            value={driverSearch}
            onChange={(e) => { setDriverSearch(e.target.value); setPage(1); }}
            placeholder="Дугаар, нэр, хаягаар хайх..."
            className="flex-1 bg-transparent outline-none text-sm"
            style={{ color: T.ink, fontFamily: FS }}
          />
          {driverSearch && (
            <button onClick={() => setDriverSearch("")}
              className="press-btn px-2 py-1 rounded-lg text-xs"
              style={{ background: T.surfaceAlt, color: T.muted, fontFamily: FS }}>
              ✕
            </button>
          )}
        </div>

        {/* Orders list / Map */}
        {loading ? (
          <div className="glass rounded-2xl p-8 text-center">
            <Loader2 className="spin mx-auto" size={20} style={{ color: T.muted }} />
          </div>
        ) : viewMode === "map" ? (
          <OrdersMapView 
            orders={filtered} 
            drivers={[]}
            onOrderClick={(o) => setActiveOrder(o)}
          />
        ) : filtered.length === 0 ? (
          <div className="glass rounded-2xl p-8 text-center">
            <div className="text-4xl mb-2">🚚</div>
            <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
              {filter === "active" ? "Хүргэх захиалга алга" : "Хоосон"}
            </div>
          </div>
        ) : (
          <div className="space-y-2">
            {pagedFiltered.map((o, idx) => {
              const hasPin = o.delivery_lat && o.delivery_lng;
              return (
              <div key={o.id} className="glass rounded-xl p-3"
                onMouseEnter={() => setHoveredOrderId(o.id)}
                onMouseLeave={() => setHoveredOrderId(null)}
                style={{
                  borderLeft: !hasPin ? `4px solid ${T.err}` : "none",
                  background: !hasPin ? "rgba(239,68,68,0.04)" : undefined,
                  transition: "transform 0.18s cubic-bezier(0.34, 1.56, 0.64, 1), box-shadow 0.18s ease",
                  transform: hoveredOrderId === o.id ? "translateY(-5px) scale(1.015)" : "translateY(0) scale(1)",
                  boxShadow: hoveredOrderId === o.id
                    ? "0 16px 40px rgba(14, 165, 233, 0.35), 0 0 0 2px #0ea5e9"
                    : undefined,
                  zIndex: hoveredOrderId === o.id ? 5 : 1,
                  position: "relative",
                }}>
                {!hasPin && (
                  <div className="flex items-center justify-between mb-1.5">
                    <div style={{ color: T.err, fontFamily: FM, fontWeight: 600 }} className="text-[10px] flex items-center gap-1">
                      📍 Pin байрлуулаагүй
                    </div>
                    <button onClick={() => setActiveOrder(o)}
                      className="press-btn px-2.5 py-1 rounded-full flex items-center gap-1 text-[10px] flex-shrink-0"
                      style={{
                        background: "linear-gradient(135deg, #6366f1, #4f46e5)",
                        color: "white", fontFamily: FS, fontWeight: 700,
                      }}>
                      <MapPin size={11} /> Pin зоох
                    </button>
                  </div>
                )}
                <div className="flex items-start gap-2">
                  <div style={{
                    background: "rgba(14,165,233,0.1)", color: "#0ea5e9",
                    fontFamily: FD, fontWeight: 700,
                  }} className="w-7 h-7 rounded-full flex items-center justify-center text-xs flex-shrink-0">
                    {idx + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap mb-1">
                      <button
                        onClick={(e) => { e.stopPropagation(); setPhoneAction({ phone: o.customer_phone }); }}
                        style={{ color: "#0ea5e9", fontFamily: FD, fontWeight: 700 }}
                        className="text-sm tabular-nums hover:underline">
                        📞 {o.customer_phone}
                      </button>
                      {o.customer_name && (
                        <span style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-xs">
                          {o.customer_name}
                        </span>
                      )}
                      {/* 🔗 FB Page badge */}
                      {o.fb_page_id && fbPagesMap[o.fb_page_id] && (
                        <span style={{
                          background: "rgba(14,165,233,0.1)",
                          color: "#0284c7",
                          fontFamily: FS,
                          fontWeight: 600,
                        }} className="text-[9px] px-1.5 py-0.5 rounded">
                          🔗 {fbPagesMap[o.fb_page_id]}
                        </span>
                      )}
                    </div>
                    {o.delivery_address && (
                      <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mb-2 flex items-start gap-1">
                        <MapPin size={11} style={{ color: T.highlight, flexShrink: 0, marginTop: 1 }} />
                        <span>{o.delivery_address}</span>
                      </div>
                    )}
                    <div className="flex items-center gap-2 flex-wrap">
                      <span style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="text-sm tabular-nums">
                        {Number(o.total_amount).toLocaleString()}₮
                      </span>
                      {Number(o.paid_amount || 0) > 0 && (
                        <span style={{ background: T.okSoft, color: T.ok, fontFamily: FS, fontWeight: 700 }}
                          className="text-[10px] px-1.5 py-0.5 rounded-full">
                          💰 Урьдчилж: {Number(o.paid_amount).toLocaleString()}₮
                        </span>
                      )}
                      {(() => {
                        // Үлдэгдэл = нийт дүн − төлсөн (статик balance_due биш, бодит тооцоо)
                        const remaining = Number(o.total_amount || 0) - Number(o.paid_amount || 0);
                        return remaining > 0 ? (
                          <span style={{ background: T.warnSoft, color: T.warn, fontFamily: FS, fontWeight: 600 }}
                            className="text-[10px] px-1.5 py-0.5 rounded-full">
                            ⚠ Үлдэгдэл: {remaining.toLocaleString()}₮
                          </span>
                        ) : null;
                      })()}
                    </div>
                  </div>
                  {o.delivery_lat && o.delivery_lng && (
                    <button onClick={() => setActiveOrder(o)}
                      className="press-btn w-9 h-9 rounded-full flex items-center justify-center flex-shrink-0"
                      style={{
                        background: "linear-gradient(135deg, #6366f1, #4f46e5)",
                        color: "white",
                      }}
                      title="Дэлгэрэнгүй харах">
                      <MapPin size={14} />
                    </button>
                  )}
                </div>

                {/* Items */}
                {(items[o.id] || []).length > 0 && (
                  <div className="mt-2 pt-2 flex gap-1.5 overflow-x-auto" style={{ borderTop: `1px solid ${T.borderSoft}` }}>
                    {(items[o.id] || []).slice(0, 5).map((it, i) => (
                      <div key={i} className="flex items-center gap-1 px-2 py-1 rounded-lg flex-shrink-0"
                        style={{ background: T.surfaceAlt }}>
                        {it.product_image && (
                          <img src={it.product_image} alt=""
                            style={{ width: 24, height: 24, objectFit: "cover", borderRadius: 4 }} />
                        )}
                        <span style={{ color: T.ink, fontFamily: FM, fontWeight: 500 }} className="text-[10px]">
                          {it.product_name}
                        </span>
                        <span style={{ background: "#0ea5e9", color: "white", fontFamily: FD, fontWeight: 700 }}
                          className="text-[9px] px-1 rounded-full">
                          ×{it.quantity}
                        </span>
                      </div>
                    ))}
                  </div>
                )}

                {/* Action buttons */}
                {!o.driver_id && o.status === "new" ? (
                  // Эзэнгүй захиалга — Авах эсвэл Хуваарилах
                  <div className={filter === "unknown" ? "mt-2" : "grid grid-cols-2 gap-2 mt-2"}>
                    <button onClick={(e) => { e.stopPropagation(); claimOrder(o.id); }}
                      className="press-btn w-full py-2.5 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                      style={{
                        background: "linear-gradient(135deg, #9333ea, #c026d3)",
                        color: "white", fontFamily: FS,
                      }}>
                      🆕 Өөртөө авах
                    </button>
                    {/* "Тодорхойгүй" tab дотор бол → "Хүргэлт хуваарилах" товч АЛГА */}
                    {filter !== "unknown" && (
                      <button onClick={(e) => { e.stopPropagation(); setAssignDriverOrder(o); }}
                        className="press-btn py-2.5 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                        style={{
                          background: "rgba(14,165,233,0.1)", color: "#0ea5e9", fontFamily: FS,
                          border: `1px solid #0ea5e9`,
                        }}>
                        🚚 Хүргэлт хуваарилах
                      </button>
                    )}
                  </div>
                ) : (o.status === "new" || o.status === "pending" || o.status === "assigned") && (
                  <div className="space-y-2 mt-2">
                    {/* "Тодорхойгүй" tab дотор → "Өөртөө авах" товч (БҮХ unknown захиалгад) */}
                    {filter === "unknown" && (
                      <button onClick={async () => {
                        if (!confirm(`✅ Энэ захиалгыг өөртөө авах уу?\n\n#${o.order_number || o.id.slice(0, 8)}\n📞 ${o.customer_phone}\n💰 ${Number(o.total_amount).toLocaleString()}₮\n\nЭнэ нь таны "🚚 Хүргэх" хэсэгт орно.`)) return;
                        try {
                          const { error, data } = await supabase.from("biz_orders").update({
                            driver_id: profile.id,
                            is_unknown: false,
                            status: "assigned",
                          }).eq("id", o.id).select();
                          
                          logDev("[Өөртөө авах] Result:", { error, data });
                          
                          if (error) {
                            alert("⚠ Алдаа: " + error.message);
                            return;
                          }
                          
                          // Optimistic update (одоогийн tab дээр үлдэнэ)
                          setOrders((prev) => prev.map((order) =>
                            order.id === o.id
                              ? { ...order, driver_id: profile.id, is_unknown: false, status: "assigned" }
                              : order
                          ));
                          // ⚡ loadAll() ажиллуулахгүй — optimistic update хангалттай (scroll position хадгална)
                        } catch (e) { 
                          console.error("[Өөртөө авах] Error:", e);
                          alert("Алдаа: " + (e.message || JSON.stringify(e))); 
                        }
                      }}
                        className="press-btn w-full py-2.5 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                        style={{ background: T.highlight, color: "white", fontFamily: FS, fontWeight: 700 }}>
                        ✅ Өөртөө авах
                      </button>
                    )}
                    {/* "Тодорхойгүй" tab → "Хүргэлт хуваарилах" (өөр driver-т оноох) */}
                    {filter === "unknown" && (
                      <button onClick={() => setAssignOrder(o)}
                        className="press-btn w-full py-2 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                        style={{ background: "#0ea5e9", color: "white", fontFamily: FS, fontWeight: 600 }}>
                        🚚 Хүргэлт хуваарилах
                      </button>
                    )}
                    {/* "Хүргэх" tab дотор → "Тодорхойгүй болгох" товч */}
                    {filter === "active" && o.driver_id === profile.id && !o.is_unknown && (
                      <button onClick={async () => {
                        if (!confirm("❓ Энэ захиалгыг 'Тодорхойгүй' болгох уу?\n\nБусад driver хариц хариуцагч авах боломжтой.")) return;
                        try {
                          const { error, data } = await supabase.from("biz_orders").update({ 
                            is_unknown: true,
                            driver_id: null,
                          }).eq("id", o.id).select();
                          
                          logDev("[Тодорхойгүй болгох] Result:", { error, data });
                          
                          if (error) {
                            alert("⚠ Алдаа: " + error.message);
                            return;
                          }
                          
                          setOrders((prev) => prev.map((order) => 
                            order.id === o.id 
                              ? { ...order, is_unknown: true, driver_id: null }
                              : order
                          ));
                          await loadAll();
                          alert("✅ Захиалга 'Тодорхойгүй' хэсэгт орлоо");
                        } catch (e) { 
                          console.error("[Тодорхойгүй болгох] Error:", e);
                          alert("Алдаа: " + (e.message || JSON.stringify(e))); 
                        }
                      }}
                        className="press-btn w-full py-2 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                        style={{ background: T.warnSoft, color: T.warn, fontFamily: FS, fontWeight: 600, border: `1px solid ${T.warn}` }}>
                        ❓ Тодорхойгүй болгох
                      </button>
                    )}
                    <div className="grid grid-cols-1 gap-2">
                      {/* "Тодорхойгүй" tab дотор бол → "Хүргэсэн"/"Амжилтгүй" товч АЛГА */}
                      {filter !== "unknown" && (
                        <div className="grid grid-cols-2 gap-2">
                          <button onClick={() => setRatingOrder({ order: o, action: "delivered" })}
                            className="press-btn py-2.5 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                            style={{ background: T.ok, color: "white", fontFamily: FS }}>
                            ✓ Хүргэсэн
                          </button>
                          <button onClick={() => setRatingOrder({ order: o, action: "cancelled" })}
                            className="press-btn py-2.5 rounded-lg text-xs font-semibold flex items-center justify-center gap-1.5"
                            style={{ background: T.errSoft, color: T.err, fontFamily: FS, fontWeight: 600, border: `1px solid ${T.err}` }}>
                            ✕ Амжилтгүй
                          </button>
                        </div>
                      )}
                    </div>
                  </div>
                )}
              </div>
              );
            })}
          </div>
        )}

        {/* Pagination */}
        {view === "orders" && filtered.length > PAGE_SIZE && (
          <div className="glass rounded-2xl p-3 flex items-center justify-between flex-wrap gap-2">
            <div style={{ color: T.muted, fontFamily: FM }} className="text-xs">
              {pageStart + 1}-{Math.min(pageStart + PAGE_SIZE, filtered.length)} / {filtered.length}
            </div>
            <div className="flex items-center gap-1">
              <button onClick={() => setPage(1)} disabled={page === 1}
                className="press-btn px-2 py-1 rounded text-xs"
                style={{ background: page === 1 ? T.surfaceAlt : T.surface, color: T.ink, fontFamily: FS, fontWeight: 600 }}>
                ⏮
              </button>
              <button onClick={() => setPage((p) => Math.max(1, p - 1))} disabled={page === 1}
                className="press-btn px-2 py-1 rounded text-xs"
                style={{ background: page === 1 ? T.surfaceAlt : T.surface, color: T.ink, fontFamily: FS, fontWeight: 600 }}>
                ◀
              </button>
              <span style={{ color: T.ink, fontFamily: FD, fontWeight: 700 }} className="px-3 text-sm">
                {page} / {totalPages}
              </span>
              <button onClick={() => setPage((p) => Math.min(totalPages, p + 1))} disabled={page === totalPages}
                className="press-btn px-2 py-1 rounded text-xs"
                style={{ background: page === totalPages ? T.surfaceAlt : T.surface, color: T.ink, fontFamily: FS, fontWeight: 600 }}>
                ▶
              </button>
              <button onClick={() => setPage(totalPages)} disabled={page === totalPages}
                className="press-btn px-2 py-1 rounded text-xs"
                style={{ background: page === totalPages ? T.surfaceAlt : T.surface, color: T.ink, fontFamily: FS, fontWeight: 600 }}>
                ⏭
              </button>
            </div>
          </div>
        )}
        </>)}

        {view === "warehouse" && (
          <DriverWarehouseView profile={profile} />
        )}

        {view === "requests" && (
          <DriverRequestsView profile={profile} />
        )}

        {view === "settlements" && (
          <DriverSettlementsView profile={profile} myOwed={myOwed} myDeliveredTotal={myDeliveredTotal} />
        )}
      </div>

      {/* Order detail modal — admin-маягийн дэлгэрэнгүй харах modal */}
      {activeOrder && createPortal(
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 9998,
          display: "flex", alignItems: "flex-start", justifyContent: "center", padding: 12,
          background: "rgba(14, 156, 142, 0.15)",
          backdropFilter: "blur(8px)",
          overflowY: "auto",
        }}
          onClick={() => { setActiveOrder(null); }}>
          <div style={{
              background: T.bg,
              borderRadius: 16, width: "100%", maxWidth: 600,
              padding: 12, marginTop: 12, marginBottom: 12,
              boxShadow: "0 24px 48px rgba(14, 156, 142, 0.3)",
            }}
            onClick={(e) => e.stopPropagation()}>
            <OrderDetail
              order={activeOrder}
              items={items[activeOrder.id] || []}
              isDriver={true}
              currentDriverId={profile.id}
              onClose={() => { setActiveOrder(null); }}
              onUpdateStatus={async (s) => {
                if (s === "delivered") {
                  // Хүргэсэн → үнэлгээ popup нээх
                  setRatingOrder({ order: activeOrder, action: "delivered" });
                  setRatingValue(0);
                  setRatingNote("");
                  setActiveOrder(null);
                  return;
                }
                await updateStatus(activeOrder.id, s);
                setActiveOrder(null);
              }}
              onClaim={async () => {
                await claimOrder(activeOrder.id);
                setActiveOrder(null);
              }}
              onAssignDriver={() => {
                setAssignDriverOrder(activeOrder);
                setActiveOrder(null);
              }}
              onCancelWithNote={() => {
                // Хүргэх боломжгүй → үнэлгээ popup нээх (cancel-note-ийн оронд)
                setRatingOrder({ order: activeOrder, action: "cancelled" });
                setRatingValue(0);
                setRatingNote("");
                setActiveOrder(null);
              }}
            />
          </div>
        </div>,
        document.body
      )}

      {/* Driver picker — Хүргэлт хуваарилах modal */}
      {/* ⭐ Үнэлгээ popup — driver хүргэх/цуцлах сонголтоор гарна */}
      {ratingOrder && createPortal(
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 10001,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 12,
          background: "rgba(0,0,0,0.6)", backdropFilter: "blur(6px)",
        }}
          onClick={() => !ratingBusy && setRatingOrder(null)}>
          <div style={{
            background: T.bg, borderRadius: 16, width: "100%", maxWidth: 420,
            boxShadow: "0 24px 48px rgba(0,0,0,0.4)",
            border: `1px solid ${T.border}`,
            maxHeight: "90vh", overflowY: "auto",
          }}
            onClick={(e) => e.stopPropagation()}>
            <div className="p-5">
              {/* Header */}
              <div className="text-center mb-4">
                <div className="text-4xl mb-2">
                  {ratingOrder.action === "delivered" ? "✅" : "❌"}
                </div>
                <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-base mb-1">
                  {ratingOrder.action === "delivered" ? "Захиалга хүргэгдлээ" : "Захиалга хүргэх боломжгүй"}
                </div>
                <div style={{ color: T.muted, fontFamily: FM }} className="text-xs">
                  Operator-ийн ажилд үнэлгээ өгнө үү
                </div>
              </div>

              {/* Order info */}
              <div className="rounded-lg p-2.5 mb-4" style={{ background: T.surfaceAlt }}>
                <div style={{ fontFamily: FD, fontWeight: 600, color: T.ink }} className="text-sm">
                  📞 {ratingOrder.order.customer_phone}
                </div>
                {ratingOrder.order.customer_name && (
                  <div style={{ color: T.muted, fontFamily: FS }} className="text-xs">
                    {ratingOrder.order.customer_name}
                  </div>
                )}
                {ratingOrder.order.delivery_address && (
                  <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-1">
                    📍 {ratingOrder.order.delivery_address}
                  </div>
                )}
              </div>

              {/* ⭐⭐⭐⭐⭐ Rating selector */}
              <div className="mb-4">
                <label style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mb-2 block text-center">
                  ⭐ Operator-ийн ажилд үнэлгээ өгөх
                </label>
                <div className="flex justify-center gap-2 mb-2">
                  {[1, 2, 3, 4, 5].map((star) => (
                    <button key={star}
                      onClick={() => setRatingValue(star)}
                      className="press-btn"
                      style={{
                        fontSize: 36,
                        lineHeight: 1,
                        opacity: ratingValue >= star ? 1 : 0.3,
                        transition: "all 0.15s",
                        cursor: "pointer",
                      }}>
                      {ratingValue >= star ? "⭐" : "☆"}
                    </button>
                  ))}
                </div>
                <div className="text-center">
                  <span style={{ 
                    fontFamily: FS, fontWeight: 700,
                    color: ratingValue >= 4 ? T.ok : ratingValue >= 3 ? T.warn : ratingValue >= 1 ? T.err : T.muted,
                  }} className="text-sm">
                    {ratingValue === 0 && "Үнэлгээ өгөөгүй"}
                    {ratingValue === 1 && "😞 Маш муу"}
                    {ratingValue === 2 && "😐 Муу"}
                    {ratingValue === 3 && "🙂 Дунд"}
                    {ratingValue === 4 && "😊 Сайн"}
                    {ratingValue === 5 && "🤩 Маш сайн"}
                  </span>
                </div>
              </div>

              {/* Тэмдэглэл */}
              <div className="mb-4">
                <label style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mb-1 block">
                  📝 Тэмдэглэл (заавал биш)
                </label>
                <textarea value={ratingNote}
                  onChange={(e) => setRatingNote(e.target.value)}
                  placeholder={ratingOrder.action === "cancelled" 
                    ? "Жнь: Хаяг буруу, утсаа авахгүй..." 
                    : "Жнь: Утсаар бүх зүйлийг сайн тайлбарласан..."
                  }
                  style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS }}
                  className="w-full px-3 py-2 rounded-lg text-sm"
                  rows={3} />
              </div>

              {/* Action товчнууд */}
              <div className="grid grid-cols-2 gap-2">
                <button onClick={() => setRatingOrder(null)} disabled={ratingBusy}
                  className="press-btn py-3 rounded-xl text-sm font-semibold"
                  style={{ background: T.surfaceAlt, color: T.muted, border: `1px solid ${T.border}`, fontFamily: FS }}>
                  Цуцлах
                </button>
                <button onClick={async () => {
                  if (ratingValue === 0) {
                    alert("⚠ Үнэлгээ өгнө үү (1-5 од)");
                    return;
                  }
                  setRatingBusy(true);
                  try {
                    // Operator-ийг олох — энэ захиалгын утсаар operator байсан хүнийг
                    let operatorId = ratingOrder.order.operator_id;
                    if (!operatorId && ratingOrder.order.customer_phone) {
                      // Тус утсанд хийгдсэн дуудлагуудаас operator олох
                      const { data: callData } = await supabase
                        .from("biz_calls")
                        .select("operator_id")
                        .eq("phone", ratingOrder.order.customer_phone)
                        .order("created_at", { ascending: false })
                        .limit(1);
                      if (callData && callData.length > 0) {
                        operatorId = callData[0].operator_id;
                      }
                    }
                    
                    // Update biz_orders
                    const orderUpdates = {
                      operator_rating: ratingValue,
                      operator_rating_note: ratingNote.trim() || null,
                    };
                    if (operatorId) orderUpdates.operator_id = operatorId;
                    
                    if (ratingOrder.action === "delivered") {
                      // Stock хасахын тулд updateStatus ажиллуулна
                      await supabase.from("biz_orders").update(orderUpdates).eq("id", ratingOrder.order.id);
                      await updateStatus(ratingOrder.order.id, "delivered");
                    } else {
                      // Cancelled — note + rating
                      const cancelNote = ratingNote.trim();
                      const fullNote = cancelNote ? `[Хүргэх боломжгүй]\n${cancelNote}` : "[Хүргэх боломжгүй]";
                      await supabase.from("biz_orders").update({
                        ...orderUpdates,
                        status: "cancelled",
                        notes: fullNote,
                      }).eq("id", ratingOrder.order.id);
                      // 🆕 biz_calls-д cancelled дуудлага нэмэх → cycle хаагдана
                      if (ratingOrder.order.customer_phone) {
                        const { data: lastC } = await supabase.from("biz_calls")
                          .select("call_status").eq("phone", ratingOrder.order.customer_phone)
                          .order("created_at", { ascending: false }).limit(1).maybeSingle();
                        if (lastC?.call_status !== "cancelled") {
                          await supabase.from("biz_calls").insert({
                            phone: ratingOrder.order.customer_phone,
                            customer_name: ratingOrder.order.customer_name || null,
                            call_status: "cancelled",
                            fb_page_id: ratingOrder.order.fb_page_id || null,
                            created_at: new Date().toISOString(),
                          });
                        }
                      }
                      // ⚡ Optimistic update (loadAll биш — scroll/page хэвээр)
                      setOrders((prev) => prev.map((o) =>
                        o.id === ratingOrder.order.id ? { ...o, status: "cancelled", notes: fullNote } : o
                      ));
                    }
                    
                    setRatingOrder(null);
                    setRatingValue(0);
                    setRatingNote("");
                  } catch (e) {
                    if (e.message?.includes("үлдэгдэл хүрэлцэхгүй")) {
                      setInsufficientStockOrder({ orderId: ratingOrder.order.id, msg: e.message });
                    } else {
                      alert("Алдаа: " + e.message);
                    }
                  } finally {
                    setRatingBusy(false);
                  }
                }} disabled={ratingBusy}
                  className="press-btn py-3 rounded-xl text-sm font-semibold"
                  style={{ 
                    background: ratingOrder.action === "delivered" ? T.ok : T.err, 
                    color: "white", fontFamily: FS, fontWeight: 700,
                  }}>
                  {ratingBusy ? "Хадгалж байна..." : (ratingOrder.action === "delivered" ? "✓ Хүргэсэн" : "✕ Цуцлах")}
                </button>
              </div>
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* Үлдэгдэл хүрэлцэхгүй popup */}
      {insufficientStockOrder && createPortal(
        (() => {
          // Алдааны мессежээс барааны нэр + тоо ялгах
          const msg = insufficientStockOrder.msg || "";
          const productMatch = msg.match(/"([^"]+)"|: ([^(\-]+?)(?: \(|-|$)/);
          const productName = productMatch ? (productMatch[1] || productMatch[2] || "").trim() : null;
          const qtyMatch = msg.match(/(\d+)\s*ширхэг байгаа.*?(\d+)\s*ширхэг хасах/);
          const haveQty = qtyMatch ? qtyMatch[1] : "0";
          const needQty = qtyMatch ? qtyMatch[2] : "?";
          
          return (
            <div style={{
              position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 10000,
              display: "flex", alignItems: "center", justifyContent: "center", padding: 16,
              background: "rgba(0,0,0,0.5)", backdropFilter: "blur(4px)",
            }}
              onClick={() => setInsufficientStockOrder(null)}>
              <div style={{
                background: T.bg, borderRadius: 16, width: "100%", maxWidth: 420,
                boxShadow: "0 24px 48px rgba(239, 68, 68, 0.3)",
                border: `2px solid ${T.err}`,
              }}
                onClick={(e) => e.stopPropagation()}>
                <div className="p-5">
                  <div className="text-center mb-3">
                    <div className="text-5xl mb-2">📭</div>
                    <div style={{ fontFamily: FS, fontWeight: 700, color: T.err }} className="text-base">
                      Барааны үлдэгдэл хүрэлцэхгүй
                    </div>
                  </div>

                  {/* Product info */}
                  {productName && (
                    <div className="rounded-lg p-3 mb-3" style={{ background: T.errSoft, border: `1px solid ${T.err}` }}>
                      <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
                        Дутагдаж буй бараа
                      </div>
                      <div style={{ color: T.ink, fontFamily: FS, fontWeight: 700 }} className="text-sm mt-0.5">
                        📦 {productName}
                      </div>
                      <div className="flex justify-around mt-2 pt-2" style={{ borderTop: `1px solid ${T.border}` }}>
                        <div className="text-center">
                          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase">Танд байгаа</div>
                          <div style={{ fontFamily: FD, fontWeight: 700, color: T.err }} className="text-xl tabular-nums">
                            {haveQty}
                          </div>
                        </div>
                        <div style={{ alignSelf: "center", color: T.muted, fontFamily: FD }}>→</div>
                        <div className="text-center">
                          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase">Хэрэгтэй</div>
                          <div style={{ fontFamily: FD, fontWeight: 700, color: T.warn }} className="text-xl tabular-nums">
                            {needQty}
                          </div>
                        </div>
                      </div>
                    </div>
                  )}

                  {/* Hint */}
                  <div style={{ color: T.muted, fontFamily: FM }} className="text-xs text-center mb-3">
                    💡 "Хүсэлт" хэсгээс энэ барааг авах хүсэлт илгээнэ үү
                  </div>

                  <button onClick={() => setInsufficientStockOrder(null)}
                    className="press-btn w-full py-3 rounded-xl text-sm font-semibold"
                    style={{ background: T.err, color: "white", fontFamily: FS }}>
                    Ойлголоо
                  </button>
                </div>
              </div>
            </div>
          );
        })(),
        document.body
      )}

      {assignDriverOrder && createPortal(
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 9999,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 8,
          background: "rgba(0,0,0,0.5)", backdropFilter: "blur(4px)",
        }}
          onClick={() => setAssignDriverOrder(null)}>
          <div style={{
            background: T.bg, borderRadius: 16, width: "100%", maxWidth: 480,
            maxHeight: "85vh", overflowY: "auto",
            boxShadow: "0 24px 48px rgba(0,0,0,0.3)",
          }}
            onClick={(e) => e.stopPropagation()}>
            
            <div className="px-4 py-3 sticky top-0" style={{
              borderBottom: `1px solid ${T.border}`, background: T.bg, zIndex: 1,
            }}>
              <div className="flex items-center justify-between">
                <div>
                  <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-base flex items-center gap-2">
                    🚚 Хүргэлт хуваарилах
                  </div>
                  <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-0.5">
                    {assignDriverOrder.customer_name || assignDriverOrder.customer_phone}
                  </div>
                </div>
                <button onClick={() => setAssignDriverOrder(null)} style={{ color: T.muted }}>
                  <X size={18} />
                </button>
              </div>
            </div>
            
            <div className="p-3">
              {drivers.length === 0 ? (
                <div className="text-center py-6">
                  <div className="text-4xl mb-2">🚚</div>
                  <div style={{ color: T.muted, fontFamily: FS }} className="text-sm">
                    Delivery ажилтан бүртгэгдээгүй
                  </div>
                </div>
              ) : (
                <div className="space-y-1.5">
                  {drivers.map((d) => {
                    const dOrders = orders.filter((o) => o.driver_id === d.id);
                    const activeCount = dOrders.filter((o) => o.status === "new" || o.status === "pending" || o.status === "assigned").length;
                    const isMe = d.id === profile.id;
                    return (
                      <button key={d.id}
                        onClick={async () => {
                          try {
                            const { data, error } = await supabase
                              .from("biz_orders")
                              .update({
                                driver_id: d.id,
                                status: "assigned",
                                is_unknown: false,
                                assigned_at: new Date().toISOString(),
                                assigned_by: profile.id,
                              })
                              .eq("id", assignDriverOrder.id)
                              .is("driver_id", null)
                              .select();
                            if (error) throw error;
                            if (!data || data.length === 0) {
                              alert("⚠ Энэ захиалгыг өөр хүн аль хэдийнэ авсан байна.");
                              setAssignDriverOrder(null);
                              return;
                            }
                            // ⚡ Optimistic update (loadAll биш)
                            setOrders((prev) => prev.map((o) =>
                              o.id === assignDriverOrder.id
                                ? { ...o, driver_id: d.id, is_unknown: false, status: "assigned" }
                                : o
                            ));
                            alert(`✅ ${d.name}-руу хуваарилагдлаа!`);
                            setAssignDriverOrder(null);
                          } catch (e) {
                            alert("Алдаа: " + (e.message || JSON.stringify(e)));
                          }
                        }}
                        className="press-btn w-full p-3 rounded-xl flex items-center gap-3"
                        style={{
                          background: isMe ? "rgba(147,51,234,0.1)" : T.surfaceAlt,
                          border: isMe ? `2px solid #9333ea` : `2px solid transparent`,
                        }}>
                        <div style={{
                          background: isMe ? "linear-gradient(135deg, #9333ea, #c026d3)" : "#0ea5e9",
                          color: "white",
                        }}
                          className="w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold flex-shrink-0">
                          {d.name?.charAt(0) || "🚚"}
                        </div>
                        <div className="flex-1 min-w-0 text-left">
                          <div style={{ fontFamily: FS, fontWeight: 700, color: T.ink }} className="text-sm flex items-center gap-1">
                            {d.name}
                            {isMe && (
                              <span style={{ background: "#9333ea", color: "white", fontFamily: FS, fontWeight: 600 }}
                                className="text-[9px] px-1.5 py-0.5 rounded-full">
                                Та
                              </span>
                            )}
                          </div>
                          {d.job_title && (
                            <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px]">
                              {d.job_title}
                            </div>
                          )}
                        </div>
                        <div className="text-right">
                          <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase">Идэвхтэй</div>
                          <div style={{ fontFamily: FD, fontWeight: 700, color: activeCount > 0 ? T.warn : T.muted }} className="text-base tabular-nums">
                            {activeCount}
                          </div>
                        </div>
                      </button>
                    );
                  })}
                </div>
              )}
            </div>
          </div>
        </div>,
        document.body
      )}

      {/* Cancel modal — Сэтгэгдэл бичих */}
      {/* 🚚 Өөр driver-т хуваарилах modal */}
      {/* 📞 Залгах / Мессеж сонголт popup */}
      {phoneAction && createPortal(
        <div
          onClick={() => setPhoneAction(null)}
          style={{
            position: "fixed", inset: 0, zIndex: 10000,
            display: "flex", alignItems: "center", justifyContent: "center", padding: 16,
            background: "rgba(0,0,0,0.4)", backdropFilter: "blur(4px)",
          }}>
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: "white", borderRadius: 18, width: "100%", maxWidth: 320,
              overflow: "hidden", boxShadow: "0 24px 48px rgba(0,0,0,0.3)",
            }}>
            <div className="px-4 py-3 text-center" style={{ borderBottom: `1px solid ${T.border}` }}>
              <div style={{ fontFamily: FD, fontWeight: 700, color: T.ink }} className="text-lg tabular-nums">
                {phoneAction.phone}
              </div>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-0.5">
                Юу хийх вэ?
              </div>
            </div>
            <a href={`tel:${(phoneAction.phone || "").replace(/[^0-9+]/g, "")}`}
              onClick={() => setPhoneAction(null)}
              className="press-btn flex items-center gap-3 px-4 py-3.5 w-full"
              style={{ color: T.highlight, fontFamily: FS, fontWeight: 600, borderBottom: `1px solid ${T.border}`, textDecoration: "none" }}>
              <span style={{ background: "rgba(14,156,142,0.12)" }} className="w-9 h-9 rounded-full flex items-center justify-center text-lg">📞</span>
              <span className="text-sm">Залгах</span>
            </a>
            <a href={`sms:${(phoneAction.phone || "").replace(/[^0-9+]/g, "")}`}
              onClick={() => setPhoneAction(null)}
              className="press-btn flex items-center gap-3 px-4 py-3.5 w-full"
              style={{ color: "#0ea5e9", fontFamily: FS, fontWeight: 600, borderBottom: `1px solid ${T.border}`, textDecoration: "none" }}>
              <span style={{ background: "rgba(14,165,233,0.12)" }} className="w-9 h-9 rounded-full flex items-center justify-center text-lg">💬</span>
              <span className="text-sm">Мессеж илгээх</span>
            </a>
            <button
              onClick={() => setPhoneAction(null)}
              className="press-btn w-full px-4 py-3 text-center"
              style={{ color: T.muted, fontFamily: FS, fontWeight: 500 }}>
              Болих
            </button>
          </div>
        </div>,
        document.body
      )}

      {assignOrder && createPortal(
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 9999,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 8,
          background: "rgba(14, 156, 142, 0.15)", backdropFilter: "blur(8px)",
        }}
          onClick={() => setAssignOrder(null)}>
          <div style={{
            background: "rgba(255, 255, 255, 0.98)", backdropFilter: "blur(24px) saturate(180%)",
            border: "1px solid rgba(255, 255, 255, 0.8)", boxShadow: "0 24px 48px rgba(14, 156, 142, 0.3)",
            borderRadius: 16, width: "100%", maxWidth: 400, maxHeight: "80vh", overflow: "auto",
          }}
            onClick={(e) => e.stopPropagation()}>
            <div className="px-4 py-3" style={{ borderBottom: `1px solid ${T.border}` }}>
              <h3 style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-base flex items-center gap-2">
                🚚 Хүргэлт хуваарилах
              </h3>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-0.5">
                {assignOrder.customer_name || assignOrder.customer_phone} — {Number(assignOrder.total_amount).toLocaleString()}₮
              </div>
            </div>
            <div className="p-3 space-y-1.5">
              {drivers.length === 0 ? (
                <div style={{ color: T.muted, fontFamily: FS }} className="text-sm text-center py-4">
                  Хүргэгч олдсонгүй
                </div>
              ) : drivers.filter((d) => d.id !== profile.id).length === 0 ? (
                <div style={{ color: T.muted, fontFamily: FS }} className="text-sm text-center py-4">
                  Өөр хүргэгч олдсонгүй
                </div>
              ) : drivers.filter((d) => d.id !== profile.id).map((d) => (
                <button key={d.id}
                  onClick={async () => {
                    try {
                      const { error } = await supabase.from("biz_orders").update({
                        driver_id: d.id,
                        is_unknown: false,
                        status: "assigned",
                        assigned_at: new Date().toISOString(),
                        assigned_by: profile.id,
                      }).eq("id", assignOrder.id);
                      if (error) { alert("⚠ Алдаа: " + error.message); return; }
                      setOrders((prev) => prev.map((order) =>
                        order.id === assignOrder.id
                          ? { ...order, driver_id: d.id, is_unknown: false, status: "assigned" }
                          : order
                      ));
                      setAssignOrder(null);
                      alert(`✅ ${d.name}-д хуваарилагдлаа`);
                    } catch (e) { alert("Алдаа: " + e.message); }
                  }}
                  className="press-btn w-full px-3 py-2.5 rounded-lg text-left flex items-center gap-2"
                  style={{ background: T.surfaceAlt, color: T.ink, fontFamily: FS, fontWeight: 500 }}>
                  <span style={{ background: "#0ea5e9", color: "white" }}
                    className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold">
                    {(d.name || "?")[0]}
                  </span>
                  <span className="text-sm">{d.name || "Нэргүй"}</span>
                </button>
              ))}
            </div>
            <div className="px-3 pb-3">
              <button onClick={() => setAssignOrder(null)}
                className="press-btn w-full py-2 rounded-lg text-sm"
                style={{ background: T.surfaceAlt, color: T.muted, fontFamily: FS }}>
                Болих
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}

      {cancelOrder && createPortal(
        <div style={{
          position: "fixed", top: 0, left: 0, right: 0, bottom: 0, zIndex: 9999,
          display: "flex", alignItems: "center", justifyContent: "center", padding: 8,
          background: "rgba(14, 156, 142, 0.15)",
          backdropFilter: "blur(8px)",
        }}
          onClick={() => setCancelOrder(null)}>
          <div style={{
              background: "rgba(255, 255, 255, 0.98)",
              backdropFilter: "blur(24px) saturate(180%)",
              border: "1px solid rgba(255, 255, 255, 0.8)",
              boxShadow: "0 24px 48px rgba(14, 156, 142, 0.3)",
              borderRadius: 16, width: "100%", maxWidth: 400,
            }}
            onClick={(e) => e.stopPropagation()}>
            <div className="px-4 py-3" style={{ borderBottom: `1px solid ${T.border}` }}>
              <h3 style={{ fontFamily: FS, fontWeight: 600, color: T.ink }} className="text-base flex items-center gap-2">
                ✕ Хүргэх боломжгүй
              </h3>
              <div style={{ color: T.muted, fontFamily: FM }} className="text-[11px] mt-0.5">
                {cancelOrder.customer_name || cancelOrder.customer_phone}
              </div>
            </div>

            <div className="p-3 space-y-2">
              <div>
                <label style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
                  Шалтгаан *
                </label>
                <textarea
                  value={cancelNote}
                  onChange={(e) => setCancelNote(e.target.value)}
                  placeholder="Жишээ нь: Хаяг олдохгүй, Хариу авахгүй, Худалдан авагч цуцалсан..."
                  rows={4}
                  autoFocus
                  style={{ background: T.surfaceAlt, border: `1px solid ${T.border}`, color: T.ink, fontFamily: FS }}
                  className="w-full px-3 py-2 rounded-lg text-sm mt-1"
                />
              </div>
            </div>

            <div className="p-3 flex gap-2" style={{ borderTop: `1px solid ${T.border}` }}>
              <button onClick={() => setCancelOrder(null)}
                className="press-btn flex-1 py-2.5 rounded-xl text-sm font-semibold"
                style={{ background: T.surfaceAlt, color: T.ink, fontFamily: FS }}>
                Болих
              </button>
              <button
                disabled={!cancelNote.trim()}
                onClick={async () => {
                  try {
                    const existingNotes = cancelOrder.notes ? cancelOrder.notes + "\n\n" : "";
                    await supabase.from("biz_orders").update({
                      status: "cancelled",
                      cancelled_at: new Date().toISOString(),
                      cancelled_by: profile.id,
                      notes: existingNotes + `[Хүргэгч цуцалсан]: ${cancelNote.trim()}`,
                    }).eq("id", cancelOrder.id);
                    // 🆕 biz_calls-д cancelled дуудлага нэмэх → cycle хаагдана
                    if (cancelOrder.customer_phone) {
                      const { data: lastC } = await supabase.from("biz_calls")
                        .select("call_status").eq("phone", cancelOrder.customer_phone)
                        .order("created_at", { ascending: false }).limit(1).maybeSingle();
                      if (lastC?.call_status !== "cancelled") {
                        await supabase.from("biz_calls").insert({
                          phone: cancelOrder.customer_phone,
                          customer_name: cancelOrder.customer_name || null,
                          call_status: "cancelled",
                          fb_page_id: cancelOrder.fb_page_id || null,
                          created_at: new Date().toISOString(),
                        });
                      }
                    }
                    setCancelOrder(null);
                    setCancelNote("");
                    await loadAll();
                  } catch (e) { alert("Алдаа: " + e.message); }
                }}
                className="press-btn flex-1 py-2.5 rounded-xl text-sm font-semibold"
                style={{ background: T.err, color: "white", fontFamily: FS, opacity: cancelNote.trim() ? 1 : 0.5 }}>
                ✕ Цуцлах
              </button>
            </div>
          </div>
        </div>,
        document.body
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  MANAGER DASHBOARD
// ═══════════════════════════════════════════════════════════════════════════
function ManagerDashboard({ profile }) {
  const [view, setView] = useState(() => {
    try {
      return localStorage.getItem("orgoo-manager-view") || "dashboard";
    } catch { return "dashboard"; }
  });

  useEffect(() => {
    try { localStorage.setItem("orgoo-manager-view", view); } catch {}
  }, [view]);
  const [team, setTeam] = useState([]);
  const [sessions, setSessions] = useState([]);
  const [activeSessions, setActiveSessions] = useState({});
  const [approvals, setApprovals] = useState([]);
  const [sites, setSites] = useState([]);
  const [employeeSites, setEmployeeSites] = useState([]);
  const [departments, setDepartments] = useState([]);
  const [kpiDefs, setKpiDefs] = useState([]);
  const [kpiEntries, setKpiEntries] = useState([]);
  const [kpiInputDept, setKpiInputDept] = useState(null);
  const [tasks, setTasks] = useState([]);
  const [editingTask, setEditingTask] = useState(null);
  const [feedback, setFeedback] = useState(null);
  const [editingKpi, setEditingKpi] = useState(null); // KPI засах modal
  const [editingSession, setEditingSession] = useState(null);
  const [, setTick] = useState(0);

  useEffect(() => { const id = setInterval(() => setTick((t) => t+1), 1000); return () => clearInterval(id); }, []);
  useEffect(() => { if (!feedback) return; const t = setTimeout(() => setFeedback(null), 5000); return () => clearTimeout(t); }, [feedback]);

  const loadAll = async () => {
    const [me, sess, active, apps, st, es, dept, kpiD, kpiE, tsk] = await Promise.all([
      supabase.from("manager_employees").select("employee_id, profiles!manager_employees_employee_id_fkey(*)").eq("manager_id", profile.id),
      supabase.from("sessions").select("*").order("start_time", { ascending: false }).limit(200),
      supabase.from("active_sessions").select("*"),
      supabase.from("approvals").select("*").order("created_at", { ascending: false }),
      supabase.from("sites").select("*").order("name"),
      supabase.from("employee_sites").select("*"),
      supabase.from("departments").select("*").order("name"),
      supabase.from("kpi_definitions").select("*").eq("is_active", true).order("display_order"),
      supabase.from("kpi_entries").select("*").gte("entry_date", new Date(Date.now() - 180*24*60*60*1000).toISOString().slice(0,10)).order("entry_date", { ascending: false }),
      supabase.from("tasks").select("*").order("created_at", { ascending: false }),
    ]);
    if (me.data) setTeam(me.data.map((m) => m.profiles).filter(Boolean));
    if (sess.data) setSessions(sess.data);
    if (active.data) {
      const map = {};
      active.data.forEach((a) => { map[a.employee_id] = a; });
      setActiveSessions(map);
    }
    if (apps.data) setApprovals(apps.data);
    if (st.data) setSites(st.data);
    if (es.data) setEmployeeSites(es.data);
    if (dept.data) setDepartments(dept.data);
    if (kpiD.data) setKpiDefs(kpiD.data);
    if (kpiE.data) setKpiEntries(kpiE.data);
    if (tsk.data) setTasks(tsk.data);
  };

  const upsertTask = async (data) => {
    try {
      if (data.id) {
        const { error } = await supabase.from("tasks").update({
          title: data.title, description: data.description,
          status: data.status, priority: data.priority,
          assignee_id: data.assignee_id, due_date: data.due_date,
          completed_at: data.status === "done" ? new Date().toISOString() : null,
          updated_at: new Date().toISOString(),
        }).eq("id", data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("tasks").insert({
          department_id: data.department_id,
          title: data.title, description: data.description,
          status: data.status || "todo", priority: data.priority || "medium",
          assignee_id: data.assignee_id, due_date: data.due_date,
          created_by: profile.id,
        });
        if (error) throw error;
      }
      setEditingTask(null);
      setFeedback({ type: "success", msg: "Хадгаллаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  const deleteTask = async (id) => {
    try {
      const { error } = await supabase.from("tasks").delete().eq("id", id);
      if (error) throw error;
      setFeedback({ type: "success", msg: "Устгагдлаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  const updateTaskStatus = async (taskId, newStatus) => {
    try {
      const { error } = await supabase.from("tasks").update({
        status: newStatus,
        completed_at: newStatus === "done" ? new Date().toISOString() : null,
        updated_at: new Date().toISOString(),
      }).eq("id", taskId);
      if (error) throw error;
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  const upsertKpiEntries = async (deptId, date, entries) => {
    try {
      const rows = entries.map((e) => ({
        kpi_id: e.kpi_id,
        department_id: deptId,
        entry_date: date,
        value: e.value,
        note: e.note || null,
        entered_by: profile.id,
        updated_at: new Date().toISOString(),
      }));
      const { error } = await supabase.from("kpi_entries").upsert(rows, {
        onConflict: "kpi_id,entry_date",
      });
      if (error) throw error;
      setKpiInputDept(null);
      setFeedback({ type: "success", msg: "Хадгаллаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  // KPI CRUD (manager эрхтэй болсон)
  const upsertKpiDef = async (data) => {
    try {
      if (data.id) {
        const { error } = await supabase.from("kpi_definitions").update({
          name: data.name, unit: data.unit, category: data.category,
          display_order: data.display_order, is_active: data.is_active ?? true,
          target: data.target, target_period: data.target_period, target_source_kpi_id: data.target_source_kpi_id || null, target_percent: data.target_percent || null,
          kpi_type: data.kpi_type || 'input',
          formula: data.formula || null,
          decimals: data.decimals ?? 0,
        }).eq("id", data.id);
        if (error) throw error;
      } else {
        const { error } = await supabase.from("kpi_definitions").insert({
          department_id: data.department_id,
          name: data.name, unit: data.unit, category: data.category,
          display_order: data.display_order || 0,
          target: data.target, target_period: data.target_period || 'daily', target_source_kpi_id: data.target_source_kpi_id || null, target_percent: data.target_percent || null,
          kpi_type: data.kpi_type || 'input',
          formula: data.formula || null,
          decimals: data.decimals ?? 0,
        });
        if (error) throw error;
      }
      setEditingKpi(null);
      setFeedback({ type: "success", msg: "KPI хадгаллаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  const deleteKpiDef = async (id) => {
    if (!confirm("Энэ KPI-г устгах уу?")) return;
    try {
      const { error } = await supabase.from("kpi_definitions").delete().eq("id", id);
      if (error) throw error;
      setFeedback({ type: "success", msg: "KPI устгагдлаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  useEffect(() => { loadAll(); }, []);

  useEffect(() => {
    const ch = supabase.channel(`manager-${profile.id}`)
      .on("postgres_changes", { event: "*", schema: "public", table: "sessions" }, () => loadAll())
      .on("postgres_changes", { event: "*", schema: "public", table: "active_sessions" }, () => loadAll())
      .on("postgres_changes", { event: "*", schema: "public", table: "approvals" }, () => loadAll())
      .on("postgres_changes", { event: "*", schema: "public", table: "manager_employees", filter: `manager_id=eq.${profile.id}` }, () => loadAll())
      .subscribe();
    return () => { supabase.removeChannel(ch); };
  }, [profile.id]);

  const pendingApprovals = approvals.filter((a) => a.status === "pending");

  const resolveApproval = async (approval, decision) => {
    const updates = {
      status: decision, resolved_at: new Date().toISOString(), resolved_by: profile.id,
    };
    const { error: updErr } = await supabase.from("approvals").update(updates).eq("id", approval.id);
    if (updErr) { setFeedback({ type: "error", msg: updErr.message }); return; }

    if (decision === "approved" && approval.kind !== "early_leave") {
      const emp = team.find((e) => e.id === approval.employee_id);
      const cappedStart = capSessionStart(emp, new Date(approval.proposed_start).getTime());
      const cappedEnd = capSessionEnd(emp, new Date(approval.proposed_end).getTime());
      if (cappedEnd > cappedStart) {
        await supabase.from("sessions").insert({
          employee_id: approval.employee_id,
          start_time: new Date(cappedStart).toISOString(),
          end_time: new Date(cappedEnd).toISOString(),
          from_approval: approval.id,
        });
      }
    }
    await loadAll();
  };

  const editSession = async ({ id, start_time, end_time, site_id, edit_reason }) => {
    try {
      const { error } = await supabase.from("sessions").update({
        start_time, end_time, site_id,
        edited_at: new Date().toISOString(),
        edited_by: profile.id,
        edit_reason,
      }).eq("id", id);
      if (error) throw error;
      setEditingSession(null);
      setFeedback({ type: "success", msg: "Бүртгэл засагдлаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  const deleteSession = async (id) => {
    try {
      const { error } = await supabase.from("sessions").delete().eq("id", id);
      if (error) throw error;
      setEditingSession(null);
      setFeedback({ type: "success", msg: "Бүртгэл устгагдлаа" });
      await loadAll();
    } catch (e) { setFeedback({ type: "error", msg: e.message }); }
  };

  const teamTodayMs = useMemo(() => {
    const t = startOfDay();
    const teamIds = new Set(team.map((e) => e.id));
    const closed = sessions
      .filter((s) => teamIds.has(s.employee_id) && new Date(s.start_time).getTime() >= t)
      .reduce((a, s) => a + sessionDurationMs(new Date(s.start_time).getTime(), new Date(s.end_time).getTime()), 0);
    const live = Object.entries(activeSessions).reduce((a, [id, e]) => {
      if (!teamIds.has(id)) return a;
      const st = new Date(e.start_time).getTime();
      if (st < t) return a;
      const emp = team.find((x) => x.id === id);
      const capped = capSessionEnd(emp, Date.now());
      return a + Math.min(Math.max(0, capped - st), DAILY_HOUR_LIMIT_MS);
    }, 0);
    return closed + live;
  }, [sessions, activeSessions, team]);

  const activeCount = team.filter((e) => activeSessions[e.id]).length;
  const [sidebarOpen, setSidebarOpen] = useState(false);

  return (
    <div style={{ color: T.ink, fontFamily: FS, background: T.bg }} className="min-h-screen">
      <div className="flex min-h-screen">
        {/* SIDEBAR */}
        <aside style={{
          background: "rgba(255,255,255,0.6)",
          backdropFilter: "blur(20px) saturate(180%)",
          WebkitBackdropFilter: "blur(20px) saturate(180%)",
          borderRight: `1px solid ${T.border}`,
          width: 240,
        }} className={`fixed lg:sticky top-0 left-0 h-screen z-40 flex flex-col transition-transform ${sidebarOpen ? "translate-x-0" : "-translate-x-full lg:translate-x-0"}`}>

          <div className="px-4 py-4 border-b" style={{ borderColor: T.border }}>
            <div className="flex items-center gap-2.5">
              <div style={{ background: "linear-gradient(135deg, #3FE0C6, #0E9C8E)", color: "white" }} className="w-8 h-8 rounded-md flex items-center justify-center">
                <ShieldCheck size={14} />
              </div>
              <div className="flex-1">
                <div style={{ fontFamily: FS, fontWeight: 600, letterSpacing: "-0.02em" }} className="text-base leading-none">
                  CoreLink<span style={{ color: T.highlight }}>.</span>
                </div>
                <div style={{ color: T.muted, fontFamily: FS }} className="text-[10px] uppercase tracking-wider mt-0.5">
                  Ахлагч
                </div>
              </div>
              <button onClick={() => setSidebarOpen(false)} className="lg:hidden" style={{ color: T.muted }}>
                <X size={16} />
              </button>
            </div>
          </div>

          <nav className="flex-1 overflow-y-auto px-2 py-3">
            <SidebarSection label="Хяналт" icon={Eye} defaultOpen>
              <SidebarTab active={view === "team"} onClick={() => { setView("team"); setSidebarOpen(false); }} icon={Users}>Баг</SidebarTab>
              <SidebarTab active={view === "livemap"} onClick={() => { setView("livemap"); setSidebarOpen(false); }} icon={MapPin}>Газрын зураг</SidebarTab>
              <SidebarTab active={view === "dashboard"} onClick={() => { setView("dashboard"); setSidebarOpen(false); }} icon={BarChart3}>Дашборд</SidebarTab>
              <SidebarTab active={view === "tasks"} onClick={() => { setView("tasks"); setSidebarOpen(false); }} icon={ClipboardCheck}>Даалгавар</SidebarTab>
            </SidebarSection>

            <SidebarSection label="Хүсэлтүүд" icon={Inbox}>
              <SidebarTab active={view === "approvals"} onClick={() => { setView("approvals"); setSidebarOpen(false); }} icon={Inbox} badge={pendingApprovals.length}>Хүсэлт</SidebarTab>
              <SidebarTab active={view === "ledger"} onClick={() => { setView("ledger"); setSidebarOpen(false); }} icon={Calendar}>Тэмдэглэл</SidebarTab>
            </SidebarSection>
          </nav>

          <div className="border-t px-2 py-2" style={{ borderColor: T.border }}>
            <div className="flex items-center gap-2 px-2 py-2 rounded-md hover:bg-gray-50">
              <div style={{ background: "linear-gradient(135deg, #3FE0C6, #0E9C8E)", color: "white" }} className="w-8 h-8 rounded-full flex items-center justify-center text-xs font-semibold">
                {profile.name?.[0]}
              </div>
              <div className="flex-1 min-w-0">
                <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-xs truncate">
                  {profile.name}
                </div>
                <div style={{ color: T.muted, fontFamily: FS }} className="text-[10px] uppercase tracking-wider">
                  {team.length} ажилтан
                </div>
              </div>
              <DarkModeToggle />
              <button onClick={() => supabase.auth.signOut()} style={{ color: T.muted }}
                className="press-btn p-1.5 rounded hover:bg-gray-100">
                <LogOut size={14} />
              </button>
            </div>
          </div>
        </aside>

        {sidebarOpen && (
          <div onClick={() => setSidebarOpen(false)}
               className="fixed inset-0 bg-black/30 z-30 lg:hidden" />
        )}

        {/* MAIN */}
        <main className="flex-1 min-w-0">
          <div className="lg:hidden flex items-center gap-3 px-4 py-3 border-b sticky top-0 z-20" style={{ background: "rgba(255,255,255,0.7)", backdropFilter: "blur(20px)", WebkitBackdropFilter: "blur(20px)", borderColor: T.border }}>
            <button onClick={() => setSidebarOpen(true)} style={{ color: T.ink }}>
              <Menu size={20} />
            </button>
            <RippleMark size={22} variant="grad" />
            <div style={{ fontFamily: FS, fontWeight: 600 }} className="text-sm">CoreLink<span style={{ color: T.highlight }}>.</span></div>
          </div>

          <div className="max-w-screen-2xl mx-auto px-4 sm:px-6 lg:px-8 py-6 sm:py-8">
            <div className="mb-6 slide-up">
              <h1 style={{ fontFamily: FS, fontWeight: 600, letterSpacing: "-0.02em" }} className="text-2xl mb-1">
                {view === "team" && "Багийн гишүүд"}
                {view === "livemap" && "Газрын зураг"}
                {view === "dashboard" && "Дашборд"}
                {view === "tasks" && "Даалгавар"}
                {view === "approvals" && "Хүсэлт"}
                {view === "ledger" && "Тэмдэглэл"}
              </h1>
              <p style={{ color: T.muted }} className="text-sm">
                {view === "team" && `${team.length} ажилтан · ${activeCount} ажиллаж байна`}
                {view === "livemap" && `Багийн ${activeCount} ажилтан газрын зураг дээр`}
                {view === "dashboard" && "KPI мониторинг"}
                {view === "tasks" && "Багийн даалгавар"}
                {view === "approvals" && `${pendingApprovals.length} шалгагдаагүй`}
                {view === "ledger" && "Цаг бүртгэлийн түүх"}
              </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mb-6 slide-up-delay-1">
              <BigStat label="Ажиллаж буй" value={activeCount} accent={activeCount > 0} icon={Play} iconColor="success" />
              <BigStat label="Өнөөдөр" value={fmtHours(teamTodayMs)} suffix="цаг" icon={Clock} iconColor="warn" />
              <BigStat label="Ажилтан" value={team.length} icon={Users} iconColor="pink" />
            </div>

        {feedback && (
          <div className="mb-4"><FeedbackBox type={feedback.type}>{feedback.msg}</FeedbackBox></div>
        )}

        {view === "team" && (
          <ManagerTeamReadOnly
            team={team} sessions={sessions} activeSessions={activeSessions}
            sites={sites} employeeSites={employeeSites} />
        )}
        {view === "livemap" && (
          <LiveMap
            employees={team}
            activeSessions={activeSessions}
            sites={sites}
            sessions={sessions}
            departments={departments}
            scope="team"
          />
        )}

        {view === "dashboard" && (
          <KPIDashboardView
            departments={departments}
            kpiDefs={kpiDefs}
            kpiEntries={kpiEntries}
            isAdmin={true}
            currentUserId={profile.id}
            onAddKpi={() => setEditingKpi("add")}
            onEditKpi={(k) => setEditingKpi(k)}
            onDeleteKpi={deleteKpiDef}
            onOpenInputForm={(deptId) => setKpiInputDept(deptId)}
          />
        )}

        {view === "tasks" && (
          <TasksView
            tasks={tasks}
            departments={departments}
            employees={team}
            currentUserId={profile.id}
            isAdmin={false}
            onAdd={() => setEditingTask("add")}
            onEdit={(t) => setEditingTask(t)}
            onDelete={deleteTask}
            onUpdateStatus={updateTaskStatus}
          />
        )}
        {view === "ledger" && (
          <LedgerView
            sessions={sessions.filter((s) => team.some((t) => t.id === s.employee_id))}
            employees={team} sites={sites}
            canEdit={true}
            onEditSession={(s) => setEditingSession(s)} />
        )}
        {view === "approvals" && (
          <ApprovalsView
            approvals={approvals.filter((a) => team.some((t) => t.id === a.employee_id))}
            employees={team} onResolve={resolveApproval} />
        )}

            <Footer count={sessions.length} />
          </div>
        </main>
      </div>

      {editingSession && (
        <SessionEditModal
          session={editingSession}
          employee={team.find((e) => e.id === editingSession.employee_id)}
          sites={sites}
          onSave={editSession}
          onDelete={deleteSession}
          onClose={() => setEditingSession(null)} />
      )}

      {editingKpi && (
        <KpiDefFormModal
          mode={editingKpi === "add" ? "add" : "edit"}
          kpi={editingKpi === "add" ? null : editingKpi}
          departments={departments}
          allKpis={kpiDefs}
          onSave={upsertKpiDef}
          onClose={() => setEditingKpi(null)} />
      )}

      {kpiInputDept && (
        <KpiEntryFormModal
          department={departments.find(d => d.id === kpiInputDept)}
          kpiDefs={kpiDefs.filter(k => k.department_id === kpiInputDept)}
          existingEntries={kpiEntries}
          onSave={upsertKpiEntries}
          onClose={() => setKpiInputDept(null)} />
      )}

      {editingTask && (
        <TaskFormModal
          mode={editingTask === "add" ? "add" : "edit"}
          task={editingTask === "add" ? null : editingTask}
          departments={departments}
          employees={team}
          onSave={upsertTask}
          onClose={() => setEditingTask(null)} />
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  MANAGER TEAM (read-only — manager can view but not clock employees in/out)
// ═══════════════════════════════════════════════════════════════════════════
function ManagerTeamReadOnly({ team, sessions, activeSessions, sites = [], employeeSites = [] }) {
  if (team.length === 0) {
    return (
      <div style={{ borderColor: T.border, background: T.surface }}
           className="border-2 border-dashed rounded-2xl py-16 px-6 text-center">
        <Users size={32} style={{ color: T.muted }} strokeWidth={1.5} className="mx-auto mb-4" />
        <h3 style={{ fontFamily: FD, fontWeight: 500 }} className="text-2xl mb-2">Багт ажилтан алга</h3>
        <p style={{ color: T.muted }} className="text-sm">
          Админ танд ажилтан оноогоогүй байна. Админд хандана уу.
        </p>
      </div>
    );
  }

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
      {team.map((emp) => {
        const active = activeSessions[emp.id];
        const isActive = !!active;
        const liveMs = isActive ? capSessionEnd(emp, Date.now()) - new Date(active.start_time).getTime() : 0;
        const empSessions = sessions.filter((s) => s.employee_id === emp.id);
        const todayMs = empSessions.filter((s) => new Date(s.start_time).getTime() >= startOfDay())
          .reduce((a, s) => a + (new Date(s.end_time).getTime() - new Date(s.start_time).getTime()), 0)
          + (isActive ? Math.max(0, liveMs) : 0);
        const weekMs = empSessions.filter((s) => new Date(s.start_time).getTime() >= startOfWeek())
          .reduce((a, s) => a + (new Date(s.end_time).getTime() - new Date(s.start_time).getTime()), 0)
          + (isActive ? Math.max(0, liveMs) : 0);
        const activeSite = isActive && active.site_id ? sites.find((s) => s.id === active.site_id) : null;
        const myAssignedSites = employeeSites.filter((es) => es.employee_id === emp.id);

        return (
          <article key={emp.id}
            className={`${isActive ? "glass-strong pulse-halo" : "glass lift"} rounded-3xl p-5 slide-up`}>
            <div className="flex items-start justify-between mb-4">
              <div className="min-w-0 flex-1">
                <div className="flex items-center gap-2 mb-1.5">
                  <span style={{
                    background: isActive ? T.ok : T.mutedSoft,
                    boxShadow: isActive ? `0 0 0 4px rgba(16, 185, 129, 0.2)` : "none",
                  }}
                        className={`inline-block w-1.5 h-1.5 rounded-full ${isActive ? "pulse-dot" : ""}`} />
                  <span style={{ fontFamily: FM, color: isActive ? T.ok : T.muted }}
                        className="text-[9px] uppercase tracking-[0.25em] font-medium">
                    {isActive ? "Ажиллаж байна" : "Цагтай биш"}
                  </span>
                </div>
                <h3 style={{ fontFamily: FD, fontWeight: 500, letterSpacing: "-0.02em" }} className="text-xl truncate">{emp.name}</h3>
                <p style={{ color: T.muted }} className="text-xs mt-0.5 truncate">{emp.job_title}</p>
              </div>
            </div>

            <div className="text-[10px] flex flex-wrap gap-x-3 gap-y-1 mb-4" style={{ fontFamily: FM, color: T.muted }}>
              <span className="flex items-center gap-1">
                <MapPin size={10} />
                {myAssignedSites.length > 0 ? `${myAssignedSites.length} байр` : hasSite(emp) ? `${emp.site_radius}m` : "байргүй"}
              </span>
              <span className="flex items-center gap-1">
                <Clock size={10} />
                {emp.schedule_days?.length ? `${emp.schedule_start}–${emp.schedule_end}` : "хязгааргүй"}
              </span>
              {activeSite && (
                <span style={{ color: T.highlight }} className="flex items-center gap-1">
                  · {activeSite.name}
                </span>
              )}
            </div>

            <div className="rounded-xl px-4 py-3 mb-3" style={{ background: T.surfaceAlt }}>
              <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-[0.25em] mb-1">
                {isActive ? "Одоо ажиллаж байна" : "Өнөөдөр"}
              </div>
              <div style={{ fontFamily: FM, fontWeight: 500, color: isActive ? T.highlight : T.ink }} className="text-3xl tabular-nums">
                {isActive ? fmtClock(liveMs) : `${fmtHours(todayMs)}`}
                {!isActive && <span style={{ fontSize: "0.45em", color: T.muted, marginLeft: 6 }}>цаг</span>}
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div style={{ background: T.surfaceAlt }} className="rounded-lg px-3 py-2">
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider mb-0.5">7 хоног</div>
                <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-sm tabular-nums">{fmtHours(weekMs)} ц</div>
              </div>
              <div style={{ background: T.surfaceAlt }} className="rounded-lg px-3 py-2">
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider mb-0.5">Сэшн</div>
                <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-sm tabular-nums">{empSessions.length}</div>
              </div>
            </div>
          </article>
        );
      })}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  EARLY LEAVE MODAL
// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
//  UNVERIFIED CLOCK-OUT MODAL (when employee outside geofence)
// ═══════════════════════════════════════════════════════════════════════════
function UnverifiedClockOutModal({ distance, siteName, onClose, onSubmit }) {
  const [reason, setReason] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async () => {
    setErr("");
    if (!reason.trim()) return setErr("Шалтгаан бичнэ үү");
    if (reason.trim().length < 5) return setErr("Илүү тодорхой шалтгаан бичнэ үү");
    setBusy(true);
    await onSubmit(reason.trim());
    setBusy(false);
  };

  return (
    <Modal onClose={onClose} title="Байршил гадуур" maxW="max-w-md">
      <div className="space-y-4">
        <div style={{ background: T.warnSoft, borderColor: T.warn }}
             className="border rounded-xl p-4">
          <div className="flex items-start gap-3">
            <AlertCircle size={18} style={{ color: T.warn }} className="shrink-0 mt-0.5" />
            <div className="flex-1">
              <div style={{ fontFamily: FM, fontWeight: 500, color: T.warn }} className="text-sm mb-1">
                {siteName}-аас {fmtDist(distance)} зайтай
              </div>
              <p style={{ color: T.muted }} className="text-xs leading-relaxed">
                Та ажлын байрнаас гадуур байгаа учраас цаг автомат бүртгэгдэхгүй. Хэрэв та үнэхээр ажил тарж байгаа бол шалтгаан бичиж явуулна уу. Энэ нь ахлагч/админ руу мэдэгдэж очино, тэд баталгаажуулна.
              </p>
            </div>
          </div>
        </div>

        <Field label="Яагаад байршлаас гадуур байгаа вэ?" required>
          <textarea value={reason} onChange={(e) => setReason(e.target.value)} rows={3}
            placeholder="Жишээ: Гадагшаа уулзалтад гарсан, ачаа аваачихаар явсан, зочинтой гэх мэт"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black resize-none" />
        </Field>

        <p style={{ color: T.muted }} className="text-[11px] leading-relaxed">
          ⚠️ Цаг тань <strong>"баталгаажуулагдсан биш"</strong> гэсэн тэмдэгтэйгээр бүртгэгдэнэ. Ахлагч/админ шалгасны дараа баталгаажна.
        </p>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose} style={{ fontFamily: FS, color: "#1e1b4b" }}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium">Цуцлах</button>
          <button onClick={submit} disabled={busy}
            style={{ background: T.warn, color: T.surface, fontFamily: FS }}
            className="flex-1 py-3 rounded-xl text-sm font-medium hover:opacity-90 disabled:opacity-50 flex items-center justify-center gap-2">
            {busy ? <Loader2 size={13} className="animate-spin" /> : <Send size={13} />} Цаг буулгах
          </button>
        </div>
      </div>
    </Modal>
  );
}

function EarlyLeaveModal({ profile, myActive, onClose, onSubmit }) {
  const [endTime, setEndTime] = useState(() => {
    const d = new Date();
    d.setHours(d.getHours() + 1, 0, 0, 0); // 1 цагийн дараа default
    return d.toTimeString().slice(0, 5);
  });
  const [reason, setReason] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async () => {
    setErr("");
    if (!reason.trim()) return setErr("Шалтгаан бичнэ үү");
    const today = new Date();
    const isoDate = today.toISOString().slice(0, 10);
    const endTs = new Date(`${isoDate}T${endTime}:00`).getTime();
    if (isNaN(endTs)) return setErr("Цаг буруу");

    // Active session-ний эхлэлээс хойш байх ёстой
    const startTs = myActive ? new Date(myActive.start_time).getTime() : Date.now();
    if (endTs <= startTs) return setErr("Дуусах цаг ажил эхлэхээс хойш байх ёстой");

    setBusy(true);
    await onSubmit({
      start: startTs,
      end: endTs,
      reason: reason.trim(),
      kind: "early_leave",
    });
    setBusy(false);
  };

  return (
    <Modal onClose={onClose} title="Эрт явах хүсэлт" maxW="max-w-md">
      <div className="space-y-4">
        <p style={{ color: T.muted }} className="text-xs leading-relaxed">
          Хуваарийн өмнө явмаар бол энэ хүсэлтийг ахалсан ахлагч (эсвэл админ) зөвшөөрөх хэрэгтэй. Зөвшөөрөгдсөний дараа байршил харгалзахгүйгээр цаг буух боломжтой болно.
        </p>

        <Field label="Хэдэн цагт явах вэ?" required>
          <input type="time" value={endTime} onChange={(e) => setEndTime(e.target.value)}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black" />
        </Field>

        <Field label="Шалтгаан / тайлбар" required>
          <textarea value={reason} onChange={(e) => setReason(e.target.value)} rows={3}
            placeholder="Жишээ: Эмнэлэгт үзлэгтэй, гэр бүлийн ажил, хувийн асуудал гэх мэт"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black resize-none" />
        </Field>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose} style={{ fontFamily: FS, color: "#1e1b4b" }}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium">Цуцлах</button>
          <button onClick={submit} disabled={busy}
            style={{ fontFamily: FS, color: "white" }}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2">
            {busy ? <Loader2 size={13} className="animate-spin" /> : <Send size={13} />} Илгээх
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  SESSION EDIT MODAL (admin & manager — to fix wrong time entries)
// ═══════════════════════════════════════════════════════════════════════════
function SessionEditModal({ session, employee, sites = [], onSave, onDelete, onClose }) {
  const startMs = new Date(session.start_time).getTime();
  const endMs = new Date(session.end_time).getTime();
  const dateStr = new Date(startMs).toLocaleDateString("en-CA"); // YYYY-MM-DD

  const [date, setDate] = useState(dateStr);
  const [start, setStart] = useState(new Date(startMs).toTimeString().slice(0, 5));
  const [end, setEnd] = useState(new Date(endMs).toTimeString().slice(0, 5));
  const [siteId, setSiteId] = useState(session.site_id || "");
  const [reason, setReason] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [confirmDel, setConfirmDel] = useState(false);

  const submit = async () => {
    setErr("");
    if (!reason.trim()) return setErr("Засварын шалтгаан бичнэ үү");
    const startTs = new Date(`${date}T${start}:00`).getTime();
    const endTs = new Date(`${date}T${end}:00`).getTime();
    if (isNaN(startTs) || isNaN(endTs)) return setErr("Огноо/цаг буруу");
    if (endTs <= startTs) return setErr("Дуусах цаг эхлэхээс хойш байх ёстой");
    setBusy(true);
    await onSave({
      id: session.id,
      start_time: new Date(startTs).toISOString(),
      end_time: new Date(endTs).toISOString(),
      site_id: siteId || null,
      edit_reason: reason.trim(),
    });
    setBusy(false);
  };

  if (confirmDel) {
    return (
      <Modal onClose={() => setConfirmDel(false)} title="Бүртгэл устгах уу?" maxW="max-w-sm">
        <p style={{ color: T.muted }} className="text-sm mb-5">
          <span style={{ color: T.ink, fontWeight: 500 }}>{employee?.name}</span>-ийн{" "}
          <span style={{ color: T.ink, fontWeight: 500 }}>{fmtDate(startMs)} {fmtTime(startMs)}–{fmtTime(endMs)}</span>{" "}
          бүртгэл устгагдана. Энэ үйлдлийг буцаах боломжгүй.
        </p>
        <div className="flex gap-3">
          <button onClick={() => setConfirmDel(false)} style={{ fontFamily: FS, color: "#1e1b4b" }}
            className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-sm">Цуцлах</button>
          <button onClick={() => onDelete(session.id)}
            style={{ background: T.err, color: T.surface, fontFamily: FS }}
            className="flex-1 py-2.5 rounded-xl text-sm font-medium hover:opacity-90 flex items-center justify-center gap-1.5">
            <Trash2 size={12} /> Устгах
          </button>
        </div>
      </Modal>
    );
  }

  return (
    <Modal onClose={onClose} title="Цагийн бүртгэл засах" maxW="max-w-md">
      <div className="space-y-4">
        <div style={{ background: T.surfaceAlt }} className="rounded-xl p-3">
          <div style={{ fontFamily: FM, color: T.muted }} className="text-[10px] uppercase tracking-[0.2em] mb-1">
            Ажилтан
          </div>
          <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-sm">{employee?.name || "—"}</div>
        </div>

        <Field label="Огноо" required>
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black" />
        </Field>

        <div className="grid grid-cols-2 gap-3">
          <Field label="Эхэлсэн" required>
            <input type="time" value={start} onChange={(e) => setStart(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black" />
          </Field>
          <Field label="Дууссан" required>
            <input type="time" value={end} onChange={(e) => setEnd(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black" />
          </Field>
        </div>

        {sites.length > 0 && (
          <Field label="Ажлын байр">
            <select value={siteId} onChange={(e) => setSiteId(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black">
              <option value="">— Сонгоогүй —</option>
              {sites.map((s) => (
                <option key={s.id} value={s.id}>{s.name}</option>
              ))}
            </select>
          </Field>
        )}

        <Field label="Засварын шалтгаан" required>
          <textarea value={reason} onChange={(e) => setReason(e.target.value)} rows={2}
            placeholder="Жишээ: Ажилтан өглөө цаг буруу бүртгүүлсэн"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black resize-none" />
        </Field>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={() => setConfirmDel(true)}
            style={{ borderColor: T.err, color: T.err, fontFamily: FS }}
            className="px-4 py-3 rounded-xl border text-sm font-medium hover:bg-red-50 flex items-center gap-1.5">
            <Trash2 size={12} />
          </button>
          <button onClick={onClose} style={{ fontFamily: FS, color: "#1e1b4b" }}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium">Цуцлах</button>
          <button onClick={submit} disabled={busy}
            style={{ fontFamily: FS, color: "white" }}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2">
            {busy && <Loader2 size={13} className="animate-spin" />}
            Хадгалах
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  SALARY VIEW (employee — own salary)
// ═══════════════════════════════════════════════════════════════════════════
function SalaryView({ sessions, profile }) {
  const [filterType, setFilterType] = useState("thisMonth"); // thisMonth | lastMonth | custom
  const [customStart, setCustomStart] = useState(() => {
    const d = new Date(); d.setDate(1);
    return d.toISOString().slice(0, 10);
  });
  const [customEnd, setCustomEnd] = useState(new Date().toISOString().slice(0, 10));

  const filterRange = useMemo(() => {
    const now = new Date();
    if (filterType === "thisMonth") {
      const start = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
      const end = new Date(now.getFullYear(), now.getMonth() + 1, 1).getTime();
      return { start, end };
    }
    if (filterType === "lastMonth") {
      const start = new Date(now.getFullYear(), now.getMonth() - 1, 1).getTime();
      const end = new Date(now.getFullYear(), now.getMonth(), 1).getTime();
      return { start, end };
    }
    const s = new Date(`${customStart}T00:00:00`).getTime();
    const e = new Date(`${customEnd}T23:59:59`).getTime();
    return { start: s, end: e };
  }, [filterType, customStart, customEnd]);

  const filtered = useMemo(() => {
    return sessions.filter((s) => {
      const t = new Date(s.start_time).getTime();
      return t >= filterRange.start && t < filterRange.end;
    });
  }, [sessions, filterRange]);

  // Өдрүүдээр бүлэглэх
  const byDay = useMemo(() => {
    const map = {};
    filtered.forEach((s) => {
      const startMs = new Date(s.start_time).getTime();
      const endMs = new Date(s.end_time).getTime();
      const dayKey = new Date(startMs).toLocaleDateString("en-CA"); // YYYY-MM-DD
      if (!map[dayKey]) map[dayKey] = { dayKey, sessions: [], totalMs: 0 };
      const ms = sessionDurationMs(startMs, endMs);
      map[dayKey].sessions.push({ s, ms });
      map[dayKey].totalMs += ms;
    });
    // Өдөр бүрд 9 цагийн дээд лимит дахин шалгана
    Object.values(map).forEach((d) => {
      d.totalMs = Math.min(d.totalMs, DAILY_HOUR_LIMIT_MS);
    });
    return Object.values(map).sort((a, b) => b.dayKey.localeCompare(a.dayKey));
  }, [filtered]);

  const totals = useMemo(() => {
    const totalMs = byDay.reduce((a, d) => a + d.totalMs, 0);
    const rate = profile.hourly_rate || 0;
    const totalPay = calcPay(totalMs, rate);
    return { totalMs, totalPay, days: byDay.length };
  }, [byDay, profile]);

  const filterLabel = filterType === "thisMonth" ? "Энэ сар"
    : filterType === "lastMonth" ? "Өнгөрсөн сар"
    : `${customStart} – ${customEnd}`;

  const noRate = !profile.hourly_rate || profile.hourly_rate === 0;

  return (
    <div className="space-y-4 fade-in">
      {/* Big totals card */}
      <div className="glass-strong rounded-3xl p-5 sm:p-6 slide-up">
        <div className="flex items-center justify-between gap-2 mb-3 flex-wrap">
          <div className="flex items-center gap-2">
            <FileSpreadsheet size={14} style={{ color: T.highlight }} />
            <span style={{ fontFamily: FM, color: T.muted }} className="text-[10px] uppercase tracking-[0.25em] font-medium">
              {filterLabel}
            </span>
          </div>
          {!noRate && totals.totalMs > 0 && (
            <button onClick={async () => {
              try {
                await generateSalaryPDF({
                  employee: profile,
                  sessions: sessions,
                  periodStart: filterRange.start,
                  periodEnd: filterRange.end,
                  periodLabel: filterLabel,
                });
              } catch (e) {
                console.error(e);
                alert("PDF үүсгэхэд алдаа гарлаа: " + e.message);
              }
            }}
              className="glow-primary press-btn px-4 py-2 rounded-full text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5 font-medium"
              style={{ fontFamily: FM }}>
              <FileSpreadsheet size={12} /> PDF татах
            </button>
          )}
        </div>

        {noRate ? (
          <div style={{ background: T.warnSoft, color: T.warn }} className="px-3 py-2.5 rounded-lg text-xs">
            Танд цагийн хөлс тогтоогоогүй байна. Админд хандана уу.
          </div>
        ) : (
          <>
            <div className="grid grid-cols-2 gap-4">
              <div>
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-[0.25em] mb-1">Нийт цаг</div>
                <div style={{ fontFamily: FD, fontWeight: 500, letterSpacing: "-0.03em" }} className="text-3xl sm:text-4xl tabular-nums">
                  {fmtHours(totals.totalMs)}
                  <span style={{ color: T.muted, fontSize: "0.5em", marginLeft: 6, fontFamily: FM }}>цаг</span>
                </div>
              </div>
              <div>
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-[0.25em] mb-1">Цалин</div>
                <div style={{ fontFamily: FD, fontWeight: 500, color: T.highlight, letterSpacing: "-0.03em" }} className="text-3xl sm:text-4xl tabular-nums">
                  ₮{Math.round(totals.totalPay).toLocaleString()}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3 mt-4 pt-4 border-t" style={{ borderColor: T.borderSoft }}>
              <div>
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider mb-0.5">Ажилласан өдөр</div>
                <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-base tabular-nums">{totals.days}</div>
              </div>
              <div>
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider mb-0.5">Цагийн хөлс</div>
                <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-base tabular-nums">₮{(profile.hourly_rate || 0).toLocaleString()}/ц</div>
              </div>
            </div>
          </>
        )}
      </div>

      {/* Period filter */}
      <div className="glass rounded-2xl p-4 slide-up-delay-1">
        <div style={{ fontFamily: FM, color: T.muted }} className="text-[10px] uppercase tracking-[0.2em] mb-2">
          Хугацаа
        </div>
        <div className="flex flex-wrap gap-1.5 mb-3">
          {[
            { id: "thisMonth", label: "Энэ сар" },
            { id: "lastMonth", label: "Өнгөрсөн сар" },
            { id: "custom", label: "Гар сонголт" },
          ].map((opt) => (
            <button key={opt.id} onClick={() => setFilterType(opt.id)}
              className={`${filterType === opt.id ? "tab-active" : "tab-inactive glass-soft"} press-btn px-3 py-1 text-[10px] uppercase tracking-[0.2em] border rounded-full`}
              style={{ fontFamily: FM, borderColor: filterType === opt.id ? "transparent" : T.borderSoft }}>
              {opt.label}
            </button>
          ))}
        </div>
        {filterType === "custom" && (
          <div className="grid grid-cols-2 gap-3">
            <div>
              <Label>Эхлэх</Label>
              <input type="date" value={customStart} onChange={(e) => setCustomStart(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="w-full px-3 py-2 rounded-lg border text-sm outline-none focus:border-black" />
            </div>
            <div>
              <Label>Дуусах</Label>
              <input type="date" value={customEnd} onChange={(e) => setCustomEnd(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="w-full px-3 py-2 rounded-lg border text-sm outline-none focus:border-black" />
            </div>
          </div>
        )}
      </div>

      {/* Daily breakdown */}
      <div className="glass rounded-3xl overflow-hidden slide-up-delay-2">
        <div className="px-5 py-4 border-b" style={{ borderColor: T.borderSoft }}>
          <h3 style={{ fontFamily: FD, fontWeight: 500 }} className="text-lg">Өдрөөр</h3>
          <p style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-[0.2em] mt-0.5">
            {byDay.length} өдөр
          </p>
        </div>
        {byDay.length === 0 ? (
          <div className="px-6 py-12 text-center" style={{ color: T.muted }}>
            <p className="text-sm">Сонгосон хугацаанд бүртгэл алга</p>
          </div>
        ) : (
          <ul>
            {byDay.map((d, i) => {
              const dayDate = new Date(d.dayKey + "T00:00:00");
              const dayPay = calcPay(d.totalMs, profile.hourly_rate || 0);
              const isCapped = d.sessions.reduce((a, x) => a + (new Date(x.s.end_time).getTime() - new Date(x.s.start_time).getTime()), 0) > DAILY_HOUR_LIMIT_MS;
              return (
                <li key={d.dayKey} className="px-5 py-3.5 flex items-center gap-4"
                    style={{ borderTop: i === 0 ? "none" : `1px solid ${T.borderSoft}` }}>
                  <div style={{ fontFamily: FM, color: T.muted }} className="text-[10px] uppercase tracking-wider w-20 shrink-0">
                    {dayDate.toLocaleDateString("mn-MN", { month: "short", day: "numeric", weekday: "short" })}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-sm tabular-nums">
                      {fmtHours(d.totalMs)} цаг
                      {isCapped && <span style={{ color: T.warn, fontSize: "0.75em", marginLeft: 6 }}>· 9ц лимит</span>}
                    </div>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] mt-0.5">
                      {d.sessions.length} сэшн
                    </div>
                  </div>
                  <div className="text-right">
                    <div style={{ fontFamily: FM, fontWeight: 500, color: T.highlight }} className="text-sm tabular-nums">
                      ₮{Math.round(dayPay).toLocaleString()}
                    </div>
                  </div>
                </li>
              );
            })}
          </ul>
        )}
      </div>

      <p style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-[0.2em] text-center pt-2">
        Тэмдэглэл: Өдөрт 9 цагийн дээд хязгаартай · ирсэн цагаас тоологдоно
      </p>
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  DEPARTMENTS VIEW
// ═══════════════════════════════════════════════════════════════════════════
function DepartmentsView({ departments, employees, managers, onEdit, onDelete, onAdd }) {
  const [confirmDel, setConfirmDel] = useState(null);

  if (departments.length === 0) {
    return (
      <div className="glass rounded-3xl py-16 px-6 text-center scale-up">
        <Users size={32} style={{ color: T.muted }} strokeWidth={1.5} className="mx-auto mb-4" />
        <h3 style={{ fontFamily: FD, fontWeight: 500 }} className="text-2xl mb-2">Хэлтэс алга</h3>
        <p style={{ color: T.muted }} className="text-sm mb-5 max-w-sm mx-auto">
          Эхний хэлтсээ үүсгээд ажилтнуудыг зохион байгуулна уу. Хэлтэст ахлагч оноох боломжтой.
        </p>
        <button onClick={onAdd}
          className="glow-primary press-btn px-5 py-2.5 rounded-full text-[11px] uppercase tracking-[0.25em] inline-flex items-center gap-2">
          <Plus size={13} strokeWidth={2.5} /> Эхний хэлтэс нэмэх
        </button>
      </div>
    );
  }

  return (
    <>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 fade-in">
        {departments.map((dept, i) => {
          const manager = dept.manager_id ? managers.find((m) => m.id === dept.manager_id) : null;
          const empCount = employees.filter((e) => e.department_id === dept.id).length;
          const sampleEmps = employees.filter((e) => e.department_id === dept.id).slice(0, 5);

          return (
            <article key={dept.id}
              className={`glass lift rounded-3xl p-5 ${i < 4 ? `slide-up-delay-${i + 1}` : "slide-up"}`}>
              <div className="flex items-start justify-between mb-3">
                <div className="min-w-0 flex-1">
                  <div className="flex items-center gap-2 mb-1.5">
                    <Users size={12} style={{ color: T.highlight }} />
                    <span style={{ fontFamily: FM, color: T.muted }}
                          className="text-[9px] uppercase tracking-[0.25em] font-medium">
                      Хэлтэс
                    </span>
                  </div>
                  <h3 style={{ fontFamily: FD, fontWeight: 500, letterSpacing: "-0.02em" }} className="text-xl truncate">
                    {dept.name}
                  </h3>
                  {dept.description && (
                    <p style={{ color: T.muted }} className="text-xs mt-1 line-clamp-2">{dept.description}</p>
                  )}
                </div>
              </div>

              {manager ? (
                <div className="glass-soft rounded-xl px-3 py-2.5 mb-3 flex items-center gap-2">
                  <ShieldCheck size={12} style={{ color: T.highlight }} />
                  <div className="flex-1 min-w-0">
                    <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider">
                      Ахлагч
                    </div>
                    <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-sm truncate">
                      {manager.name}
                    </div>
                  </div>
                </div>
              ) : (
                <div className="glass-soft rounded-xl px-3 py-2.5 mb-3" style={{ color: T.warn }}>
                  <span style={{ fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
                    Ахлагч оноогоогүй
                  </span>
                </div>
              )}

              <div className="glass-soft rounded-xl px-4 py-3 mb-4">
                <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-[0.25em] mb-1">
                  Ажилтны тоо
                </div>
                <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-2xl tabular-nums mb-1">
                  {empCount}
                </div>
                {sampleEmps.length > 0 && (
                  <div style={{ color: T.muted }} className="text-[11px] line-clamp-2">
                    {sampleEmps.map((e) => e.name).join(", ")}
                    {empCount > 5 && ` · +${empCount - 5}`}
                  </div>
                )}
              </div>

              <div className="flex gap-2">
                <button onClick={() => onEdit(dept)}
                  className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-xs font-medium flex items-center justify-center gap-1.5"
                  style={{ fontFamily: FS, color: T.ink }}>
                  <Edit3 size={12} /> Засах
                </button>
                <button onClick={() => setConfirmDel(dept)}
                  className="glass-soft press-btn px-4 py-2.5 rounded-xl text-xs font-medium"
                  style={{ fontFamily: FS, color: T.err }}>
                  <Trash2 size={12} />
                </button>
              </div>
            </article>
          );
        })}
      </div>

      {confirmDel && (
        <Modal onClose={() => setConfirmDel(null)} title="Хэлтэс устгах уу?" maxW="max-w-sm">
          <p style={{ color: T.muted }} className="text-sm mb-5">
            <strong style={{ color: T.ink }}>{confirmDel.name}</strong> хэлтэс устгагдана. Энэ хэлтсэд харьяалагдаж байсан ажилтнуудын <strong>хэлтэс хоосон</strong> болно (ажилтнууд устгагдахгүй).
          </p>
          <div className="flex gap-3">
            <button onClick={() => setConfirmDel(null)}
              className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-sm"
              style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
            <button onClick={() => { onDelete(confirmDel.id); setConfirmDel(null); }}
              className="glow-danger press-btn flex-1 py-2.5 rounded-xl text-sm font-medium flex items-center justify-center gap-1.5"
              style={{ fontFamily: FS }}>
              <Trash2 size={12} /> Устгах
            </button>
          </div>
        </Modal>
      )}
    </>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  DEPARTMENT FORM MODAL
// ═══════════════════════════════════════════════════════════════════════════
function DepartmentFormModal({ mode, dept, managers, onSave, onClose }) {
  const [name, setName] = useState(dept?.name || "");
  const [description, setDescription] = useState(dept?.description || "");
  const [managerId, setManagerId] = useState(dept?.manager_id || "");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  const submit = async () => {
    setErr("");
    if (!name.trim()) return setErr("Хэлтсийн нэр оруулна уу");
    setBusy(true);
    await onSave({
      id: dept?.id || null,
      name: name.trim(),
      description: description.trim() || null,
      manager_id: managerId || null,
    });
    setBusy(false);
  };

  return (
    <Modal onClose={onClose} title={mode === "add" ? "Хэлтэс нэмэх" : "Хэлтэс засах"}>
      <div className="space-y-4">
        <Field label="Хэлтсийн нэр" required>
          <Input value={name} onChange={setName} placeholder="Жишээ: Маркетинг, Худалдаа" autoFocus />
        </Field>

        <Field label="Тайлбар (заавал биш)">
          <textarea value={description} onChange={(e) => setDescription(e.target.value)} rows={2}
            placeholder="Хэлтсийн үндсэн чиг үүрэг"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black resize-none" />
        </Field>

        <Field label="Хэлтсийн ахлагч (заавал биш)">
          <select value={managerId} onChange={(e) => setManagerId(e.target.value)}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none focus:border-black">
            <option value="">— Сонгоогүй —</option>
            {managers.map((m) => (
              <option key={m.id} value={m.id}>{m.name}</option>
            ))}
          </select>
          <p style={{ color: T.muted }} className="text-[11px] mt-1.5">
            Ахлагч сонгосон үед тэр хэлтсийн бүх ажилтныг автомат хариуцна
          </p>
        </Field>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium"
            style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
          <button onClick={submit} disabled={busy}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2"
            style={{ fontFamily: FS }}>
            {busy && <Loader2 size={13} className="spin" />}
            Хадгалах
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  LEAVES — helpers
// ═══════════════════════════════════════════════════════════════════════════
const LEAVE_TYPES = {
  sick: "Өвчний чөлөө",
  personal: "Хувийн чөлөө",
  vacation: "Амралт",
  maternity: "Жирэмсний / Хүүхдийн",
  unpaid: "Цалингүй чөлөө",
  other: "Бусад",
};

const LEAVE_STATUS = {
  pending: { label: "Хүлээгдэж буй", color: T.warn, soft: T.warnSoft },
  approved: { label: "Зөвшөөрсөн", color: T.ok, soft: T.okSoft },
  denied: { label: "Татгалзсан", color: T.err, soft: T.errSoft },
  cancelled: { label: "Цуцалсан", color: T.muted, soft: "rgba(107,114,128,0.1)" },
};

function diffDays(start, end) {
  const s = new Date(start + "T00:00:00").getTime();
  const e = new Date(end + "T00:00:00").getTime();
  return Math.round((e - s) / 86400000) + 1;
}

// ═══════════════════════════════════════════════════════════════════════════
//  MY LEAVES VIEW (employee)
// ═══════════════════════════════════════════════════════════════════════════
function MyLeavesView({ leaves, onNew, onCancel }) {
  return (
    <div className="space-y-4 fade-in">
      <button onClick={onNew}
        className="glow-primary press-btn w-full py-3 rounded-2xl text-sm font-medium flex items-center justify-center gap-2 slide-up"
        style={{ fontFamily: FS }}>
        <Plus size={14} /> Чөлөөний хүсэлт явуулах
      </button>

      {leaves.length === 0 ? (
        <div className="glass rounded-3xl py-12 px-6 text-center slide-up-delay-1" style={{ color: T.muted }}>
          <Calendar size={28} className="mx-auto mb-3" strokeWidth={1.5} />
          <p className="text-sm">Илгээсэн чөлөөний хүсэлт алга</p>
        </div>
      ) : (
        <div className="space-y-3 slide-up-delay-1">
          {leaves.map((l) => {
            const status = LEAVE_STATUS[l.status] || LEAVE_STATUS.pending;
            const days = diffDays(l.start_date, l.end_date);
            return (
              <div key={l.id} className="glass lift rounded-2xl p-4 slide-up">
                <div className="flex items-start justify-between gap-3 mb-2">
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <span style={{
                        background: T.highlightSoft, color: T.highlight, fontFamily: FM,
                      }} className="px-2 py-0.5 rounded-full text-[9px] uppercase tracking-[0.2em] font-medium">
                        {LEAVE_TYPES[l.leave_type] || l.leave_type}
                      </span>
                      {!l.paid && (
                        <span style={{ background: "rgba(107,114,128,0.1)", color: T.muted, fontFamily: FM }}
                              className="px-2 py-0.5 rounded-full text-[9px] uppercase tracking-[0.2em]">
                          Цалингүй
                        </span>
                      )}
                    </div>
                    <div style={{ fontFamily: FM, fontWeight: 500 }} className="text-sm">
                      {l.start_date} – {l.end_date}
                    </div>
                    <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mt-0.5">
                      {days} өдөр
                    </div>
                  </div>
                  <span style={{ background: status.soft, color: status.color, fontFamily: FM }}
                        className="px-2.5 py-1 rounded-full text-[9px] uppercase tracking-[0.2em] font-medium">
                    {status.label}
                  </span>
                </div>
                {l.reason && <p style={{ color: T.muted }} className="text-xs leading-relaxed mb-2">{l.reason}</p>}
                {l.admin_note && (
                  <div className="glass-soft rounded-lg p-2.5 mb-2">
                    <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider mb-1">
                      Админы тэмдэглэл
                    </div>
                    <p style={{ fontFamily: FS }} className="text-xs">{l.admin_note}</p>
                  </div>
                )}
                {l.status === "pending" && (
                  <button onClick={() => onCancel(l.id)}
                    className="glass-soft press-btn w-full py-2 rounded-lg text-[11px] uppercase tracking-[0.2em]"
                    style={{ fontFamily: FM, color: T.err }}>
                    Цуцлах
                  </button>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  LEAVE FORM MODAL
// ═══════════════════════════════════════════════════════════════════════════
function LeaveFormModal({ onClose, onSubmit }) {
  const today = new Date().toISOString().slice(0, 10);
  const [leaveType, setLeaveType] = useState("personal");
  const [startDate, setStartDate] = useState(today);
  const [endDate, setEndDate] = useState(today);
  const [reason, setReason] = useState("");
  const [paid, setPaid] = useState(true);
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async () => {
    setErr("");
    if (!startDate || !endDate) return setErr("Огноо сонгоно уу");
    if (new Date(endDate) < new Date(startDate)) return setErr("Дуусах огноо эхлэхээс өмнө байж болохгүй");
    if (!reason.trim()) return setErr("Шалтгаан бичнэ үү");
    setBusy(true);
    await onSubmit({
      leave_type: leaveType,
      start_date: startDate,
      end_date: endDate,
      reason: reason.trim(),
      paid,
    });
    setBusy(false);
  };

  const days = startDate && endDate ? diffDays(startDate, endDate) : 0;

  return (
    <Modal onClose={onClose} title="Чөлөөний хүсэлт">
      <div className="space-y-4">
        <Field label="Чөлөөний төрөл" required>
          <select value={leaveType} onChange={(e) => {
            setLeaveType(e.target.value);
            setPaid(e.target.value !== "unpaid");
          }}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none">
            {Object.entries(LEAVE_TYPES).map(([k, v]) => (
              <option key={k} value={k}>{v}</option>
            ))}
          </select>
        </Field>

        <div className="grid grid-cols-2 gap-3">
          <Field label="Эхлэх огноо" required>
            <input type="date" value={startDate} onChange={(e) => setStartDate(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none" />
          </Field>
          <Field label="Дуусах огноо" required>
            <input type="date" value={endDate} onChange={(e) => setEndDate(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none" />
          </Field>
        </div>

        {days > 0 && (
          <div className="glass-soft rounded-xl px-4 py-3 flex items-baseline justify-between">
            <span style={{ fontFamily: FM, color: T.muted }} className="text-[10px] uppercase tracking-wider">
              Нийт өдөр
            </span>
            <span style={{ fontFamily: FM, fontWeight: 500, color: T.highlight }} className="text-2xl tabular-nums">
              {days}
            </span>
          </div>
        )}

        <Field label="Шалтгаан" required>
          <textarea value={reason} onChange={(e) => setReason(e.target.value)} rows={3}
            placeholder="Жишээ: Эмнэлэгт үзлэгтэй, гэр бүлийн ажил гэх мэт"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none resize-none" />
        </Field>

        <label className="flex items-center gap-2 cursor-pointer">
          <input type="checkbox" checked={paid} onChange={(e) => setPaid(e.target.checked)} />
          <span style={{ fontFamily: FM }} className="text-sm">Цалинтай чөлөө</span>
        </label>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium"
            style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
          <button onClick={submit} disabled={busy}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2"
            style={{ fontFamily: FS }}>
            {busy ? <Loader2 size={13} className="spin" /> : <Send size={13} />}
            Илгээх
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  LEAVES VIEW (admin/manager)
// ═══════════════════════════════════════════════════════════════════════════
function LeavesView({ leaves, employees, onResolve }) {
  const [tab, setTab] = useState("pending");
  const list = leaves.filter((l) => l.status === tab);
  const empById = (id) => employees.find((e) => e.id === id);

  const counts = {
    pending: leaves.filter((l) => l.status === "pending").length,
    approved: leaves.filter((l) => l.status === "approved").length,
    denied: leaves.filter((l) => l.status === "denied").length,
  };

  return (
    <div className="space-y-4 fade-in">
      <div className="flex gap-1.5 slide-up">
        {[
          { id: "pending", label: "Хүлээгдэж буй", count: counts.pending },
          { id: "approved", label: "Зөвшөөрсөн", count: counts.approved },
          { id: "denied", label: "Татгалзсан", count: counts.denied },
        ].map((t) => (
          <button key={t.id} onClick={() => setTab(t.id)}
            className={`${tab === t.id ? "tab-active" : "tab-inactive glass-soft"} press-btn px-3.5 py-1.5 rounded-full border text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5`}
            style={{ fontFamily: FM, borderColor: tab === t.id ? "transparent" : T.borderSoft }}>
            {t.label}
            {t.count > 0 && (
              <span style={{
                background: tab === t.id ? "rgba(255,255,255,0.95)" : T.highlight,
                color: tab === t.id ? T.highlight : "white",
              }} className="px-1.5 py-0.5 rounded-full text-[9px] font-bold tabular-nums">{t.count}</span>
            )}
          </button>
        ))}
      </div>

      {list.length === 0 ? (
        <div className="glass rounded-3xl py-12 px-6 text-center slide-up-delay-1" style={{ color: T.muted }}>
          <Calendar size={28} className="mx-auto mb-3" strokeWidth={1.5} />
          <p className="text-sm">{tab === "pending" ? "Хүлээгдэж буй чөлөө алга" : tab === "approved" ? "Зөвшөөрсөн чөлөө алга" : "Татгалзсан чөлөө алга"}</p>
        </div>
      ) : (
        <div className="space-y-3 slide-up-delay-1">
          {list.map((l) => {
            const emp = empById(l.employee_id);
            const days = diffDays(l.start_date, l.end_date);
            return (
              <div key={l.id} className="glass lift rounded-2xl p-5 slide-up">
                <div className="flex items-start justify-between mb-3">
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <span style={{ background: T.highlightSoft, color: T.highlight, fontFamily: FM }}
                            className="px-2 py-0.5 rounded-full text-[9px] uppercase tracking-[0.2em] font-medium">
                        {LEAVE_TYPES[l.leave_type]}
                      </span>
                      {!l.paid && (
                        <span style={{ background: "rgba(107,114,128,0.1)", color: T.muted, fontFamily: FM }}
                              className="px-2 py-0.5 rounded-full text-[9px] uppercase tracking-[0.2em]">
                          Цалингүй
                        </span>
                      )}
                    </div>
                    <div style={{ fontFamily: FD, fontWeight: 500 }} className="text-lg">{emp?.name || "(устсан)"}</div>
                    <div style={{ fontFamily: FM, color: T.muted }} className="text-[10px] uppercase tracking-wider mt-0.5">
                      {l.start_date} – {l.end_date} · {days} өдөр
                    </div>
                  </div>
                </div>

                {l.reason && (
                  <div className="glass-soft rounded-lg p-3 mb-3">
                    <p style={{ fontFamily: FS }} className="text-xs leading-relaxed">{l.reason}</p>
                  </div>
                )}

                {l.status === "pending" ? (
                  <div className="flex gap-2">
                    <button onClick={() => onResolve(l, "denied")}
                      className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-xs font-medium"
                      style={{ fontFamily: FS, color: T.ink }}>
                      Татгалзах
                    </button>
                    <button onClick={() => onResolve(l, "approved")}
                      className="glow-success press-btn flex-1 py-2.5 rounded-xl text-xs font-medium flex items-center justify-center gap-1.5"
                      style={{ fontFamily: FS }}>
                      <CheckCircle2 size={13} /> Зөвшөөрөх
                    </button>
                  </div>
                ) : l.admin_note && (
                  <div className="glass-soft rounded-lg p-2.5">
                    <div style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-wider mb-1">
                      Тэмдэглэл
                    </div>
                    <p style={{ fontFamily: FS }} className="text-xs">{l.admin_note}</p>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  PDF SALARY REPORT GENERATOR
// ═══════════════════════════════════════════════════════════════════════════
async function generateSalaryPDF({ employee, sessions, periodStart, periodEnd, periodLabel }) {
  const { default: jsPDF } = await import("jspdf");
  const { default: autoTable } = await import("jspdf-autotable");

  const doc = new jsPDF({ unit: "mm", format: "a4" });
  const pageW = doc.internal.pageSize.getWidth();
  const pageH = doc.internal.pageSize.getHeight();

  // ── Header — CoreLink brand
  doc.setFillColor(99, 102, 241); // indigo
  doc.rect(0, 0, pageW, 32, "F");

  doc.setTextColor(255, 255, 255);
  doc.setFontSize(28);
  doc.setFont("helvetica", "bold");
  doc.text("CoreLink", 14, 18);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text("SALARY REPORT", 14, 26);

  // Дата
  doc.setFontSize(9);
  const today = new Date().toLocaleDateString("en-GB");
  doc.text(`Generated: ${today}`, pageW - 14, 18, { align: "right" });
  doc.text(`Period: ${periodLabel}`, pageW - 14, 26, { align: "right" });

  // ── Body — Employee info
  doc.setTextColor(30, 27, 75);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text("Employee Information", 14, 48);

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.setTextColor(75, 85, 99);

  const infoY = 56;
  doc.text("Name:", 14, infoY);
  doc.setTextColor(30, 27, 75);
  doc.setFont("helvetica", "bold");
  doc.text(employee.name || "—", 40, infoY);

  doc.setFont("helvetica", "normal");
  doc.setTextColor(75, 85, 99);
  doc.text("Position:", 14, infoY + 6);
  doc.setTextColor(30, 27, 75);
  doc.setFont("helvetica", "bold");
  doc.text(employee.job_title || "—", 40, infoY + 6);

  doc.setFont("helvetica", "normal");
  doc.setTextColor(75, 85, 99);
  doc.text("Hourly Rate:", 14, infoY + 12);
  doc.setTextColor(30, 27, 75);
  doc.setFont("helvetica", "bold");
  doc.text(`${(employee.hourly_rate || 0).toLocaleString()} MNT/hr`, 40, infoY + 12);

  // ── Calculate totals
  const startMs = periodStart;
  const endMs = periodEnd;
  const filtered = sessions.filter((s) => {
    const t = new Date(s.start_time).getTime();
    return t >= startMs && t < endMs;
  });

  // Group by day
  const byDay = {};
  filtered.forEach((s) => {
    const day = new Date(s.start_time).toISOString().slice(0, 10);
    const ms = new Date(s.end_time).getTime() - new Date(s.start_time).getTime();
    if (!byDay[day]) byDay[day] = 0;
    byDay[day] += ms;
  });

  const days = Object.keys(byDay).sort();
  const totalMs = Object.values(byDay).reduce((a, b) => a + b, 0);
  const totalHours = totalMs / 3600000;
  const rate = employee.hourly_rate || 0;
  const totalSalary = totalHours * rate;

  // ── Big totals card
  const cardY = 82;
  doc.setFillColor(243, 244, 246);
  doc.roundedRect(14, cardY, pageW - 28, 28, 3, 3, "F");

  doc.setTextColor(107, 114, 128);
  doc.setFontSize(8);
  doc.setFont("helvetica", "normal");
  doc.text("TOTAL HOURS", 22, cardY + 8);
  doc.text("WORKING DAYS", 80, cardY + 8);
  doc.text("TOTAL SALARY (MNT)", 138, cardY + 8);

  doc.setTextColor(30, 27, 75);
  doc.setFontSize(20);
  doc.setFont("helvetica", "bold");
  doc.text(`${totalHours.toFixed(1)}`, 22, cardY + 20);
  doc.text(`${days.length}`, 80, cardY + 20);

  doc.setTextColor(99, 102, 241);
  doc.text(totalSalary.toLocaleString(), 138, cardY + 20);

  // ── Table — Daily breakdown
  doc.setTextColor(30, 27, 75);
  doc.setFontSize(14);
  doc.setFont("helvetica", "bold");
  doc.text("Daily Breakdown", 14, 122);

  const tableData = days.map((d) => {
    const ms = byDay[d];
    const hours = ms / 3600000;
    const earnings = hours * rate;
    const dateObj = new Date(d);
    const weekday = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"][dateObj.getDay()];
    return [
      d,
      weekday,
      hours.toFixed(2),
      earnings.toLocaleString(),
    ];
  });

  autoTable(doc, {
    startY: 128,
    head: [["Date", "Day", "Hours", "Earnings (MNT)"]],
    body: tableData,
    foot: [["", "Total", totalHours.toFixed(2), totalSalary.toLocaleString()]],
    theme: "striped",
    headStyles: {
      fillColor: [99, 102, 241],
      textColor: [255, 255, 255],
      fontStyle: "bold",
      fontSize: 10,
    },
    footStyles: {
      fillColor: [237, 233, 254],
      textColor: [99, 102, 241],
      fontStyle: "bold",
    },
    bodyStyles: { textColor: [30, 27, 75], fontSize: 10 },
    alternateRowStyles: { fillColor: [248, 250, 252] },
    columnStyles: {
      0: { cellWidth: 40 },
      1: { cellWidth: 30, halign: "center" },
      2: { cellWidth: 35, halign: "right" },
      3: { halign: "right" },
    },
    margin: { left: 14, right: 14 },
  });

  // ── Signatures
  const finalY = doc.lastAutoTable.finalY || 200;
  let sigY = finalY + 25;
  if (sigY > pageH - 50) {
    doc.addPage();
    sigY = 30;
  }

  doc.setDrawColor(200, 200, 200);
  doc.line(20, sigY, 80, sigY);
  doc.line(pageW - 80, sigY, pageW - 20, sigY);

  doc.setFontSize(9);
  doc.setTextColor(107, 114, 128);
  doc.setFont("helvetica", "normal");
  doc.text("Employee signature", 50, sigY + 6, { align: "center" });
  doc.text("Authorized signature", pageW - 50, sigY + 6, { align: "center" });

  // ── Footer
  doc.setFontSize(8);
  doc.setTextColor(150, 150, 150);
  doc.text(`CoreLink Time Tracking · ${today}`, pageW / 2, pageH - 8, { align: "center" });

  // Save
  const filename = `salary_${employee.name?.replace(/\s+/g, "_") || "report"}_${periodLabel.replace(/\s+/g, "_")}.pdf`;
  doc.save(filename);
}

// ═══════════════════════════════════════════════════════════════════════════
//  KPI DASHBOARD VIEW
// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
//  KPI Excel Export
// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
//  SALARY PDF — Цалингийн тайлан үүсгэх
// ═══════════════════════════════════════════════════════════════════════════
async function exportSalaryPdf(employee, sessions, leaves, year, month) {
  const { jsPDF } = await import("jspdf");
  await import("jspdf-autotable");

  const monthStart = new Date(year, month - 1, 1);
  const monthEnd = new Date(year, month, 0, 23, 59, 59);

  // Filter sessions for this month
  const monthSessions = sessions.filter((s) => {
    if (s.employee_id !== employee.id || !s.end_time) return false;
    const start = new Date(s.start_time);
    return start >= monthStart && start <= monthEnd;
  });

  // Тооцооллуудаа хийе
  let totalMs = 0;
  let regularMs = 0;
  let overtimeMs = 0;
  const dailyHours = {};

  monthSessions.forEach((s) => {
    const start = new Date(s.start_time);
    const end = new Date(s.end_time);
    const ms = end - start;
    totalMs += ms;

    const dayKey = start.toISOString().slice(0, 10);
    dailyHours[dayKey] = (dailyHours[dayKey] || 0) + ms;
  });

  // Илүү цаг тооцох (өдөрт 8+ цаг -> overtime)
  Object.values(dailyHours).forEach((ms) => {
    const hours = ms / 3600000;
    if (hours <= 8) {
      regularMs += ms;
    } else {
      regularMs += 8 * 3600000;
      overtimeMs += (hours - 8) * 3600000;
    }
  });

  const totalHours = totalMs / 3600000;
  const regularHours = regularMs / 3600000;
  const overtimeHours = overtimeMs / 3600000;

  const hourlyRate = Number(employee.hourly_rate || 0);
  const otMultiplier = Number(employee.overtime_rate_multiplier || 1.5);
  const baseSalary = Number(employee.base_salary || 0);

  const regularPay = regularHours * hourlyRate;
  const overtimePay = overtimeHours * hourlyRate * otMultiplier;

  // Чөлөө тооцох
  const monthLeaves = leaves.filter((l) => {
    if (l.employee_id !== employee.id || l.status !== "approved") return false;
    const lDate = new Date(l.leave_date);
    return lDate >= monthStart && lDate <= monthEnd;
  });
  const leaveDeduction = monthLeaves.length * 8 * hourlyRate * 0.5; // 50% хасалт чөлөөтэй өдөр

  const grossPay = baseSalary + regularPay + overtimePay - leaveDeduction;
  const tax = grossPay * 0.1; // 10% татвар
  const netPay = grossPay - tax;

  const monthNames = ["", "1-р сар", "2-р сар", "3-р сар", "4-р сар", "5-р сар", "6-р сар",
                      "7-р сар", "8-р сар", "9-р сар", "10-р сар", "11-р сар", "12-р сар"];

  // PDF үүсгэх
  const pdf = new jsPDF({ unit: "mm", format: "a4" });
  pdf.setFont("helvetica");

  // Header
  pdf.setFontSize(20);
  pdf.setTextColor(236, 72, 153);
  pdf.text("CoreLink", 20, 20);
  pdf.setFontSize(10);
  pdf.setTextColor(100, 100, 100);
  pdf.text("Tsalingiin tailan", 20, 28);

  // Employee info
  pdf.setFontSize(14);
  pdf.setTextColor(30, 30, 30);
  pdf.text(employee.name || "—", 20, 45);
  pdf.setFontSize(9);
  pdf.setTextColor(120, 120, 120);
  pdf.text(`Albanaa: ${employee.job_title || "—"}`, 20, 51);
  pdf.text(`${monthNames[month]} ${year}`, 20, 56);

  // Тооцооллын хүснэгт
  const data = [
    ["Undsen tsalin", `${baseSalary.toLocaleString()} togrog`],
    ["Niit tsag", `${totalHours.toFixed(1)} tsag`],
    ["  · Engiin", `${regularHours.toFixed(1)} tsag`],
    ["  · Iluu tsag", `${overtimeHours.toFixed(1)} tsag`],
    ["Tsagiin staavka", `${hourlyRate.toLocaleString()} togrog`],
    ["Engiin tsag mongo", `${regularPay.toLocaleString()} togrog`],
    [`Iluu tsag (x${otMultiplier})`, `${overtimePay.toLocaleString()} togrog`],
    ["Cholootei udur", `${monthLeaves.length} udur`],
    ["Cholootei khasalt", `-${leaveDeduction.toLocaleString()} togrog`],
    ["", ""],
    ["NIIT TUGREEN", `${grossPay.toLocaleString()} togrog`],
    ["Tatvar (10%)", `-${tax.toLocaleString()} togrog`],
  ];

  pdf.autoTable({
    startY: 70,
    head: [["Zuil", "Mongo"]],
    body: data,
    theme: "plain",
    headStyles: { fillColor: [236, 72, 153], textColor: [255, 255, 255], fontSize: 9 },
    bodyStyles: { fontSize: 9 },
    alternateRowStyles: { fillColor: [253, 243, 245] },
    margin: { left: 20, right: 20 },
  });

  const finalY = pdf.lastAutoTable.finalY + 8;

  // Final pay box
  pdf.setFillColor(236, 72, 153);
  pdf.rect(20, finalY, 170, 18, "F");
  pdf.setTextColor(255, 255, 255);
  pdf.setFontSize(10);
  pdf.text("AVAH MONGO", 25, finalY + 8);
  pdf.setFontSize(16);
  pdf.text(`${netPay.toLocaleString()} togrog`, 25, finalY + 15);

  // Footer
  pdf.setFontSize(8);
  pdf.setTextColor(150, 150, 150);
  pdf.text(`Uusgesen: ${new Date().toLocaleString("mn-MN")}`, 20, 285);
  pdf.text("CoreLink automatic tailan", 150, 285);

  pdf.save(`CoreLink-${employee.name}-${year}-${String(month).padStart(2, "0")}.pdf`);
}

// ═══════════════════════════════════════════════════════════════════════════
//  BEST EMPLOYEE — Шилдэг ажилтан автомат
// ═══════════════════════════════════════════════════════════════════════════
function calculateBestEmployees(employees, sessions, kpiEntries, leaves, year, month) {
  const monthStart = new Date(year, month - 1, 1);
  const monthEnd = new Date(year, month, 0, 23, 59, 59);

  const stats = employees.map((emp) => {
    // Цаг
    const empSessions = sessions.filter((s) => {
      if (s.employee_id !== emp.id || !s.end_time) return false;
      const sd = new Date(s.start_time);
      return sd >= monthStart && sd <= monthEnd;
    });
    const totalHours = empSessions.reduce((sum, s) =>
      sum + (new Date(s.end_time) - new Date(s.start_time)) / 3600000, 0);

    // KPI
    const empKpis = kpiEntries.filter((k) => {
      if (k.employee_id !== emp.id) return false;
      const kd = new Date(k.date);
      return kd >= monthStart && kd <= monthEnd;
    });
    const kpiScore = empKpis.reduce((sum, k) => sum + Number(k.value || 0), 0);

    // Чөлөө
    const empLeaves = leaves.filter((l) => {
      if (l.employee_id !== emp.id || l.status !== "approved") return false;
      const ld = new Date(l.leave_date);
      return ld >= monthStart && ld <= monthEnd;
    });
    const leaveCount = empLeaves.length;

    // Final оноо: цаг (40%) + KPI (40%) + цөөн чөлөө (20%)
    // Normalize: бусадтай харьцангуй
    return {
      employee: emp,
      totalHours: totalHours.toFixed(1),
      kpiScore,
      leaveCount,
      // Тогтмол шинж шалгаруулах
      score: 0,
    };
  });

  // Normalize and score
  const maxHours = Math.max(...stats.map((s) => s.totalHours), 1);
  const maxKpi = Math.max(...stats.map((s) => s.kpiScore), 1);
  const maxLeaves = Math.max(...stats.map((s) => s.leaveCount), 1);

  stats.forEach((s) => {
    const hourScore = (s.totalHours / maxHours) * 40;
    const kpiScore = (s.kpiScore / maxKpi) * 40;
    const leaveScore = ((maxLeaves - s.leaveCount) / maxLeaves) * 20;
    s.score = Math.round(hourScore + kpiScore + leaveScore);
  });

  // Sort by score desc
  stats.sort((a, b) => b.score - a.score);
  return stats;
}

function exportKpiToExcel(departments, kpiDefs, filteredEntries, periodRange) {
  const wb = XLSX.utils.book_new();

  // ============== Хуудас 1: ХУРААНГУЙ ==============
  const summaryRows = [
    ["CoreLink · KPI Хураангуй тайлан"],
    [`Хугацаа: ${periodRange.label}`],
    [`Огноо: ${periodRange.start} → ${periodRange.end}`],
    [],
    ["Хэлтэс", "KPI", "Нэгж", "Нийт утга", "Зорилт", "Биеэлэлт %", "Тренд"],
  ];

  departments.forEach((dept) => {
    const deptKpis = kpiDefs.filter(k => k.department_id === dept.id);
    deptKpis.forEach((kpi) => {
      const entries = filteredEntries.filter(e => e.kpi_id === kpi.id);
      const total = entries.reduce((sum, e) => sum + Number(e.value), 0);

      // Target tailbar
      let targetTotal = "";
      let percent = "";
      if (kpi.target) {
        let tt = Number(kpi.target);
        if (kpi.target_period === "daily") {
          const days = Math.max(1, Math.ceil((new Date(periodRange.end) - new Date(periodRange.start)) / 86400000) + 1);
          tt = Number(kpi.target) * days;
        } else if (kpi.target_period === "weekly") {
          const weeks = Math.max(1, Math.ceil((new Date(periodRange.end) - new Date(periodRange.start)) / (7 * 86400000)));
          tt = Number(kpi.target) * weeks;
        }
        targetTotal = tt;
        percent = tt > 0 ? `${((total / tt) * 100).toFixed(1)}%` : "";
      }

      summaryRows.push([
        dept.name,
        kpi.name,
        kpi.unit || "",
        total,
        targetTotal,
        percent,
        "", // тренд хоосон
      ]);
    });
  });

  const ws1 = XLSX.utils.aoa_to_sheet(summaryRows);
  ws1["!cols"] = [{ wch: 18 }, { wch: 24 }, { wch: 8 }, { wch: 16 }, { wch: 16 }, { wch: 12 }, { wch: 10 }];
  XLSX.utils.book_append_sheet(wb, ws1, "Хураангуй");

  // ============== Хуудас 2: ӨДРИЙН ДЭЛГЭРЭНГҮЙ ==============
  // Огнооны массив
  const dateList = [];
  const start = new Date(periodRange.start);
  const end = new Date(periodRange.end);
  const cur = new Date(start);
  while (cur <= end) {
    dateList.push(cur.toISOString().slice(0, 10));
    cur.setDate(cur.getDate() + 1);
  }

  const detailRows = [
    ["CoreLink · KPI Өдрийн дэлгэрэнгүй"],
    [`Хугацаа: ${periodRange.label}`],
    [],
  ];

  departments.forEach((dept) => {
    const deptKpis = kpiDefs.filter(k => k.department_id === dept.id);
    if (deptKpis.length === 0) return;

    // Хэлтсийн гарчиг
    detailRows.push([`▸ ${dept.name}`]);

    // Header: Огноо | KPI1 | KPI2 | ...
    const header = ["Огноо", ...deptKpis.map(k => `${k.name}${k.unit ? ` (${k.unit})` : ""}`)];
    detailRows.push(header);

    // Өдөр бүрд мөр
    dateList.forEach((date) => {
      const row = [date];
      deptKpis.forEach((kpi) => {
        const entry = filteredEntries.find(e => e.kpi_id === kpi.id && e.entry_date === date);
        row.push(entry ? Number(entry.value) : "");
      });
      detailRows.push(row);
    });

    // Нийт мөр
    const totalRow = ["НИЙТ"];
    deptKpis.forEach((kpi) => {
      const entries = filteredEntries.filter(e => e.kpi_id === kpi.id);
      const total = entries.reduce((sum, e) => sum + Number(e.value), 0);
      totalRow.push(total);
    });
    detailRows.push(totalRow);
    detailRows.push([]);  // хоосон мөр
  });

  const ws2 = XLSX.utils.aoa_to_sheet(detailRows);
  ws2["!cols"] = [{ wch: 12 }, ...Array(20).fill({ wch: 16 })];
  XLSX.utils.book_append_sheet(wb, ws2, "Өдрийн дэлгэрэнгүй");

  // Файл татах
  const fileName = `CoreLink-KPI-${periodRange.start}-${periodRange.end}.xlsx`;
  XLSX.writeFile(wb, fileName);
}

function KPIDashboardView({ departments, kpiDefs, kpiEntries, isAdmin, currentUserId, onAddKpi, onEditKpi, onDeleteKpi, onOpenInputForm }) {
  const [period, setPeriod] = useState("month"); // day | week | month | year | custom
  const [selectedDept, setSelectedDept] = useState("all");
  const [confirmDelKpi, setConfirmDelKpi] = useState(null);
  const [viewMode, setViewMode] = useState("cards"); // cards | charts
  const [chartType, setChartType] = useState("bar"); // bar | line | area
  const [chartGroupBy, setChartGroupBy] = useState("day"); // day | week | month
  // 🗓 Хэлтэс бүрд тус тусдаа anchor огноо хадгалах { [deptId]: "YYYY-MM-DD" }
  const [deptAnchorDates, setDeptAnchorDates] = useState({});
  const setDeptAnchor = (deptId, dateISO) => {
    setDeptAnchorDates((prev) => ({ ...prev, [deptId]: dateISO }));
  };

  const today = new Date();
  const [selectedDate, setSelectedDate] = useState(today.toISOString().slice(0, 10));
  const [selectedMonth, setSelectedMonth] = useState(today.toISOString().slice(0, 7)); // YYYY-MM
  const [selectedYear, setSelectedYear] = useState(String(today.getFullYear()));
  const [customStart, setCustomStart] = useState(today.toISOString().slice(0, 10));
  const [customEnd, setCustomEnd] = useState(today.toISOString().slice(0, 10));

  const periodRange = useMemo(() => {
    if (period === "day") {
      return { start: selectedDate, end: selectedDate, label: selectedDate };
    }
    if (period === "yesterday") {
      const y = new Date();
      y.setDate(y.getDate() - 1);
      const yStr = y.toISOString().slice(0, 10);
      return { start: yStr, end: yStr, label: `Өчигдөр (${yStr})` };
    }
    if (period === "week") {
      const end = new Date(selectedDate);
      const start = new Date(end); start.setDate(end.getDate() - 6);
      return {
        start: start.toISOString().slice(0, 10),
        end: end.toISOString().slice(0, 10),
        label: `7 хоног (${start.toISOString().slice(5, 10)}–${end.toISOString().slice(5, 10)})`,
      };
    }
    if (period === "month") {
      // Сонгосон сар
      const [year, month] = selectedMonth.split("-").map(Number);
      const start = `${selectedMonth}-01`;
      const lastDay = new Date(year, month, 0).getDate();
      const end = `${selectedMonth}-${String(lastDay).padStart(2, "0")}`;
      const monthName = new Date(year, month - 1, 1).toLocaleDateString("mn-MN", { month: "long", year: "numeric" });
      return { start, end, label: monthName };
    }
    if (period === "year") {
      return {
        start: `${selectedYear}-01-01`,
        end: `${selectedYear}-12-31`,
        label: `${selectedYear} он`,
      };
    }
    if (period === "custom") {
      return { start: customStart, end: customEnd, label: `${customStart} – ${customEnd}` };
    }
    return { start: "", end: "", label: "" };
  }, [period, selectedDate, selectedMonth, selectedYear, customStart, customEnd]);

  const filteredEntries = useMemo(() => {
    return kpiEntries.filter((e) => e.entry_date >= periodRange.start && e.entry_date <= periodRange.end);
  }, [kpiEntries, periodRange]);

  // 🔃 Хэлтсийн дараалал — гар тохиргоо (localStorage)
  const [deptOrder, setDeptOrder] = useState(() => {
    try {
      const saved = localStorage.getItem("orgoo-dept-order");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });

  useEffect(() => {
    try { localStorage.setItem("orgoo-dept-order", JSON.stringify(deptOrder)); } catch {}
  }, [deptOrder]);

  // Sorted departments
  const sortedDepartments = useMemo(() => {
    if (deptOrder.length === 0) return departments;
    return [...departments].sort((a, b) => {
      const ia = deptOrder.indexOf(a.id);
      const ib = deptOrder.indexOf(b.id);
      if (ia === -1 && ib === -1) return 0;
      if (ia === -1) return 1;
      if (ib === -1) return -1;
      return ia - ib;
    });
  }, [departments, deptOrder]);

  // Дараалал солих (дээш/доош нэг алхам)
  const moveDept = (deptId, direction) => {
    const ordered = sortedDepartments.map((d) => d.id);
    const idx = ordered.indexOf(deptId);
    if (idx === -1) return;
    if (direction === "up" && idx > 0) {
      [ordered[idx], ordered[idx - 1]] = [ordered[idx - 1], ordered[idx]];
    } else if (direction === "down" && idx < ordered.length - 1) {
      [ordered[idx], ordered[idx + 1]] = [ordered[idx + 1], ordered[idx]];
    }
    setDeptOrder(ordered);
  };

  const visibleDepts = selectedDept === "all" ? sortedDepartments : sortedDepartments.filter(d => d.id === selectedDept);

  // Department-ийн ахлагч мөн үү?
  const isDeptManager = (deptId) => {
    const dept = departments.find(d => d.id === deptId);
    return dept?.manager_id === currentUserId;
  };

  return (
    <div className="space-y-4 fade-in">
      {/* Period type tabs */}
      <div className="glass rounded-2xl p-4 slide-up space-y-3">
        <div className="flex items-center gap-3 flex-wrap">
          <div className="flex gap-1.5 flex-wrap">
            {[
              { id: "day", label: "Өнөөдөр" },
              { id: "yesterday", label: "Өчигдөр" },
              { id: "week", label: "7 хоног" },
              { id: "month", label: "Сар" },
              { id: "year", label: "Жил" },
              { id: "custom", label: "Гар" },
            ].map((p) => (
              <button key={p.id} onClick={() => setPeriod(p.id)}
                className={`${period === p.id ? "tab-active" : "tab-inactive glass-soft"} press-btn px-3 py-1.5 rounded-full text-[10px] uppercase tracking-[0.2em]`}
                style={{ fontFamily: FM, borderColor: period === p.id ? "transparent" : T.borderSoft, border: "1px solid" }}>
                {p.label}
              </button>
            ))}
          </div>

          <div className="flex-1" />

          {/* Хэлтэс шүүлт */}
          <select value={selectedDept} onChange={(e) => setSelectedDept(e.target.value)}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="px-3 py-2 rounded-lg border text-xs outline-none">
            <option value="all">Бүх хэлтэс</option>
            {departments.map((d) => (
              <option key={d.id} value={d.id}>{d.name}</option>
            ))}
          </select>

          {isAdmin && (
            <button onClick={onAddKpi}
              className="glow-primary press-btn px-3 py-2 rounded-lg text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5"
              style={{ fontFamily: FM }}>
              <Plus size={11} /> KPI нэмэх
            </button>
          )}
        </div>

        {/* Огноо сонгогчид + view mode */}
        <div className="flex items-center gap-3 flex-wrap pt-1 border-t" style={{ borderColor: T.borderSoft }}>
          {period === "day" && (
            <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="px-3 py-2 rounded-lg border text-xs outline-none" />
          )}
          {period === "week" && (
            <>
              <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">Дуусах өдөр:</span>
              <input type="date" value={selectedDate} onChange={(e) => setSelectedDate(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-3 py-2 rounded-lg border text-xs outline-none" />
            </>
          )}
          {period === "month" && (
            <input type="month" value={selectedMonth} onChange={(e) => setSelectedMonth(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="px-3 py-2 rounded-lg border text-xs outline-none" />
          )}
          {period === "year" && (
            <select value={selectedYear} onChange={(e) => setSelectedYear(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="px-3 py-2 rounded-lg border text-xs outline-none">
              {[2024, 2025, 2026, 2027, 2028].map((y) => (
                <option key={y} value={y}>{y} он</option>
              ))}
            </select>
          )}
          {period === "custom" && (
            <>
              <input type="date" value={customStart} onChange={(e) => setCustomStart(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-3 py-2 rounded-lg border text-xs outline-none" />
              <span style={{ color: T.muted }} className="text-xs">→</span>
              <input type="date" value={customEnd} onChange={(e) => setCustomEnd(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-3 py-2 rounded-lg border text-xs outline-none" />
            </>
          )}

          <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
            {periodRange.label}
          </span>

          <div className="flex-1" />

          {/* View mode toggle */}
          <div className="flex gap-1 glass-soft rounded-lg p-0.5">
            <button onClick={() => setViewMode("cards")}
              className={`${viewMode === "cards" ? "bg-white shadow-sm" : ""} press-btn px-3 py-1.5 rounded text-[10px] uppercase tracking-wider`}
              style={{ fontFamily: FM, color: viewMode === "cards" ? T.highlight : T.muted }}>
              Карт
            </button>
            <button onClick={() => setViewMode("charts")}
              className={`${viewMode === "charts" ? "bg-white shadow-sm" : ""} press-btn px-3 py-1.5 rounded text-[10px] uppercase tracking-wider flex items-center gap-1`}
              style={{ fontFamily: FM, color: viewMode === "charts" ? T.highlight : T.muted }}>
              <BarChart3 size={10} /> График
            </button>
          </div>

          {viewMode === "charts" && (
            <>
              <select value={chartGroupBy} onChange={(e) => setChartGroupBy(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-3 py-2 rounded-lg border text-xs outline-none"
                title="Бүлэглэх">
                <option value="day">📅 Өдөр бүр</option>
                <option value="week">🗓 7/7 хоног (сүүлийн 5)</option>
                <option value="month">📆 Сар (сүүлийн 5)</option>
              </select>
              <select value={chartType} onChange={(e) => setChartType(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-3 py-2 rounded-lg border text-xs outline-none">
                <option value="bar">Багана</option>
                <option value="line">Шугам</option>
                <option value="area">Талбай</option>
              </select>
            </>
          )}

          <button onClick={() => exportKpiToExcel(visibleDepts, kpiDefs, filteredEntries, periodRange)}
            className="glass-soft press-btn px-3 py-2 rounded-lg text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5 hover:bg-white"
            style={{ fontFamily: FM, color: T.ok, border: `1px solid ${T.borderSoft}` }}>
            <FileSpreadsheet size={11} /> Excel
          </button>
        </div>
      </div>

      {visibleDepts.length === 0 || kpiDefs.length === 0 ? (
        <div className="glass rounded-3xl py-12 px-6 text-center" style={{ color: T.muted }}>
          <BarChart3 size={32} className="mx-auto mb-3" strokeWidth={1.5} />
          <p className="text-sm mb-2">{kpiDefs.length === 0 ? "KPI-ууд тохируулаагүй байна" : "Хэлтэс байхгүй байна"}</p>
          {isAdmin && kpiDefs.length === 0 && (
            <button onClick={onAddKpi}
              className="glow-primary press-btn mt-3 px-4 py-2 rounded-full text-[10px] uppercase tracking-[0.2em] inline-flex items-center gap-1.5"
              style={{ fontFamily: FM }}>
              <Plus size={11} /> Эхний KPI нэмэх
            </button>
          )}
        </div>
      ) : (
        visibleDepts.map((dept, deptIdx) => {
          const deptKpis = kpiDefs.filter(k => k.department_id === dept.id);
          if (deptKpis.length === 0) return null;
          const canEnter = isAdmin || isDeptManager(dept.id);

          return (
            <div key={dept.id} className={`glass-strong rounded-3xl p-5 ${deptIdx < 4 ? `slide-up-delay-${deptIdx + 1}` : "slide-up"}`}>
              {/* Department header */}
              <div className="flex items-center justify-between mb-4">
                <div>
                  <div className="flex items-center gap-2 mb-0.5">
                    <Users size={12} style={{ color: T.highlight }} />
                    <span style={{ fontFamily: FM, color: T.muted }} className="text-[9px] uppercase tracking-[0.25em]">
                      Хэлтэс
                    </span>
                  </div>
                  <h3 style={{ fontFamily: FD, fontWeight: 500 }} className="text-2xl">{dept.name}</h3>
                </div>
                <div className="flex items-center gap-2">
                  {/* 🔃 Дараалал солих товч — зөвхөн admin/manager + "Бүх хэлтэс" үед */}
                  {isAdmin && selectedDept === "all" && visibleDepts.length > 1 && (
                    <div className="flex flex-col gap-0.5">
                      <button onClick={() => moveDept(dept.id, "up")}
                        disabled={deptIdx === 0}
                        title="Дээш"
                        className="press-btn rounded text-xs"
                        style={{
                          width: 20, height: 16,
                          background: deptIdx === 0 ? T.surfaceAlt : T.highlight,
                          color: deptIdx === 0 ? T.muted : "white",
                          opacity: deptIdx === 0 ? 0.4 : 1,
                          cursor: deptIdx === 0 ? "not-allowed" : "pointer",
                          fontFamily: FM, fontWeight: 700, lineHeight: 1,
                        }}>
                        ▲
                      </button>
                      <button onClick={() => moveDept(dept.id, "down")}
                        disabled={deptIdx === visibleDepts.length - 1}
                        title="Доош"
                        className="press-btn rounded text-xs"
                        style={{
                          width: 20, height: 16,
                          background: deptIdx === visibleDepts.length - 1 ? T.surfaceAlt : T.highlight,
                          color: deptIdx === visibleDepts.length - 1 ? T.muted : "white",
                          opacity: deptIdx === visibleDepts.length - 1 ? 0.4 : 1,
                          cursor: deptIdx === visibleDepts.length - 1 ? "not-allowed" : "pointer",
                          fontFamily: FM, fontWeight: 700, lineHeight: 1,
                        }}>
                        ▼
                      </button>
                    </div>
                  )}
                  {canEnter && (
                    <button onClick={() => onOpenInputForm(dept.id)}
                      className="glow-primary press-btn px-3 py-2 rounded-lg text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5"
                      style={{ fontFamily: FM }}>
                      <Plus size={11} /> Тоо оруулах
                    </button>
                  )}
                </div>
              </div>

              {/* KPI cards or Charts */}
              {viewMode === "charts" ? (
                <>
                  {/* 🗓 Хэлтсийн anchor огноо — Зөвхөн week/month grouping үед */}
                  {(chartGroupBy === "week" || chartGroupBy === "month") && (
                    <div className="glass-soft rounded-xl p-3 mb-3 flex items-center gap-2 flex-wrap">
                      <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
                        {chartGroupBy === "week" ? "🗓 Эхлэх огноо" : "📆 Эхлэх сар"}
                      </span>
                      <input
                        type="date"
                        value={deptAnchorDates[dept.id] || new Date().toISOString().slice(0, 10)}
                        onChange={(e) => setDeptAnchor(dept.id, e.target.value)}
                        style={{
                          borderColor: T.border,
                          background: "rgba(255,255,255,0.9)",
                          color: T.ink,
                          fontFamily: FM,
                        }}
                        className="px-3 py-1.5 rounded-lg border text-xs outline-none focus:border-black"
                      />
                      <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                        {chartGroupBy === "week"
                          ? "→ Сонгосон огнооноос буцаж сүүлийн 5 долоо хоног"
                          : "→ Сонгосон сараас буцаж сүүлийн 5 сар"}
                      </span>
                      <button
                        onClick={() => setDeptAnchor(dept.id, new Date().toISOString().slice(0, 10))}
                        style={{ color: T.highlight, fontFamily: FM }}
                        className="press-btn ml-auto text-[10px] uppercase tracking-wider hover:opacity-70"
                        title="Өнөөдөр болгох">
                        Өнөөдөр
                      </button>
                    </div>
                  )}
                  <KpiChartView
                    deptKpis={deptKpis}
                    filteredEntries={filteredEntries}
                    allEntries={kpiEntries}
                    periodRange={periodRange}
                    chartType={chartType}
                    groupBy={chartGroupBy}
                    anchorDate={deptAnchorDates[dept.id]}
                    departmentId={dept.id}
                    initialNote={dept.chart_notes || ""}
                    canEdit={isAdmin}
                    onNoteSaved={(deptId, newNote) => {
                      setDepartments((prev) => prev.map((d) =>
                        d.id === deptId ? { ...d, chart_notes: newNote } : d
                      ));
                    }}
                  />
                </>
              ) : (
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
                {deptKpis.map((kpi) => {
                  let total = 0;
                  let entries = [];

                  // Calculated KPI: формулаар тооцоолох
                  if (kpi.kpi_type === "calculated" && kpi.formula?.numerator_id && kpi.formula?.denominator_id) {
                    const numEntries = filteredEntries.filter(e => e.kpi_id === kpi.formula.numerator_id);
                    const denEntries = filteredEntries.filter(e => e.kpi_id === kpi.formula.denominator_id);
                    const numSum = numEntries.reduce((s, e) => s + Number(e.value), 0);
                    const denSum = denEntries.reduce((s, e) => s + Number(e.value), 0);
                    const op = kpi.formula.operator;
                    if (op === "divide") {
                      total = denSum === 0 ? 0 : numSum / denSum;
                    } else if (op === "multiply") {
                      total = numSum * denSum;
                    } else if (op === "add") {
                      total = numSum + denSum;
                    } else if (op === "subtract") {
                      total = numSum - denSum;
                    }
                  } else if (kpi.kpi_type === "copy" && kpi.formula?.source_id) {
                    // 📋 Copy KPI — source-ийн утгыг хуулна
                    const srcEntries = filteredEntries.filter(e => e.kpi_id === kpi.formula.source_id);
                    total = srcEntries.reduce((s, e) => s + Number(e.value), 0);
                    entries = srcEntries; // түүх ч мөн хуулагдана
                  } else {
                    entries = filteredEntries.filter(e => e.kpi_id === kpi.id);
                    total = entries.reduce((sum, e) => sum + Number(e.value), 0);
                  }

                  // 📊 Computed trends — 7 хоног vs өмнөх 7 хоног + Сар vs өмнөх сар
                  // Anchor date нь сонгосон period-ийн төгсгөл (өнөөдөр/өчигдөр/сонгосон огноо)
                  const fmtDate = (d) => d.toISOString().slice(0, 10);
                  const anchorDate = new Date(periodRange.end);

                  // Helper: тухайн KPI-н нийт дүн (date range дотор)
                  const computeRangeTotal = (startISO, endISO) => {
                    if (kpi.kpi_type === "calculated" && kpi.formula?.numerator_id && kpi.formula?.denominator_id) {
                      const n = kpiEntries
                        .filter(e => e.kpi_id === kpi.formula.numerator_id && e.entry_date >= startISO && e.entry_date <= endISO)
                        .reduce((s, e) => s + Number(e.value), 0);
                      const d = kpiEntries
                        .filter(e => e.kpi_id === kpi.formula.denominator_id && e.entry_date >= startISO && e.entry_date <= endISO)
                        .reduce((s, e) => s + Number(e.value), 0);
                      const op = kpi.formula.operator;
                      if (op === "divide") return d === 0 ? 0 : n / d;
                      if (op === "multiply") return n * d;
                      if (op === "add") return n + d;
                      if (op === "subtract") return n - d;
                      return 0;
                    }
                    if (kpi.kpi_type === "copy" && kpi.formula?.source_id) {
                      return kpiEntries
                        .filter(e => e.kpi_id === kpi.formula.source_id && e.entry_date >= startISO && e.entry_date <= endISO)
                        .reduce((s, e) => s + Number(e.value), 0);
                    }
                    return kpiEntries
                      .filter(e => e.kpi_id === kpi.id && e.entry_date >= startISO && e.entry_date <= endISO)
                      .reduce((s, e) => s + Number(e.value), 0);
                  };

                  // 🗓 Сүүлийн 7 хоног (anchor - 6 to anchor)
                  const last7End = new Date(anchorDate);
                  const last7Start = new Date(anchorDate);
                  last7Start.setDate(last7Start.getDate() - 6);
                  // Өмнөх 7 хоног (anchor - 13 to anchor - 7)
                  const prev7End = new Date(anchorDate);
                  prev7End.setDate(prev7End.getDate() - 7);
                  const prev7Start = new Date(anchorDate);
                  prev7Start.setDate(prev7Start.getDate() - 13);

                  const last7Total = computeRangeTotal(fmtDate(last7Start), fmtDate(last7End));
                  const prev7Total = computeRangeTotal(fmtDate(prev7Start), fmtDate(prev7End));
                  const trend7d = prev7Total > 0
                    ? ((last7Total - prev7Total) / prev7Total) * 100
                    : (last7Total > 0 ? 100 : null);

                  // 📆 Анхорын сар vs өмнөх сар
                  const monthStart = new Date(anchorDate.getFullYear(), anchorDate.getMonth(), 1);
                  const monthEnd = new Date(anchorDate.getFullYear(), anchorDate.getMonth() + 1, 0);
                  const prevMonthStart = new Date(anchorDate.getFullYear(), anchorDate.getMonth() - 1, 1);
                  const prevMonthEnd = new Date(anchorDate.getFullYear(), anchorDate.getMonth(), 0);

                  const currMonthTotal = computeRangeTotal(fmtDate(monthStart), fmtDate(monthEnd));
                  const prevMonthTotal = computeRangeTotal(fmtDate(prevMonthStart), fmtDate(prevMonthEnd));
                  const trendMonth = prevMonthTotal > 0
                    ? ((currMonthTotal - prevMonthTotal) / prevMonthTotal) * 100
                    : (currMonthTotal > 0 ? 100 : null);

                  // ↗/↘ icon-руу backwards compat (7d-г primary)
                  const trend = trend7d !== null ? { change: trend7d, up: trend7d > 0 } : null;

                  // Тус KPI-н өнгийг тогтоогдоход (display_order эсвэл index ашиглан)
                  const kpiIndex = deptKpis.findIndex(k => k.id === kpi.id);
                  const gradients = [
                    { from: "#8b5cf6", to: "#ec4899", shadow: "rgba(139,92,246,0.25)" }, // Purple → Pink
                    { from: "#06b6d4", to: "#3b82f6", shadow: "rgba(6,182,212,0.25)" },  // Cyan → Blue
                    { from: "#f59e0b", to: "#ef4444", shadow: "rgba(245,158,11,0.25)" }, // Orange → Red
                    { from: "#10b981", to: "#14b8a6", shadow: "rgba(16,185,129,0.25)" }, // Green → Teal
                    { from: "#ec4899", to: "#f97316", shadow: "rgba(236,72,153,0.25)" }, // Pink → Orange
                    { from: "#6366f1", to: "#8b5cf6", shadow: "rgba(99,102,241,0.25)" }, // Indigo → Purple
                    { from: "#f43f5e", to: "#fb7185", shadow: "rgba(244,63,94,0.25)" },  // Rose
                    { from: "#0ea5e9", to: "#06b6d4", shadow: "rgba(14,165,233,0.25)" }, // Sky → Cyan
                  ];
                  const grad = gradients[kpiIndex % gradients.length];

                  // Бүтээх mini chart points (өмнөх 7 өдрөөс)
                  const chartPoints = (() => {
                    const days = 7;
                    const today = new Date(periodRange.end || new Date());
                    const points = [];
                    for (let i = days - 1; i >= 0; i--) {
                      const d = new Date(today);
                      d.setDate(d.getDate() - i);
                      const dStr = d.toISOString().slice(0, 10);

                      let val = 0;
                      if (kpi.kpi_type === "calculated" && kpi.formula?.numerator_id && kpi.formula?.denominator_id) {
                        const numEntries = kpiEntries.filter(e => e.kpi_id === kpi.formula.numerator_id && e.entry_date === dStr);
                        const denEntries = kpiEntries.filter(e => e.kpi_id === kpi.formula.denominator_id && e.entry_date === dStr);
                        const n = numEntries.reduce((s, e) => s + Number(e.value), 0);
                        const dn = denEntries.reduce((s, e) => s + Number(e.value), 0);
                        const op = kpi.formula.operator;
                        if (op === "divide") val = dn === 0 ? 0 : n / dn;
                        else if (op === "multiply") val = n * dn;
                        else if (op === "add") val = n + dn;
                        else if (op === "subtract") val = n - dn;
                      } else {
                        const dayEntries = kpiEntries.filter(e => e.kpi_id === kpi.id && e.entry_date === dStr);
                        val = dayEntries.reduce((s, e) => s + Number(e.value), 0);
                      }
                      points.push(val);
                    }
                    return points;
                  })();

                  // Normalize to SVG points
                  const maxVal = Math.max(...chartPoints, 1);
                  const minVal = Math.min(...chartPoints, 0);
                  const range = maxVal - minVal || 1;
                  const svgPoints = chartPoints.map((v, i) => {
                    const x = (i / (chartPoints.length - 1)) * 80;
                    const y = 22 - ((v - minVal) / range) * 18;
                    return `${x.toFixed(1)},${y.toFixed(1)}`;
                  }).join(" ");
                  const polygonPoints = `${svgPoints} 80,24 0,24`;

                  return (
                    <div key={kpi.id}
                      className="lift rounded-2xl p-3 group relative"
                      style={{
                        background: `linear-gradient(135deg, ${grad.from} 0%, ${grad.to} 100%)`,
                        boxShadow: `0 4px 20px ${grad.shadow}`,
                        color: "white",
                      }}>
                      <div className="flex items-start justify-between mb-1.5">
                        <span style={{ fontFamily: FM, opacity: 0.9, fontWeight: 600 }} className="text-[9px] uppercase tracking-[0.15em] line-clamp-2">
                          {kpi.name}
                        </span>
                        <div className="flex items-center gap-1">
                          {kpi.kpi_type === "calculated" && (
                            <div style={{ background: "rgba(255,255,255,0.2)" }}
                              className="w-4 h-4 rounded-full flex items-center justify-center text-[8px]" title="Тооцооллын KPI">
                              🧮
                            </div>
                          )}
                          {trend && (
                            <div style={{ background: "rgba(255,255,255,0.2)" }}
                              className="w-4 h-4 rounded-full flex items-center justify-center text-[9px]">
                              {trend.up ? "↗" : "↘"}
                            </div>
                          )}
                          {isAdmin && (
                            <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity ml-1">
                              <button onClick={() => onEditKpi(kpi)} style={{ color: "white" }} className="hover:opacity-70">
                                <Edit3 size={10} />
                              </button>
                              <button onClick={() => setConfirmDelKpi(kpi)} style={{ color: "white" }} className="hover:opacity-70">
                                <Trash2 size={10} />
                              </button>
                            </div>
                          )}
                        </div>
                      </div>

                      <div className="flex items-baseline gap-1">
                        <span style={{ fontFamily: FD, fontWeight: 700, letterSpacing: "-0.02em" }}
                              className="text-xl tabular-nums">
                          {total.toLocaleString(undefined, {
                            minimumFractionDigits: kpi.decimals || 0,
                            maximumFractionDigits: kpi.decimals || 0,
                          })}
                        </span>
                        {kpi.unit && <span style={{ opacity: 0.85, fontFamily: FM }} className="text-[9px]">{kpi.unit}</span>}
                      </div>

                      {/* Mini chart */}
                      <svg viewBox="0 0 80 24" style={{ width: "100%", height: 20, marginTop: 6 }}>
                        <defs>
                          <linearGradient id={`grad-${kpi.id}`} x1="0" y1="0" x2="0" y2="1">
                            <stop offset="0%" stopColor="#fff" stopOpacity="0.4"/>
                            <stop offset="100%" stopColor="#fff" stopOpacity="0"/>
                          </linearGradient>
                        </defs>
                        <polygon points={polygonPoints} fill={`url(#grad-${kpi.id})`} />
                        <polyline points={svgPoints} fill="none" stroke="white" strokeWidth="1.5" strokeLinejoin="round" strokeLinecap="round" />
                      </svg>

                      {/* 📊 Comparison trends — 7 хоног + Сар */}
                      <div className="mt-1.5 space-y-0.5">
                        <div className="flex items-center justify-between text-[9px]">
                          <span style={{ opacity: 0.7, fontFamily: FM }} className="flex items-center gap-1">
                            <span>📅</span> 7 хоног
                          </span>
                          {trend7d !== null ? (
                            <span style={{
                              opacity: 0.95, fontFamily: FM, fontWeight: 700,
                              color: trend7d >= 0 ? "rgba(255,255,255,0.98)" : "rgba(255,215,215,0.95)"
                            }} className="tabular-nums">
                              {trend7d > 0 ? "↗ +" : trend7d < 0 ? "↘ " : "→ "}{trend7d.toFixed(1)}%
                            </span>
                          ) : (
                            <span style={{ opacity: 0.4, fontFamily: FM }}>—</span>
                          )}
                        </div>
                        <div className="flex items-center justify-between text-[9px]">
                          <span style={{ opacity: 0.7, fontFamily: FM }} className="flex items-center gap-1">
                            <span>🗓</span> Сар
                          </span>
                          {trendMonth !== null ? (
                            <span style={{
                              opacity: 0.95, fontFamily: FM, fontWeight: 700,
                              color: trendMonth >= 0 ? "rgba(255,255,255,0.98)" : "rgba(255,215,215,0.95)"
                            }} className="tabular-nums">
                              {trendMonth > 0 ? "↗ +" : trendMonth < 0 ? "↘ " : "→ "}{trendMonth.toFixed(1)}%
                            </span>
                          ) : (
                            <span style={{ opacity: 0.4, fontFamily: FM }}>—</span>
                          )}
                        </div>
                      </div>

                      {/* Target progress (статик эсвэл динамик) */}
                      {((kpi.target) || (kpi.target_source_kpi_id && kpi.target_percent)) && entries.length > 0 ? (() => {
                        let targetTotal = 0;
                        // 🎯 Динамик зорилт — эх KPI-ийн entries-аас шууд тооцох
                        if (kpi.target_source_kpi_id && kpi.target_percent) {
                          const sourceEntries = filteredEntries.filter(e => e.kpi_id === kpi.target_source_kpi_id);
                          const sourceTotal = sourceEntries.reduce((s, e) => s + Number(e.value || 0), 0);
                          targetTotal = (sourceTotal * Number(kpi.target_percent)) / 100;
                        } else if (kpi.target) {
                          // Статик зорилт
                          targetTotal = Number(kpi.target);
                          if (kpi.target_period === "daily") {
                            const days = Math.max(1, Math.ceil((new Date(periodRange.end) - new Date(periodRange.start)) / 86400000) + 1);
                            targetTotal = Number(kpi.target) * days;
                          } else if (kpi.target_period === "weekly") {
                            const weeks = Math.max(1, Math.ceil((new Date(periodRange.end) - new Date(periodRange.start)) / (7 * 86400000)));
                            targetTotal = Number(kpi.target) * weeks;
                          }
                        }
                        if (targetTotal <= 0) return null;
                        const percent = targetTotal > 0 ? (total / targetTotal) * 100 : 0;
                        const isDynamic = kpi.target_source_kpi_id && kpi.target_percent;
                        return (
                          <div className="mt-1.5">
                            <div className="flex items-center justify-between text-[9px] mb-1">
                              <span style={{ opacity: 0.85, fontFamily: FM }}>
                                {isDynamic ? "🎯⚡" : "🎯"} {Math.round(targetTotal).toLocaleString()}
                              </span>
                              <span style={{ opacity: 0.95, fontFamily: FM, fontWeight: 600 }}>
                                {percent.toFixed(0)}%
                              </span>
                            </div>
                            <div style={{ background: "rgba(255,255,255,0.25)", height: 3, borderRadius: 999, overflow: "hidden" }}>
                              <div style={{
                                width: `${Math.min(percent, 100)}%`,
                                height: "100%",
                                background: "white",
                                transition: "width 0.5s ease",
                              }} />
                            </div>
                          </div>
                        );
                      })() : (
                        <div style={{ opacity: 0.7, fontFamily: FM }} className="text-[9px] mt-1.5">
                          {entries.length} өдрийн нийт
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
              )}
            </div>
          );
        })
      )}

      {confirmDelKpi && (
        <Modal onClose={() => setConfirmDelKpi(null)} title="KPI устгах уу?" maxW="max-w-sm">
          <p style={{ color: T.muted }} className="text-sm mb-5">
            <strong style={{ color: T.ink }}>{confirmDelKpi.name}</strong> KPI болон бүх оруулсан тоонууд устгагдана.
          </p>
          <div className="flex gap-3">
            <button onClick={() => setConfirmDelKpi(null)}
              className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-sm"
              style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
            <button onClick={() => { onDeleteKpi(confirmDelKpi.id); setConfirmDelKpi(null); }}
              className="glow-danger press-btn flex-1 py-2.5 rounded-xl text-sm font-medium"
              style={{ fontFamily: FS }}>Устгах</button>
          </div>
        </Modal>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  KPI DEFINITION FORM (admin)
// ═══════════════════════════════════════════════════════════════════════════
function KpiDefFormModal({ mode, kpi, departments, allKpis = [], onSave, onClose }) {
  const [name, setName] = useState(kpi?.name || "");
  const [unit, setUnit] = useState(kpi?.unit || "");
  const [departmentId, setDepartmentId] = useState(kpi?.department_id || (departments[0]?.id || ""));
  const [category, setCategory] = useState(kpi?.category || "");
  const [order, setOrder] = useState(kpi?.display_order || 0);
  const [target, setTarget] = useState(kpi?.target ? String(kpi.target) : "");
  const [targetPeriod, setTargetPeriod] = useState(kpi?.target_period || "daily");
  // 🎯 Динамик зорилт (өөр KPI-ээс)
  const [targetSourceKpiId, setTargetSourceKpiId] = useState(kpi?.target_source_kpi_id || "");
  const [targetPercent, setTargetPercent] = useState(kpi?.target_percent ? String(kpi.target_percent) : "");
  const [kpiType, setKpiType] = useState(kpi?.kpi_type || "input");
  const [numeratorId, setNumeratorId] = useState(
    kpi?.formula?.numerator_id || kpi?.formula?.source_id || ""
  );
  const [denominatorId, setDenominatorId] = useState(kpi?.formula?.denominator_id || "");
  const [operator, setOperator] = useState(kpi?.formula?.operator || "divide");
  const [decimals, setDecimals] = useState(kpi?.decimals ?? 2);
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  // Энэ хэлтсийн KPI-уудаас сонгох (өөрөөсөө бусад)
  // Бүх хэлтсийн KPI-уудаас сонгох (хэлтэс бүрээр бүлэглэсэн)
  const allInputKpis = allKpis.filter((k) => k.id !== kpi?.id && k.kpi_type !== "calculated");
  const kpisByDept = useMemo(() => {
    const grouped = {};
    allInputKpis.forEach((k) => {
      const dept = departments.find((d) => d.id === k.department_id);
      const deptName = dept?.name || "Бусад";
      if (!grouped[deptName]) grouped[deptName] = [];
      grouped[deptName].push(k);
    });
    return grouped;
  }, [allInputKpis, departments]);

  const submit = async () => {
    setErr("");
    if (!name.trim()) return setErr("KPI-ийн нэр оруулна уу");
    if (!departmentId) return setErr("Хэлтэс сонгоно уу");
    if (kpiType === "calculated" && (!numeratorId || !denominatorId)) {
      return setErr("Тооцооллын KPI: эх KPI-ууд сонгоно уу");
    }
    setBusy(true);
    await onSave({
      id: kpi?.id || null,
      department_id: departmentId,
      name: name.trim(),
      unit: unit.trim(),
      category: category.trim() || null,
      display_order: parseInt(order) || 0,
      target: target ? Number(target) : null,
      target_period: targetPeriod,
      // 🎯 Динамик зорилт
      target_source_kpi_id: targetSourceKpiId || null,
      target_percent: targetPercent ? Number(targetPercent) : null,
      kpi_type: kpiType,
      formula: kpiType === "calculated" ? {
        numerator_id: numeratorId,
        denominator_id: denominatorId,
        operator,
      } : kpiType === "copy" ? {
        source_id: numeratorId,
      } : null,
      decimals: parseInt(decimals) || 0,
    });
    setBusy(false);
  };

  return (
    <Modal onClose={onClose} title={mode === "add" ? "KPI нэмэх" : "KPI засах"}>
      <div className="space-y-4">
        <Field label="Хэлтэс" required>
          <select value={departmentId} onChange={(e) => setDepartmentId(e.target.value)}
            disabled={mode === "edit"}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none disabled:opacity-60">
            <option value="">— Сонгох —</option>
            {departments.map((d) => (
              <option key={d.id} value={d.id}>{d.name}</option>
            ))}
          </select>
        </Field>

        <Field label="KPI нэр" required>
          <Input value={name} onChange={setName} placeholder="Жишээ: Хандалт, Захиалга" autoFocus />
        </Field>

        {/* KPI төрөл сонгох */}
        <Field label="KPI төрөл">
          <div className="grid grid-cols-3 gap-2">
            <button type="button" onClick={() => setKpiType("input")}
              className={`press-btn px-3 py-2.5 rounded-lg text-xs ${kpiType === "input" ? "tab-active" : "tab-inactive glass-soft"}`}
              style={{ fontFamily: FM, border: "1px solid", borderColor: kpiType === "input" ? "transparent" : T.borderSoft }}>
              ✍ Гар оруулах
            </button>
            <button type="button" onClick={() => setKpiType("calculated")}
              className={`press-btn px-3 py-2.5 rounded-lg text-xs ${kpiType === "calculated" ? "tab-active" : "tab-inactive glass-soft"}`}
              style={{ fontFamily: FM, border: "1px solid", borderColor: kpiType === "calculated" ? "transparent" : T.borderSoft }}>
              🧮 Тооцоолох
            </button>
            <button type="button" onClick={() => setKpiType("copy")}
              className={`press-btn px-3 py-2.5 rounded-lg text-xs ${kpiType === "copy" ? "tab-active" : "tab-inactive glass-soft"}`}
              style={{ fontFamily: FM, border: "1px solid", borderColor: kpiType === "copy" ? "transparent" : T.borderSoft }}>
              📋 Хуулах
            </button>
          </div>
        </Field>

        {/* Хуулах KPI бол өөр KPI сонгох */}
        {kpiType === "copy" && (
          <div className="glass-soft rounded-lg p-3 space-y-2">
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mb-1">
              📋 Хуулах KPI сонгох
            </div>
            <select value={numeratorId} onChange={(e) => setNumeratorId(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-2 py-2.5 rounded-lg border text-xs outline-none">
              <option value="">— Сонгох —</option>
              {Object.entries(kpisByDept).map(([deptName, kpis]) => (
                <optgroup key={deptName} label={`📂 ${deptName}`}>
                  {kpis.map((k) => (
                    <option key={k.id} value={k.id}>{k.name}</option>
                  ))}
                </optgroup>
              ))}
            </select>
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] italic">
              💡 Сонгосон KPI-ийн утга энэ KPI-руу автомат хуулагдана. Тус бүр өөрчлөгдөхөд автомат шинэчлэгдэнэ.
            </div>
          </div>
        )}

        {/* Тооцооллын KPI бол формула UI */}
        {kpiType === "calculated" && (
          <div className="glass-soft rounded-lg p-3 space-y-2">
            <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider mb-1">
              🧮 Формул (бүх хэлтсийн KPI-аас сонгож болно)
            </div>
            <div className="grid grid-cols-[1fr_auto_1fr] gap-2 items-center">
              <select value={numeratorId} onChange={(e) => setNumeratorId(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-2 py-2 rounded-lg border text-xs outline-none">
                <option value="">— Сонгох —</option>
                {Object.entries(kpisByDept).map(([deptName, kpis]) => (
                  <optgroup key={deptName} label={`📂 ${deptName}`}>
                    {kpis.map((k) => (
                      <option key={k.id} value={k.id}>{k.name}</option>
                    ))}
                  </optgroup>
                ))}
              </select>
              <select value={operator} onChange={(e) => setOperator(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM, fontSize: 18, fontWeight: 600 }}
                className="px-2 py-2 rounded-lg border outline-none text-center">
                <option value="divide">÷</option>
                <option value="multiply">×</option>
                <option value="add">+</option>
                <option value="subtract">−</option>
              </select>
              <select value={denominatorId} onChange={(e) => setDenominatorId(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="px-2 py-2 rounded-lg border text-xs outline-none">
                <option value="">— Сонгох —</option>
                {Object.entries(kpisByDept).map(([deptName, kpis]) => (
                  <optgroup key={deptName} label={`📂 ${deptName}`}>
                    {kpis.map((k) => (
                      <option key={k.id} value={k.id}>{k.name}</option>
                    ))}
                  </optgroup>
                ))}
              </select>
            </div>

            {/* Хэлтэс хоорондын тооцоолол байгаа эсэхийг харуулах */}
            {numeratorId && denominatorId && (() => {
              const num = allInputKpis.find((k) => k.id === numeratorId);
              const den = allInputKpis.find((k) => k.id === denominatorId);
              if (!num || !den) return null;
              const numDept = departments.find((d) => d.id === num.department_id);
              const denDept = departments.find((d) => d.id === den.department_id);
              const sameDept = num.department_id === den.department_id;
              return (
                <div style={{ background: sameDept ? T.highlightSoft : "rgba(245,158,11,0.1)", color: sameDept ? T.highlight : T.warn, fontFamily: FM }}
                     className="text-[10px] px-2 py-1.5 rounded">
                  {sameDept ? "✓" : "🔀"} {numDept?.name || "?"} · {num.name}
                  {" "}{operator === "divide" ? "÷" : operator === "multiply" ? "×" : operator === "add" ? "+" : "−"}{" "}
                  {denDept?.name || "?"} · {den.name}
                  {!sameDept && " (хэлтэс хооронд)"}
                </div>
              );
            })()}

            <div style={{ color: T.muted, fontFamily: FM }} className="text-[9px] mt-1">
              💡 Энэ KPI-д хүн утга оруулахгүй — автомат тооцоолно
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-3">
          <Field label="Хэмжих нэгж">
            <Input value={unit} onChange={setUnit} placeholder="₮, тоо, %" />
          </Field>
          {kpiType === "calculated" ? (
            <Field label="Аравтын орон">
              <Input value={String(decimals)} onChange={setDecimals} type="number" placeholder="2" />
            </Field>
          ) : (
            <Field label="Дараалал">
              <Input value={String(order)} onChange={setOrder} type="number" placeholder="0" />
            </Field>
          )}
        </div>

        <div className="grid grid-cols-2 gap-3">
          <Field label="🎯 Зорилт (заавал биш)">
            <Input value={target} onChange={setTarget} type="number" placeholder="14581" />
          </Field>
          <Field label="Зорилтын хугацаа">
            <select value={targetPeriod} onChange={(e) => setTargetPeriod(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none">
              <option value="daily">Өдөр бүр</option>
              <option value="weekly">7 хоног бүр</option>
              <option value="monthly">Сар бүр</option>
            </select>
          </Field>
        </div>

        {/* 🎯 Динамик зорилт — өөр KPI-ээс */}
        <div className="rounded-xl p-3" style={{ background: "rgba(245,158,11,0.06)", border: `1px solid ${T.warn}33` }}>
          <div style={{ color: T.warn, fontFamily: FS, fontWeight: 700 }} className="text-xs mb-2 flex items-center gap-1.5">
            🎯 Динамик зорилт (өөр KPI-ээс)
          </div>
          <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] mb-2">
            Зорилтыг өөр KPI-ийн утгаас % хувиар тооцоолно. Жнь: Захиалга = Дуудлагын 30%
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-2">
            <Field label="Эх KPI">
              <select value={targetSourceKpiId} onChange={(e) => setTargetSourceKpiId(e.target.value)}
                style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none">
                <option value="">— Сонгох —</option>
                {Object.entries(kpisByDept).map(([deptName, kpis]) => (
                  <optgroup key={deptName} label={deptName}>
                    {kpis.map((k) => (
                      <option key={k.id} value={k.id}>{k.name}</option>
                    ))}
                  </optgroup>
                ))}
              </select>
            </Field>
            <Field label="Хувь (%)">
              <Input value={targetPercent} onChange={setTargetPercent} type="number" placeholder="30" />
            </Field>
          </div>
          {targetSourceKpiId && targetPercent && (
            <div style={{ color: T.ok, fontFamily: FM }} className="text-[11px] mt-2">
              ✅ Зорилт = {allKpis.find((k) => k.id === targetSourceKpiId)?.name || "?"} × {targetPercent}%
            </div>
          )}
          {targetSourceKpiId && !targetPercent && (
            <div style={{ color: T.err, fontFamily: FM }} className="text-[11px] mt-2">
              ⚠ Хувийн утга оруулна уу
            </div>
          )}
        </div>

        <Field label="Бүлэг (заавал биш)">
          <Input value={category} onChange={setCategory} placeholder="sales, operations" />
        </Field>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium"
            style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
          <button onClick={submit} disabled={busy}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2"
            style={{ fontFamily: FS }}>
            {busy && <Loader2 size={13} className="spin" />}
            Хадгалах
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  KPI ENTRY FORM (manager / admin daily input)
// ═══════════════════════════════════════════════════════════════════════════
function KpiEntryFormModal({ department, kpiDefs, existingEntries, onSave, onClose }) {
  const today = new Date().toISOString().slice(0, 10);
  const [date, setDate] = useState(today);
  const [values, setValues] = useState({});
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  // Зөвхөн input KPI-уудыг харуулах (calculated болон copy биш)
  const inputKpis = kpiDefs.filter((k) => k.kpi_type !== "calculated" && k.kpi_type !== "copy");

  // Date солигдох тоолон утгуудыг ачаалах
  useEffect(() => {
    const initial = {};
    inputKpis.forEach((k) => {
      const existing = existingEntries.find(e => e.kpi_id === k.id && e.entry_date === date);
      initial[k.id] = existing ? String(existing.value) : "";
    });
    setValues(initial);
  }, [date, inputKpis.length]);

  const submit = async (advanceDay = false) => {
    setErr("");
    const entries = Object.entries(values)
      .filter(([_, v]) => v !== "" && !isNaN(Number(v)))
      .map(([kpi_id, v]) => ({ kpi_id, value: Number(v) }));
    if (entries.length === 0) return setErr("Ядаж нэг тоо оруулна уу");
    setBusy(true);
    await onSave(department.id, date, entries, advanceDay); // advanceDay=true бол modal хаахгүй
    setBusy(false);
    if (advanceDay) {
      // 📅 Дараагийн өдөр рүү шилжих — огноог +1 хоног, талбаруудыг цэвэрлэх
      const next = new Date(date + "T00:00:00");
      next.setDate(next.getDate() + 1);
      const nextStr = next.toISOString().slice(0, 10);
      setDate(nextStr);
      // values нь date useEffect-ээр шинэ огооны хуучин утгаар (байвал) дүүрнэ
      setErr("");
    }
  };

  return (
    <Modal onClose={onClose} title={`${department.name} · KPI оруулах`} maxW="max-w-lg">
      <div className="space-y-4">
        <Field label="Огноо" required>
          <input type="date" value={date} onChange={(e) => setDate(e.target.value)}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none" />
        </Field>

        <div className="space-y-2 max-h-[50vh] overflow-y-auto">
          {inputKpis.length === 0 ? (
            <div className="glass-soft rounded-xl p-4 text-center">
              <p style={{ color: T.muted }} className="text-sm">Энэ хэлтэст KPI тохируулаагүй байна</p>
            </div>
          ) : (
            inputKpis.map((k) => (
              <div key={k.id} className="glass-soft rounded-xl p-3 flex items-center gap-3">
                <div className="flex-1 min-w-0">
                  <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-sm truncate">{k.name}</div>
                  {k.unit && <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">{k.unit}</div>}
                </div>
                <input type="number" step="any" value={values[k.id] || ""}
                  onChange={(e) => setValues({ ...values, [k.id]: e.target.value })}
                  placeholder="0"
                  style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
                  className="w-32 px-3 py-2 rounded-lg border text-sm outline-none text-right tabular-nums" />
              </div>
            ))
          )}
        </div>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium"
            style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
          <button onClick={submit} disabled={busy || inputKpis.length === 0}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2"
            style={{ fontFamily: FS }}>
            {busy && <Loader2 size={13} className="spin" />}
            Хадгалах
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  KPI CHART VIEW — Чартаар харах
// ═══════════════════════════════════════════════════════════════════════════
// ─── 📝 KPI Chart-ийн гар тайлбар хэсэг ──────────────────────────────
function ChartNoteSection({ note, setNote, editingNote, setEditingNote, savingNote, saveNote, canEdit, singleDayTotals, multiDayTotals, periodLabel, chartType }) {
  return (
    <div className="glass-soft rounded-2xl p-3">
      {/* Header */}
      <div className="flex items-center justify-between mb-2">
        <div style={{ color: T.ink, fontFamily: FS, fontWeight: 700 }} className="text-sm flex items-center gap-2">
          📝 Тайлбар
        </div>
        {canEdit && !editingNote && (
          <button onClick={() => setEditingNote(true)}
            className="press-btn text-[11px] px-2 py-1 rounded-lg flex items-center gap-1"
            style={{ background: T.surfaceAlt, color: T.ink, fontFamily: FS, fontWeight: 600 }}>
            ✏ {note ? "Засах" : "Бичих"}
          </button>
        )}
      </div>

      {/* Тайлбарын текст эсвэл edit mode */}
      {editingNote ? (
        <div className="space-y-2">
          <textarea
            value={note}
            onChange={(e) => setNote(e.target.value)}
            placeholder="Энэ хэлтсийн KPI үзүүлэлтийн талаар тайлбар бичих... (жнь: '5-р сарын зорилго 1000 захиалга', 'Шинээр нэмэгдсэн KPI: Засварын тоо')"
            rows={3}
            className="w-full px-3 py-2 rounded-lg text-xs resize-y"
            style={{ background: T.surfaceAlt, color: T.ink, border: `1px solid ${T.border}`, fontFamily: FS, minHeight: 60 }}
            autoFocus
          />
          <div className="flex items-center gap-2">
            <button onClick={saveNote} disabled={savingNote}
              className="press-btn glow-primary px-3 py-1.5 rounded-lg text-xs flex items-center gap-1.5"
              style={{ fontFamily: FS, fontWeight: 600 }}>
              {savingNote ? (
                <><Loader2 size={12} className="spin" /> Хадгалж байна...</>
              ) : (
                <>💾 Хадгалах</>
              )}
            </button>
            <button onClick={() => setEditingNote(false)} disabled={savingNote}
              className="press-btn px-3 py-1.5 rounded-lg text-xs"
              style={{ background: T.surfaceAlt, color: T.muted, fontFamily: FS, fontWeight: 600 }}>
              ✕ Болих
            </button>
            <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] ml-auto">
              {note.length} тэмдэгт
            </span>
          </div>
        </div>
      ) : (
        <>
          {/* Гарын тайлбар */}
          {note ? (
            <div style={{ color: T.ink, fontFamily: FS, lineHeight: 1.5, whiteSpace: "pre-wrap" }} className="text-xs">
              {note}
            </div>
          ) : (
            <div style={{ color: T.muted, fontFamily: FM, fontStyle: "italic" }} className="text-[11px]">
              {canEdit ? "Тайлбар бичээгүй байна — ✏ товчийг дарж нэмнэ үү" : "Тайлбар оруулаагүй байна"}
            </div>
          )}

          {/* Доор автомат статистик */}
          <div style={{ borderTop: `1px dashed ${T.borderSoft}`, color: T.muted, fontFamily: FM }}
            className="mt-2 pt-2 text-[10px] flex items-center gap-2 flex-wrap">
            {singleDayTotals && (
              <>
                <span>📅 Нэг өдөр</span>
                <span>·</span>
                <span>{singleDayTotals.count} үзүүлэлт</span>
                <span>·</span>
                <span>Нийт: <b style={{ color: T.ink }}>{singleDayTotals.total.toLocaleString()}</b></span>
                {singleDayTotals.max?.value > 0 && (
                  <>
                    <span>·</span>
                    <span>🏆 {singleDayTotals.max.name} ({singleDayTotals.max.value.toLocaleString()})</span>
                  </>
                )}
              </>
            )}
            {multiDayTotals && (
              <>
                <span>📅 {multiDayTotals.periods} {periodLabel}</span>
                <span>·</span>
                <span>Нийт: <b style={{ color: T.ink }}>{multiDayTotals.totalSum.toLocaleString()}</b></span>
                {multiDayTotals.topKpiTotal > 0 && (
                  <>
                    <span>·</span>
                    <span>🏆 {multiDayTotals.topKpiName} ({multiDayTotals.topKpiTotal.toLocaleString()})</span>
                  </>
                )}
                <span>·</span>
                <span>📈 {chartType === "line" ? "Шугаман" : chartType === "area" ? "Талбайн" : "Багана"}</span>
              </>
            )}
          </div>
        </>
      )}
    </div>
  );
}

function KpiChartView({ deptKpis, filteredEntries, allEntries, periodRange, chartType, groupBy = "day", anchorDate, departmentId, initialNote = "", canEdit = false, onNoteSaved }) {
  const COLORS = ["#6366f1", "#10b981", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#14b8a6", "#f97316"];

  // 📝 Гар тайлбар state
  const [note, setNote] = useState(initialNote || "");
  const [editingNote, setEditingNote] = useState(false);
  const [savingNote, setSavingNote] = useState(false);

  // initialNote prop өөрчлөгдөхөд state шинэчлэх
  useEffect(() => {
    setNote(initialNote || "");
  }, [initialNote, departmentId]);

  const saveNote = async () => {
    if (!departmentId) return;
    setSavingNote(true);
    try {
      const { error } = await supabase.from("departments")
        .update({ chart_notes: note.trim() || null })
        .eq("id", departmentId);
      if (error) throw error;
      setEditingNote(false);
      if (onNoteSaved) onNoteSaved(departmentId, note.trim() || "");
    } catch (e) {
      alert("Хадгалахад алдаа: " + e.message);
      logErr("[saveNote]", e);
    } finally {
      setSavingNote(false);
    }
  };

  // 🗓 Anchor огноо: хэрэв хэлтсийн anchor өгөгдсөн бол түүнийг, эс бол period-ийн төгсгөл
  const effectiveAnchor = useMemo(() => {
    if (anchorDate) return new Date(anchorDate + "T00:00:00");
    return new Date(periodRange.end);
  }, [anchorDate, periodRange.end]);

  // Огнооны массив (start-аас end хүртэл) — өдөр бүрд
  const dateList = useMemo(() => {
    const list = [];
    const start = new Date(periodRange.start);
    const end = new Date(periodRange.end);
    const cur = new Date(start);
    while (cur <= end) {
      list.push(cur.toISOString().slice(0, 10));
      cur.setDate(cur.getDate() + 1);
    }
    return list;
  }, [periodRange]);

  // ─────────────────────────────────────────────────────────────────────────
  // Helper: KPI-ийн нийт дүн (date range дотор) — calculated/copy/normal KPI support
  // ─────────────────────────────────────────────────────────────────────────
  const computeKpiValue = (kpi, entries, startISO, endISO) => {
    const inRange = (e, id) => e.kpi_id === id && e.entry_date >= startISO && e.entry_date <= endISO;
    if (kpi.kpi_type === "calculated" && kpi.formula?.numerator_id && kpi.formula?.denominator_id) {
      const n = entries.filter(e => inRange(e, kpi.formula.numerator_id)).reduce((s, e) => s + Number(e.value), 0);
      const d = entries.filter(e => inRange(e, kpi.formula.denominator_id)).reduce((s, e) => s + Number(e.value), 0);
      const op = kpi.formula.operator;
      if (op === "divide") return d === 0 ? 0 : n / d;
      if (op === "multiply") return n * d;
      if (op === "add") return n + d;
      if (op === "subtract") return n - d;
      return 0;
    }
    if (kpi.kpi_type === "copy" && kpi.formula?.source_id) {
      return entries.filter(e => inRange(e, kpi.formula.source_id)).reduce((s, e) => s + Number(e.value), 0);
    }
    return entries.filter(e => inRange(e, kpi.id)).reduce((s, e) => s + Number(e.value), 0);
  };

  // ─────────────────────────────────────────────────────────────────────────
  // Chart data: groupBy-аас хамаарч
  //   "day"   → өдөр бүр (хуучин логик)
  //   "week"  → сүүлийн 5 долоо хоног (anchor-аас 7-7 хоногоор)
  //   "month" → сүүлийн 5 сар
  // ─────────────────────────────────────────────────────────────────────────
  const fmtDate = (d) => d.toISOString().slice(0, 10);

  const chartData = useMemo(() => {
    // 📆 СҮҮЛИЙН 5 САР
    if (groupBy === "month") {
      const anchor = effectiveAnchor;
      const rows = [];
      for (let i = 4; i >= 0; i--) {
        const monthStart = new Date(anchor.getFullYear(), anchor.getMonth() - i, 1);
        const monthEnd = new Date(anchor.getFullYear(), anchor.getMonth() - i + 1, 0);
        const label = `${monthStart.getFullYear()}-${String(monthStart.getMonth() + 1).padStart(2, "0")}`;
        const row = { date: label };
        deptKpis.forEach((kpi) => {
          row[kpi.name] = computeKpiValue(kpi, allEntries || [], fmtDate(monthStart), fmtDate(monthEnd));
        });
        rows.push(row);
      }
      return rows;
    }

    // 🗓 СҮҮЛИЙН 5 ДОЛОО ХОНОГ — anchor-аас (сонгосон огноо) 7-7 хоногоор
    if (groupBy === "week") {
      const anchor = effectiveAnchor;
      const rows = [];
      for (let i = 4; i >= 0; i--) {
        // Week i: anchor - (i+1)*7 + 1 ... anchor - i*7
        const wEnd = new Date(anchor);
        wEnd.setDate(wEnd.getDate() - i * 7);
        const wStart = new Date(wEnd);
        wStart.setDate(wStart.getDate() - 6);
        const label = `${String(wStart.getMonth() + 1).padStart(2, "0")}-${String(wStart.getDate()).padStart(2, "0")} → ${String(wEnd.getMonth() + 1).padStart(2, "0")}-${String(wEnd.getDate()).padStart(2, "0")}`;
        const row = { date: label };
        deptKpis.forEach((kpi) => {
          row[kpi.name] = computeKpiValue(kpi, allEntries || [], fmtDate(wStart), fmtDate(wEnd));
        });
        rows.push(row);
      }
      return rows;
    }

    // 📅 ӨДӨР БҮР (default — period-ийн зурвас дотор)
    return dateList.map((date) => {
      const row = { date: date.slice(5) }; // MM-DD
      deptKpis.forEach((kpi) => {
        // 🔧 Calculated/copy KPI-руу computeKpiValue ашиглах
        if (kpi.kpi_type === "calculated" || kpi.kpi_type === "copy") {
          row[kpi.name] = computeKpiValue(kpi, allEntries || filteredEntries, date, date);
        } else {
          const entry = filteredEntries.find(e => e.kpi_id === kpi.id && e.entry_date === date);
          row[kpi.name] = entry ? Number(entry.value) : 0;
        }
      });
      return row;
    });
  }, [dateList, deptKpis, filteredEntries, allEntries, groupBy, effectiveAnchor]);

  // Хэрэв нэг өдөр л байгаа бол bar chart харуулах (KPI бүрд) — зөвхөн day grouping үед
  const isSingleDay = groupBy === "day" && dateList.length === 1;

  if (deptKpis.length === 0) {
    return (
      <div className="glass-soft rounded-xl p-8 text-center" style={{ color: T.muted }}>
        <p className="text-sm">KPI байхгүй</p>
      </div>
    );
  }

  if (filteredEntries.length === 0 && groupBy === "day") {
    return (
      <div className="glass-soft rounded-xl p-8 text-center" style={{ color: T.muted }}>
        <p className="text-sm">Сонгосон хугацаанд тоо оруулаагүй байна</p>
      </div>
    );
  }

  if ((groupBy === "week" || groupBy === "month") && (!allEntries || allEntries.length === 0)) {
    return (
      <div className="glass-soft rounded-xl p-8 text-center" style={{ color: T.muted }}>
        <p className="text-sm">Тоон утга оруулаагүй байна</p>
      </div>
    );
  }

  // Single day → 1 bar chart with all KPIs as bars
  if (isSingleDay) {
    const singleDayDate = dateList[0];
    const singleDayData = deptKpis.map((kpi, i) => {
      // 🔧 Calculated/copy KPI-руу computeKpiValue ашиглах
      let kpiValue = 0;
      if (kpi.kpi_type === "calculated" || kpi.kpi_type === "copy") {
        kpiValue = computeKpiValue(kpi, allEntries || filteredEntries, singleDayDate, singleDayDate);
      } else {
        const entry = filteredEntries.find(e => e.kpi_id === kpi.id);
        kpiValue = entry ? Number(entry.value) : 0;
      }
      // 🎯 Динамик зорилт — эх KPI-ийн entry-аас тооцоолох
      let dailyTarget = 0;
      if (kpi.target_source_kpi_id && kpi.target_percent) {
        const sourceEntry = filteredEntries.find(e => e.kpi_id === kpi.target_source_kpi_id);
        const sourceValue = sourceEntry ? Number(sourceEntry.value) : 0;
        dailyTarget = (sourceValue * Number(kpi.target_percent)) / 100;
      } else if (kpi.target) {
        const t = Number(kpi.target);
        if (kpi.target_period === "daily") dailyTarget = t;
        else if (kpi.target_period === "weekly") dailyTarget = t / 7;
        else if (kpi.target_period === "monthly") dailyTarget = t / 30;
      }
      return {
        name: kpi.name,
        value: kpiValue,
        target: Math.round(dailyTarget),
        unit: kpi.unit,
        color: COLORS[i % COLORS.length],
      };
    });

    const totalSingleDay = singleDayData.reduce((s, d) => s + d.value, 0);
    const maxKpi = singleDayData.reduce((m, d) => d.value > m.value ? d : m, singleDayData[0] || { name: "—", value: 0 });

    return (
      <div className="space-y-3">
        {/* 📝 Гар тайлбар хэсэг */}
        <ChartNoteSection
          note={note}
          setNote={setNote}
          editingNote={editingNote}
          setEditingNote={setEditingNote}
          savingNote={savingNote}
          saveNote={saveNote}
          canEdit={canEdit}
          singleDayTotals={{ total: totalSingleDay, max: maxKpi, count: deptKpis.length }}
        />

        {/* 📈 Chart — Утгуудтай label-тай + Зорилт */}
        <div className="glass-soft rounded-2xl p-4">
          <ResponsiveContainer width="100%" height={320}>
            <BarChart data={singleDayData} margin={{ top: 25, right: 15, left: 0, bottom: 5 }}>
              <CartesianGrid strokeDasharray="3 3" stroke="rgba(99,102,241,0.1)" />
              <XAxis dataKey="name" tick={{ fontSize: 11 }} />
              <YAxis tick={{ fontSize: 11 }} />
              <RechartsTooltip 
                contentStyle={{ background: "rgba(255,255,255,0.95)", border: "1px solid rgba(99,102,241,0.2)", borderRadius: 12 }}
                formatter={(value, name, props) => {
                  const target = props.payload?.target || 0;
                  const pct = target > 0 ? Math.round((value / target) * 100) : 0;
                  return [
                    `${value.toLocaleString()}${target > 0 ? ` / ${target.toLocaleString()} (${pct}%)` : ""}`,
                    "Хэмжээ"
                  ];
                }}
              />
              <Bar dataKey="value" radius={[8, 8, 0, 0]}>
                {singleDayData.map((entry, i) => (
                  <Cell key={i} fill={entry.color} />
                ))}
                <LabelList dataKey="value" position="top"
                  style={{ fontSize: 12, fontWeight: 700, fill: T.ink }}
                  formatter={(v) => v > 0 ? v.toLocaleString() : ""} />
              </Bar>
              {/* 🎯 Зорилт reference dot/line — KPI бүрд */}
              <Bar dataKey="target" fill="transparent" stroke="none" radius={[0, 0, 0, 0]}>
                <LabelList dataKey="target" position="insideTop"
                  style={{ fontSize: 9, fontWeight: 700, fill: T.warn }}
                  formatter={(v) => v > 0 ? `🎯 ${v.toLocaleString()}` : ""} />
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    );
  }

  // Multi-day — line/bar/area chart with date axis
  const ChartComponent = chartType === "line" ? LineChart : chartType === "area" ? AreaChart : BarChart;
  const DataComponent = chartType === "line" ? Line : chartType === "area" ? Area : Bar;

  // ─────────────────────────────────────────────────────────────────────────
  // 📊 KPI бүрийн өсөлт/бууралтын дүгнэлт (зөвхөн week/month grouping үед)
  // Бүх 5 период + сүүлийн өөрчлөлтийг тооцох
  // ─────────────────────────────────────────────────────────────────────────
  const kpiChanges = useMemo(() => {
    if (groupBy === "day" || chartData.length < 2) return null;
    const lastRow = chartData[chartData.length - 1];   // Хамгийн сүүлийн период
    const prevRow = chartData[chartData.length - 2];   // Өмнөх период
    return deptKpis.map((kpi, i) => {
      const lastVal = Number(lastRow[kpi.name] || 0);
      const prevVal = Number(prevRow[kpi.name] || 0);
      const diff = lastVal - prevVal;
      const pct = prevVal > 0
        ? (diff / prevVal) * 100
        : (lastVal > 0 ? 100 : 0);

      // 📅 Бүх периодын утгууд + label-ууд
      const periods = chartData.map((row, idx) => {
        const val = Number(row[kpi.name] || 0);
        let pctVsPrev = null;
        if (idx > 0) {
          const prevP = Number(chartData[idx - 1][kpi.name] || 0);
          if (prevP > 0) pctVsPrev = ((val - prevP) / prevP) * 100;
          else if (val > 0) pctVsPrev = 100;
          else pctVsPrev = 0;
        }
        return { label: row.date, value: val, pctVsPrev };
      });

      return {
        id: kpi.id,
        name: kpi.name,
        unit: kpi.unit,
        decimals: kpi.decimals || 0,
        lastVal,
        prevVal,
        diff,
        pct,
        status: diff > 0 ? "up" : diff < 0 ? "down" : "flat",
        color: COLORS[i % COLORS.length],
        periods,
      };
    });
  }, [chartData, deptKpis, groupBy]);

  const summary = useMemo(() => {
    if (!kpiChanges) return null;
    const up = kpiChanges.filter(k => k.status === "up");
    const down = kpiChanges.filter(k => k.status === "down");
    const flat = kpiChanges.filter(k => k.status === "flat");
    const validPcts = kpiChanges.filter(k => k.prevVal > 0 || k.lastVal > 0).map(k => k.pct);
    const avgPct = validPcts.length > 0
      ? validPcts.reduce((s, v) => s + v, 0) / validPcts.length
      : 0;
    return { up, down, flat, avgPct };
  }, [kpiChanges]);

  const periodLabel = groupBy === "week" ? "долоо хоног" : groupBy === "month" ? "сар" : "өдөр";

  // 📊 График-ийн тоймийг бэлдэх
  const chartSummary = useMemo(() => {
    if (!chartData || chartData.length === 0) return null;
    const totalsByKpi = {};
    chartData.forEach((row) => {
      deptKpis.forEach((kpi) => {
        totalsByKpi[kpi.name] = (totalsByKpi[kpi.name] || 0) + (Number(row[kpi.name]) || 0);
      });
    });
    const topKpi = Object.entries(totalsByKpi).sort((a, b) => b[1] - a[1])[0];
    return {
      periods: chartData.length,
      topKpiName: topKpi?.[0] || "—",
      topKpiTotal: topKpi?.[1] || 0,
      totalSum: Object.values(totalsByKpi).reduce((s, v) => s + v, 0),
    };
  }, [chartData, deptKpis]);

  return (
    <div className="space-y-3">
      {/* 📝 Гар тайлбар хэсэг */}
      <ChartNoteSection
        note={note}
        setNote={setNote}
        editingNote={editingNote}
        setEditingNote={setEditingNote}
        savingNote={savingNote}
        saveNote={saveNote}
        canEdit={canEdit}
        multiDayTotals={chartSummary}
        periodLabel={periodLabel}
        chartType={chartType}
      />

      {/* Chart */}
      <div className="glass-soft rounded-2xl p-4">
        <ResponsiveContainer width="100%" height={350}>
          <ChartComponent data={chartData} margin={{ top: 25, right: 15, left: 0, bottom: 5 }}>
            <CartesianGrid strokeDasharray="3 3" stroke="rgba(99,102,241,0.1)" />
            <XAxis dataKey="date" tick={{ fontSize: 11 }} />
            <YAxis tick={{ fontSize: 11 }} />
            <RechartsTooltip contentStyle={{ background: "rgba(255,255,255,0.95)", border: "1px solid rgba(99,102,241,0.2)", borderRadius: 12 }} />
            <Legend wrapperStyle={{ fontSize: 11 }} />
            {/* 🎯 Зорилтын reference line — KPI бүрд (динамик эсвэл статик) */}
            {deptKpis.map((kpi, i) => {
              let perPeriodTarget = 0;
              if (kpi.target_source_kpi_id && kpi.target_percent) {
                // Динамик зорилт — эх KPI-ийн entries-аас тооцоолох
                const sourceEntries = filteredEntries.filter(e => e.kpi_id === kpi.target_source_kpi_id);
                const sourceTotal = sourceEntries.reduce((s, e) => s + Number(e.value || 0), 0);
                if (chartData.length > 0 && sourceTotal > 0) {
                  const sourceAvg = sourceTotal / chartData.length;
                  perPeriodTarget = Math.round((sourceAvg * Number(kpi.target_percent)) / 100);
                }
              } else if (kpi.target) {
                // Статик зорилт
                perPeriodTarget = Number(kpi.target);
                if (kpi.target_period === "daily" && groupBy === "week") perPeriodTarget *= 7;
                else if (kpi.target_period === "daily" && groupBy === "month") perPeriodTarget *= 30;
                else if (kpi.target_period === "weekly" && groupBy === "day") perPeriodTarget /= 7;
                else if (kpi.target_period === "weekly" && groupBy === "month") perPeriodTarget *= 4;
                else if (kpi.target_period === "monthly" && groupBy === "day") perPeriodTarget /= 30;
                else if (kpi.target_period === "monthly" && groupBy === "week") perPeriodTarget /= 4;
                perPeriodTarget = Math.round(perPeriodTarget);
              }
              if (perPeriodTarget <= 0) return null;
              return (
                <ReferenceLine
                  key={`target-${kpi.id}`}
                  y={perPeriodTarget}
                  stroke={COLORS[i % COLORS.length]}
                  strokeDasharray="5 5"
                  strokeWidth={1.5}
                  label={{
                    value: `🎯 ${kpi.name} (${perPeriodTarget.toLocaleString()})`,
                    position: "insideTopRight",
                    fontSize: 9,
                    fill: COLORS[i % COLORS.length],
                    fontWeight: 600,
                  }}
                />
              );
            })}
            {deptKpis.map((kpi, i) => (
              <DataComponent
                key={kpi.id}
                type="monotone"
                dataKey={kpi.name}
                stroke={COLORS[i % COLORS.length]}
                fill={COLORS[i % COLORS.length]}
                fillOpacity={chartType === "area" ? 0.3 : 1}
                radius={chartType === "bar" ? [4, 4, 0, 0] : 0}
                strokeWidth={chartType === "line" ? 2.5 : 1}
                dot={chartType === "line" ? { r: 3 } : false}
              >
                {/* 🏷 Тоон утга харуулна — bar/area chart-руу зөвхөн */}
                {chartType !== "line" && chartData.length <= 10 && (
                  <LabelList
                    dataKey={kpi.name}
                    position="top"
                    style={{ fontSize: 10, fontWeight: 600, fill: COLORS[i % COLORS.length] }}
                    formatter={(v) => v > 0 ? (v >= 1000 ? (v / 1000).toFixed(1) + "K" : v.toLocaleString()) : ""}
                  />
                )}
              </DataComponent>
            ))}
          </ChartComponent>
        </ResponsiveContainer>
      </div>

      {/* 📊 Summary section — Сүүлийн период vs өмнөх период */}
      {summary && kpiChanges && kpiChanges.length > 0 && (
        <div className="glass-soft rounded-2xl p-4 space-y-3">
          <div className="flex items-center justify-between flex-wrap gap-2">
            <div style={{ color: T.ink, fontFamily: FS, fontWeight: 600 }} className="text-sm">
              📊 Сүүлийн {periodLabel} vs өмнөх {periodLabel}
            </div>
            <div className="flex items-center gap-3 text-xs">
              <span style={{ color: T.ok, fontFamily: FM, fontWeight: 600 }}>
                ↗ {summary.up.length}
              </span>
              <span style={{ color: T.err, fontFamily: FM, fontWeight: 600 }}>
                ↘ {summary.down.length}
              </span>
              {summary.flat.length > 0 && (
                <span style={{ color: T.muted, fontFamily: FM, fontWeight: 600 }}>
                  → {summary.flat.length}
                </span>
              )}
              <span style={{
                color: summary.avgPct > 0 ? T.ok : summary.avgPct < 0 ? T.err : T.muted,
                fontFamily: FD, fontWeight: 700,
              }} className="text-sm">
                Дундаж: {summary.avgPct > 0 ? "+" : ""}{summary.avgPct.toFixed(1)}%
              </span>
            </div>
          </div>

          {/* KPI бүрийн өөрчлөлт — 5 период бүхэл утга */}
          <div className="space-y-2">
            {kpiChanges.map((k) => (
              <div key={k.id}
                className="rounded-xl p-3"
                style={{
                  background: k.status === "up" ? "rgba(16,185,129,0.05)"
                           : k.status === "down" ? "rgba(239,68,68,0.05)"
                           : "rgba(107,114,128,0.04)",
                  border: `1px solid ${
                    k.status === "up" ? "rgba(16,185,129,0.18)"
                    : k.status === "down" ? "rgba(239,68,68,0.18)"
                    : "rgba(107,114,128,0.12)"
                  }`,
                }}>
                {/* Header — KPI нэр + сүүлийн өөрчлөлт */}
                <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2 min-w-0 flex-1">
                    <div style={{ background: k.color, width: 8, height: 8, borderRadius: "50%", flexShrink: 0 }} />
                    <div style={{ color: T.ink, fontFamily: FM, fontWeight: 600 }} className="text-xs truncate" title={k.name}>
                      {k.name}
                      {k.unit && <span style={{ color: T.muted, fontWeight: 400 }} className="ml-1 text-[10px]">({k.unit})</span>}
                    </div>
                  </div>
                  <div style={{
                    color: k.status === "up" ? T.ok : k.status === "down" ? T.err : T.muted,
                    fontFamily: FD, fontWeight: 700,
                  }} className="text-sm tabular-nums whitespace-nowrap">
                    {k.status === "up" ? "↗ +" : k.status === "down" ? "↘ " : "→ "}
                    {k.pct.toFixed(1)}%
                  </div>
                </div>

                {/* 5 период — grid layout */}
                <div className="grid gap-1" style={{ gridTemplateColumns: `repeat(${k.periods.length}, minmax(0, 1fr))` }}>
                  {k.periods.map((p, idx) => {
                    const isLast = idx === k.periods.length - 1;
                    const isUp = p.pctVsPrev !== null && p.pctVsPrev > 0;
                    const isDown = p.pctVsPrev !== null && p.pctVsPrev < 0;
                    return (
                      <div key={idx}
                        className="rounded-lg p-1.5 text-center"
                        style={{
                          background: isLast ? "rgba(255,255,255,0.85)" : "rgba(255,255,255,0.5)",
                          border: isLast ? `1px solid ${k.color}` : "1px solid rgba(0,0,0,0.05)",
                        }}>
                        <div style={{ color: T.muted, fontFamily: FM }} className="text-[8px] uppercase tracking-tight mb-0.5">
                          {p.label}
                        </div>
                        <div style={{
                          color: T.ink,
                          fontFamily: FD,
                          fontWeight: isLast ? 700 : 600,
                        }} className="text-[11px] tabular-nums">
                          {p.value.toLocaleString(undefined, { maximumFractionDigits: k.decimals })}
                        </div>
                        {p.pctVsPrev !== null && (
                          <div style={{
                            color: isUp ? T.ok : isDown ? T.err : T.muted,
                            fontFamily: FM,
                            fontWeight: 600,
                          }} className="text-[9px] tabular-nums mt-0.5">
                            {isUp ? "↗+" : isDown ? "↘" : "→"}{p.pctVsPrev.toFixed(1)}%
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  TASKS — helpers
// ═══════════════════════════════════════════════════════════════════════════
const TASK_STATUS = {
  todo: { label: "Хийх", color: T.muted, bg: "rgba(107,114,128,0.1)", icon: "📋" },
  in_progress: { label: "Хийж буй", color: T.warn, bg: "rgba(245,158,11,0.12)", icon: "⚡" },
  done: { label: "Хийсэн", color: T.ok, bg: "rgba(16,185,129,0.12)", icon: "✅" },
};

const TASK_PRIORITY = {
  low: { label: "Бага", color: "#6b7280", bg: "rgba(107,114,128,0.12)" },
  medium: { label: "Дунд", color: "#3b82f6", bg: "rgba(59,130,246,0.12)" },
  high: { label: "Өндөр", color: "#f59e0b", bg: "rgba(245,158,11,0.15)" },
  urgent: { label: "Яаралтай", color: "#ef4444", bg: "rgba(239,68,68,0.15)" },
};

// ═══════════════════════════════════════════════════════════════════════════
//  TASKS VIEW (admin/manager) — Kanban
// ═══════════════════════════════════════════════════════════════════════════
function TasksView({ tasks, departments, employees, currentUserId, isAdmin, onAdd, onEdit, onDelete, onUpdateStatus }) {
  const [selectedDept, setSelectedDept] = useState("all");
  const [confirmDel, setConfirmDel] = useState(null);

  const filteredTasks = selectedDept === "all" ? tasks : tasks.filter(t => t.department_id === selectedDept);

  const tasksByStatus = {
    todo: filteredTasks.filter(t => t.status === "todo"),
    in_progress: filteredTasks.filter(t => t.status === "in_progress"),
    done: filteredTasks.filter(t => t.status === "done"),
  };

  const empById = (id) => employees.find(e => e.id === id);
  const deptById = (id) => departments.find(d => d.id === id);

  return (
    <div className="space-y-4 fade-in">
      {/* Filter bar */}
      <div className="glass rounded-2xl p-4 slide-up flex items-center gap-3 flex-wrap">
        <select value={selectedDept} onChange={(e) => setSelectedDept(e.target.value)}
          style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
          className="px-3 py-2 rounded-lg border text-xs outline-none">
          <option value="all">Бүх хэлтэс</option>
          {departments.map((d) => (
            <option key={d.id} value={d.id}>{d.name}</option>
          ))}
        </select>

        <div className="flex-1" />

        <div style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
          {filteredTasks.length} даалгавар
        </div>

        <button onClick={onAdd}
          className="glow-primary press-btn px-3 py-2 rounded-lg text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5"
          style={{ fontFamily: FM }}>
          <Plus size={11} /> Даалгавар нэмэх
        </button>
      </div>

      {/* Kanban */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-3">
        {Object.entries(tasksByStatus).map(([status, list], colIdx) => {
          const meta = TASK_STATUS[status];
          return (
            <div key={status} className={`glass rounded-3xl p-4 slide-up-delay-${colIdx + 1}`}>
              <div className="flex items-center justify-between mb-3">
                <div className="flex items-center gap-2">
                  <span style={{ fontSize: 14 }}>{meta.icon}</span>
                  <h3 style={{ fontFamily: FD, fontWeight: 500 }} className="text-base">{meta.label}</h3>
                </div>
                <span style={{ background: meta.bg, color: meta.color, fontFamily: FM }}
                      className="px-2 py-0.5 rounded-full text-[9px] font-bold tabular-nums">
                  {list.length}
                </span>
              </div>

              <div className="space-y-2 max-h-[60vh] overflow-y-auto">
                {list.length === 0 ? (
                  <div style={{ color: T.muted }} className="text-center py-8 text-xs">
                    Даалгавар алга
                  </div>
                ) : list.map((t) => {
                  const dept = deptById(t.department_id);
                  const assignee = empById(t.assignee_id);
                  const priority = TASK_PRIORITY[t.priority] || TASK_PRIORITY.medium;
                  const isOverdue = t.due_date && t.status !== "done" && new Date(t.due_date) < new Date(new Date().toISOString().slice(0,10));

                  return (
                    <div key={t.id} className="glass-soft rounded-xl p-3 lift cursor-pointer slide-up"
                         onClick={() => onEdit(t)}>
                      <div className="flex items-start justify-between gap-2 mb-1.5">
                        <div className="flex items-center gap-1.5">
                          <span style={{ background: priority.bg, color: priority.color, fontFamily: FM }}
                                className="px-1.5 py-0.5 rounded text-[8px] uppercase tracking-wider font-bold">
                            {priority.label}
                          </span>
                          {dept && (
                            <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider truncate">
                              {dept.name}
                            </span>
                          )}
                        </div>
                        <button onClick={(e) => { e.stopPropagation(); setConfirmDel(t); }}
                          style={{ color: T.muted }} className="hover:text-red-500 shrink-0">
                          <Trash2 size={10} />
                        </button>
                      </div>

                      <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-sm mb-1.5 line-clamp-2">
                        {t.title}
                      </div>

                      {t.description && (
                        <p style={{ color: T.muted }} className="text-[11px] leading-relaxed line-clamp-2 mb-2">
                          {t.description}
                        </p>
                      )}

                      <div className="flex items-center justify-between gap-2 flex-wrap">
                        {assignee ? (
                          <div className="flex items-center gap-1">
                            <div style={{
                              background: "#0E9C8E",
                              color: "white",
                            }} className="w-5 h-5 rounded-full flex items-center justify-center text-[9px] font-bold">
                              {assignee.name?.[0]}
                            </div>
                            <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] truncate">
                              {assignee.name}
                            </span>
                          </div>
                        ) : (
                          <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] italic">
                            Хариуцагчгүй
                          </span>
                        )}

                        {t.due_date && (
                          <span style={{
                            color: isOverdue ? T.err : T.muted,
                            fontFamily: FM,
                          }} className="text-[10px]">
                            📅 {t.due_date.slice(5)}
                            {isOverdue && " ⚠"}
                          </span>
                        )}
                      </div>

                      {/* Status change buttons */}
                      <div className="flex gap-1 mt-2 pt-2 border-t" style={{ borderColor: T.borderSoft }}>
                        {status !== "todo" && (
                          <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "todo"); }}
                            className="glass-soft press-btn flex-1 py-1 rounded text-[9px] uppercase tracking-wider"
                            style={{ fontFamily: FM, color: T.muted }}>
                            ← Хийх
                          </button>
                        )}
                        {status !== "in_progress" && (
                          <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "in_progress"); }}
                            className="glass-soft press-btn flex-1 py-1 rounded text-[9px] uppercase tracking-wider"
                            style={{ fontFamily: FM, color: T.warn }}>
                            ⚡ Эхлэх
                          </button>
                        )}
                        {status !== "done" && (
                          <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "done"); }}
                            className="glass-soft press-btn flex-1 py-1 rounded text-[9px] uppercase tracking-wider"
                            style={{ fontFamily: FM, color: T.ok }}>
                            ✓ Дуусгах
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          );
        })}
      </div>

      {confirmDel && (
        <Modal onClose={() => setConfirmDel(null)} title="Даалгавар устгах?" maxW="max-w-sm">
          <p style={{ color: T.muted }} className="text-sm mb-5">
            <strong style={{ color: T.ink }}>{confirmDel.title}</strong> устгагдана.
          </p>
          <div className="flex gap-3">
            <button onClick={() => setConfirmDel(null)}
              className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-sm"
              style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
            <button onClick={() => { onDelete(confirmDel.id); setConfirmDel(null); }}
              className="glow-danger press-btn flex-1 py-2.5 rounded-xl text-sm font-medium"
              style={{ fontFamily: FS }}>Устгах</button>
          </div>
        </Modal>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  TASK FORM MODAL
// ═══════════════════════════════════════════════════════════════════════════
function TaskFormModal({ mode, task, departments, employees, onSave, onClose }) {
  const [title, setTitle] = useState(task?.title || "");
  const [description, setDescription] = useState(task?.description || "");
  const [departmentId, setDepartmentId] = useState(task?.department_id || (departments[0]?.id || ""));
  const [assigneeId, setAssigneeId] = useState(task?.assignee_id || "");
  const [priority, setPriority] = useState(task?.priority || "medium");
  const [status, setStatus] = useState(task?.status || "todo");
  const [dueDate, setDueDate] = useState(task?.due_date || "");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  const submit = async () => {
    setErr("");
    if (!title.trim()) return setErr("Гарчиг бичнэ үү");
    if (!departmentId) return setErr("Хэлтэс сонгоно уу");
    setBusy(true);
    await onSave({
      id: task?.id || null,
      department_id: departmentId,
      title: title.trim(),
      description: description.trim() || null,
      assignee_id: assigneeId || null,
      priority,
      status,
      due_date: dueDate || null,
    });
    setBusy(false);
  };

  // Хэлтсийн ажилтнууд
  const deptEmps = departmentId ? employees.filter(e => e.department_id === departmentId) : employees;

  return (
    <Modal onClose={onClose} title={mode === "add" ? "Шинэ даалгавар" : "Даалгавар засах"}>
      <div className="space-y-4">
        <Field label="Гарчиг" required>
          <Input value={title} onChange={setTitle} placeholder="Жишээ: Сарын тайлан бэлдэх" autoFocus />
        </Field>

        <Field label="Дэлгэрэнгүй">
          <textarea value={description} onChange={(e) => setDescription(e.target.value)} rows={3}
            placeholder="Юу хийх вэ, хэрхэн хийх ёстой г.м"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none resize-none" />
        </Field>

        <div className="grid grid-cols-2 gap-3">
          <Field label="Хэлтэс" required>
            <select value={departmentId} onChange={(e) => { setDepartmentId(e.target.value); setAssigneeId(""); }}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none">
              <option value="">— Сонгох —</option>
              {departments.map((d) => (
                <option key={d.id} value={d.id}>{d.name}</option>
              ))}
            </select>
          </Field>

          <Field label="Хариуцагч">
            <select value={assigneeId} onChange={(e) => setAssigneeId(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none">
              <option value="">— Сонгоогүй —</option>
              {deptEmps.map((e) => (
                <option key={e.id} value={e.id}>{e.name}</option>
              ))}
            </select>
          </Field>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <Field label="Чухалчлал">
            <select value={priority} onChange={(e) => setPriority(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none">
              {Object.entries(TASK_PRIORITY).map(([k, v]) => (
                <option key={k} value={k}>{v.label}</option>
              ))}
            </select>
          </Field>

          <Field label="Дуусах огноо">
            <input type="date" value={dueDate} onChange={(e) => setDueDate(e.target.value)}
              style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
              className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none" />
          </Field>
        </div>

        {mode === "edit" && (
          <Field label="Төлөв">
            <div className="flex gap-1.5">
              {Object.entries(TASK_STATUS).map(([k, v]) => (
                <button key={k} onClick={() => setStatus(k)}
                  className={`${status === k ? "tab-active" : "tab-inactive glass-soft"} press-btn flex-1 py-2 rounded-lg text-[10px] uppercase tracking-wider`}
                  style={{ fontFamily: FM, borderColor: status === k ? "transparent" : T.borderSoft, border: "1px solid" }}>
                  {v.icon} {v.label}
                </button>
              ))}
            </div>
          </Field>
        )}

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium"
            style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
          <button onClick={submit} disabled={busy}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2"
            style={{ fontFamily: FS }}>
            {busy && <Loader2 size={13} className="spin" />}
            Хадгалах
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  MY TASKS VIEW (employee) — Kanban + add own
// ═══════════════════════════════════════════════════════════════════════════
function MyTasksView({ tasks, currentUserId, colleagues, hasDepartment, onAdd, onEdit, onDelete, onUpdateStatus }) {
  const [filter, setFilter] = useState("assigned"); // assigned | created | all
  const [viewMode, setViewMode] = useState("kanban"); // kanban | list
  const [confirmDel, setConfirmDel] = useState(null);

  const filtered = filter === "assigned" ? tasks.filter(t => t.assignee_id === currentUserId)
                  : filter === "created" ? tasks.filter(t => t.created_by === currentUserId)
                  : tasks;

  const tasksByStatus = {
    todo: filtered.filter(t => t.status === "todo"),
    in_progress: filtered.filter(t => t.status === "in_progress"),
    done: filtered.filter(t => t.status === "done"),
  };

  const empById = (id) => colleagues.find(e => e.id === id);

  return (
    <div className="space-y-4 fade-in">
      {/* Filter + add */}
      <div className="glass rounded-2xl p-4 slide-up flex items-center gap-3 flex-wrap">
        <div className="flex gap-1.5 flex-wrap">
          {[
            { id: "assigned", label: "Надад", count: tasks.filter(t => t.assignee_id === currentUserId).length },
            { id: "created", label: "Миний үүсгэсэн", count: tasks.filter(t => t.created_by === currentUserId).length },
            { id: "all", label: "Бүгд", count: tasks.length },
          ].map((f) => (
            <button key={f.id} onClick={() => setFilter(f.id)}
              className={`${filter === f.id ? "tab-active" : "tab-inactive glass-soft"} press-btn px-3 py-1.5 rounded-full border text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5`}
              style={{ fontFamily: FM, borderColor: filter === f.id ? "transparent" : T.borderSoft }}>
              {f.label}
              {f.count > 0 && (
                <span style={{
                  background: filter === f.id ? "rgba(255,255,255,0.95)" : T.highlight,
                  color: filter === f.id ? T.highlight : "white",
                }} className="px-1.5 py-0.5 rounded-full text-[9px] font-bold tabular-nums">{f.count}</span>
              )}
            </button>
          ))}
        </div>

        <div className="flex-1" />

        <div className="flex gap-1 glass-soft rounded-lg p-0.5">
          <button onClick={() => setViewMode("kanban")}
            className={`${viewMode === "kanban" ? "bg-white shadow-sm" : ""} press-btn px-2.5 py-1.5 rounded text-[10px] uppercase tracking-wider`}
            style={{ fontFamily: FM, color: viewMode === "kanban" ? T.highlight : T.muted }}>
            Kanban
          </button>
          <button onClick={() => setViewMode("list")}
            className={`${viewMode === "list" ? "bg-white shadow-sm" : ""} press-btn px-2.5 py-1.5 rounded text-[10px] uppercase tracking-wider`}
            style={{ fontFamily: FM, color: viewMode === "list" ? T.highlight : T.muted }}>
            Жагсаалт
          </button>
        </div>

        {hasDepartment && (
          <button onClick={onAdd}
            className="glow-primary press-btn px-3 py-2 rounded-lg text-[10px] uppercase tracking-[0.2em] flex items-center gap-1.5"
            style={{ fontFamily: FM }}>
            <Plus size={11} /> Шинэ
          </button>
        )}
      </div>

      {!hasDepartment && (
        <div className="glass rounded-3xl py-6 px-4 text-center slide-up-delay-1" style={{ color: T.warn }}>
          <AlertCircle size={20} className="mx-auto mb-2" strokeWidth={1.5} />
          <p style={{ fontFamily: FM }} className="text-xs">
            Та хэлтэст харьяалагдаагүй учраас даалгавар үүсгэх боломжгүй. Админд хандана уу.
          </p>
        </div>
      )}

      {/* Kanban view */}
      {viewMode === "kanban" && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-3">
          {Object.entries(tasksByStatus).map(([status, list], colIdx) => {
            const meta = TASK_STATUS[status];
            return (
              <div key={status} className={`glass rounded-3xl p-4 slide-up-delay-${colIdx + 1}`}>
                <div className="flex items-center justify-between mb-3">
                  <div className="flex items-center gap-2">
                    <span style={{ fontSize: 14 }}>{meta.icon}</span>
                    <h3 style={{ fontFamily: FD, fontWeight: 500 }} className="text-base">{meta.label}</h3>
                  </div>
                  <span style={{ background: meta.bg, color: meta.color, fontFamily: FM }}
                        className="px-2 py-0.5 rounded-full text-[9px] font-bold tabular-nums">
                    {list.length}
                  </span>
                </div>

                <div className="space-y-2 max-h-[60vh] overflow-y-auto">
                  {list.length === 0 ? (
                    <div style={{ color: T.muted }} className="text-center py-8 text-xs">
                      Алга
                    </div>
                  ) : list.map((t) => {
                    const assignee = empById(t.assignee_id);
                    const priority = TASK_PRIORITY[t.priority] || TASK_PRIORITY.medium;
                    const isOverdue = t.due_date && t.status !== "done" && new Date(t.due_date) < new Date(new Date().toISOString().slice(0,10));
                    const canEdit = t.created_by === currentUserId || t.assignee_id === currentUserId;

                    return (
                      <div key={t.id} className="glass-soft rounded-xl p-3 lift cursor-pointer slide-up"
                           onClick={() => canEdit && onEdit(t)}>
                        <div className="flex items-start justify-between gap-2 mb-1.5">
                          <span style={{ background: priority.bg, color: priority.color, fontFamily: FM }}
                                className="px-1.5 py-0.5 rounded text-[8px] uppercase tracking-wider font-bold">
                            {priority.label}
                          </span>
                          {(t.created_by === currentUserId) && (
                            <button onClick={(e) => { e.stopPropagation(); setConfirmDel(t); }}
                              style={{ color: T.muted }} className="hover:text-red-500 shrink-0">
                              <Trash2 size={10} />
                            </button>
                          )}
                        </div>

                        <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-sm mb-1.5 line-clamp-2">
                          {t.title}
                        </div>

                        {t.description && (
                          <p style={{ color: T.muted }} className="text-[11px] leading-relaxed line-clamp-2 mb-2">
                            {t.description}
                          </p>
                        )}

                        <div className="flex items-center justify-between gap-2 flex-wrap">
                          {assignee ? (
                            <div className="flex items-center gap-1">
                              <div style={{
                                background: "#0E9C8E",
                                color: "white",
                              }} className="w-5 h-5 rounded-full flex items-center justify-center text-[9px] font-bold">
                                {assignee.name?.[0]}
                              </div>
                              <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] truncate">
                                {assignee.name}
                              </span>
                            </div>
                          ) : (
                            <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] italic">
                              Хариуцагчгүй
                            </span>
                          )}

                          {t.due_date && (
                            <span style={{
                              color: isOverdue ? T.err : T.muted,
                              fontFamily: FM,
                            }} className="text-[10px]">
                              📅 {t.due_date.slice(5)}
                              {isOverdue && " ⚠"}
                            </span>
                          )}
                        </div>

                        {/* Status change buttons (only for assignee) */}
                        {t.assignee_id === currentUserId && (
                          <div className="flex gap-1 mt-2 pt-2 border-t" style={{ borderColor: T.borderSoft }}>
                            {status !== "todo" && (
                              <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "todo"); }}
                                className="glass-soft press-btn flex-1 py-1 rounded text-[9px] uppercase tracking-wider"
                                style={{ fontFamily: FM, color: T.muted }}>
                                ← Хийх
                              </button>
                            )}
                            {status !== "in_progress" && (
                              <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "in_progress"); }}
                                className="glass-soft press-btn flex-1 py-1 rounded text-[9px] uppercase tracking-wider"
                                style={{ fontFamily: FM, color: T.warn }}>
                                ⚡ Эхлэх
                              </button>
                            )}
                            {status !== "done" && (
                              <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "done"); }}
                                className="glass-soft press-btn flex-1 py-1 rounded text-[9px] uppercase tracking-wider"
                                style={{ fontFamily: FM, color: T.ok }}>
                                ✓ Дуусгах
                              </button>
                            )}
                          </div>
                        )}
                      </div>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* List view */}
      {viewMode === "list" && (
        <>
          {filtered.length === 0 ? (
            <div className="glass rounded-3xl py-12 px-6 text-center slide-up-delay-1" style={{ color: T.muted }}>
              <ClipboardCheck size={28} className="mx-auto mb-3" strokeWidth={1.5} />
              <p className="text-sm">Даалгавар алга</p>
            </div>
          ) : (
            <div className="space-y-2 slide-up-delay-1">
              {filtered.map((t) => {
                const status = TASK_STATUS[t.status];
                const priority = TASK_PRIORITY[t.priority];
                const isOverdue = t.due_date && t.status !== "done" && new Date(t.due_date) < new Date(new Date().toISOString().slice(0,10));
                const assignee = empById(t.assignee_id);

                return (
                  <div key={t.id} className="glass lift rounded-2xl p-4 slide-up cursor-pointer"
                       onClick={() => onEdit(t)}>
                    <div className="flex items-start justify-between gap-3 mb-2">
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2 mb-1 flex-wrap">
                          <span style={{ background: priority.bg, color: priority.color, fontFamily: FM }}
                                className="px-2 py-0.5 rounded text-[9px] uppercase tracking-wider font-bold">
                            {priority.label}
                          </span>
                          <span style={{ background: status.bg, color: status.color, fontFamily: FM }}
                                className="px-2 py-0.5 rounded text-[9px] uppercase tracking-wider">
                            {status.icon} {status.label}
                          </span>
                          {assignee && (
                            <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                              👤 {assignee.name}
                            </span>
                          )}
                        </div>
                        <div style={{ fontFamily: FS, fontWeight: 500 }} className="text-sm mb-1">
                          {t.title}
                        </div>
                        {t.description && (
                          <p style={{ color: T.muted }} className="text-xs leading-relaxed mb-2">{t.description}</p>
                        )}
                        {t.due_date && (
                          <div style={{ color: isOverdue ? T.err : T.muted, fontFamily: FM }} className="text-[10px] mt-1">
                            📅 {t.due_date}
                            {isOverdue && <span className="ml-1 font-bold">⚠ Хугацаа хэтэрсэн</span>}
                          </div>
                        )}
                      </div>
                    </div>

                    {t.assignee_id === currentUserId && t.status !== "done" && (
                      <div className="flex gap-2 mt-3 pt-3 border-t" style={{ borderColor: T.borderSoft }}>
                        {t.status === "todo" && (
                          <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "in_progress"); }}
                            className="glow-warn press-btn flex-1 py-2 rounded-lg text-[10px] uppercase tracking-wider font-medium"
                            style={{ fontFamily: FM }}>
                            ⚡ Эхлэх
                          </button>
                        )}
                        <button onClick={(e) => { e.stopPropagation(); onUpdateStatus(t.id, "done"); }}
                          className="glow-success press-btn flex-1 py-2 rounded-lg text-[10px] uppercase tracking-wider font-medium"
                          style={{ fontFamily: FM }}>
                          ✓ Дуусгах
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </>
      )}

      {confirmDel && (
        <Modal onClose={() => setConfirmDel(null)} title="Даалгавар устгах?" maxW="max-w-sm">
          <p style={{ color: T.muted }} className="text-sm mb-5">
            <strong style={{ color: T.ink }}>{confirmDel.title}</strong> устгагдана.
          </p>
          <div className="flex gap-3">
            <button onClick={() => setConfirmDel(null)}
              className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-sm"
              style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
            <button onClick={() => { onDelete(confirmDel.id); setConfirmDel(null); }}
              className="glow-danger press-btn flex-1 py-2.5 rounded-xl text-sm font-medium"
              style={{ fontFamily: FS }}>Устгах</button>
          </div>
        </Modal>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  ANNOUNCEMENTS VIEW
// ═══════════════════════════════════════════════════════════════════════════
const ANN_PRIORITY = {
  normal: { label: "Энгийн", color: T.muted, bg: "rgba(107,114,128,0.1)", emoji: "📢" },
  important: { label: "Чухал", color: T.highlight, bg: T.highlightSoft, emoji: "⭐" },
  urgent: { label: "Яаралтай", color: T.err, bg: "rgba(239,68,68,0.12)", emoji: "🚨" },
};

function AnnouncementsView({ announcements, isAdmin, onAdd, onEdit, onDelete }) {
  const [confirmDel, setConfirmDel] = useState(null);

  return (
    <div className="space-y-4 fade-in">
      {isAdmin && (
        <div className="flex justify-end slide-up">
          <button onClick={onAdd}
            className="glow-primary press-btn px-4 py-2.5 rounded-xl text-sm font-medium flex items-center gap-2"
            style={{ fontFamily: FS }}>
            <Plus size={14} /> Зарлал нэмэх
          </button>
        </div>
      )}

      {announcements.length === 0 ? (
        <div className="glass rounded-3xl py-12 px-6 text-center slide-up-delay-1" style={{ color: T.muted }}>
          <Inbox size={28} className="mx-auto mb-3" strokeWidth={1.5} />
          <p className="text-sm">Зарлал алга</p>
        </div>
      ) : (
        <div className="space-y-3 slide-up-delay-1">
          {announcements.map((a, i) => {
            const p = ANN_PRIORITY[a.priority] || ANN_PRIORITY.normal;
            const isExpired = a.expires_at && new Date(a.expires_at) < new Date();
            return (
              <article key={a.id}
                className={`${a.pinned ? "glass-strong" : "glass"} lift rounded-3xl p-5 slide-up ${isExpired ? "opacity-50" : ""}`}
                style={a.pinned ? { borderColor: p.color, borderWidth: 2 } : {}}>
                <div className="flex items-start justify-between gap-3 mb-2">
                  <div className="flex items-center gap-2 flex-wrap">
                    {a.pinned && (
                      <span style={{ background: T.highlightSoft, color: T.highlight, fontFamily: FM }}
                            className="px-2 py-0.5 rounded text-[9px] uppercase tracking-wider font-bold">
                        📌 Бэхэлсэн
                      </span>
                    )}
                    <span style={{ background: p.bg, color: p.color, fontFamily: FM }}
                          className="px-2 py-0.5 rounded text-[9px] uppercase tracking-wider font-bold">
                      {p.emoji} {p.label}
                    </span>
                    {isExpired && (
                      <span style={{ color: T.muted, fontFamily: FM }} className="text-[9px] uppercase tracking-wider">
                        Хугацаа дууссан
                      </span>
                    )}
                  </div>
                  {isAdmin && (
                    <div className="flex gap-1 shrink-0">
                      <button onClick={() => onEdit(a)} style={{ color: T.muted }}
                        className="hover:text-black p-1">
                        <Edit3 size={12} />
                      </button>
                      <button onClick={() => setConfirmDel(a)} style={{ color: T.err }} className="p-1">
                        <Trash2 size={12} />
                      </button>
                    </div>
                  )}
                </div>

                <h3 style={{ fontFamily: FD, fontWeight: 500, letterSpacing: "-0.02em" }}
                    className="text-xl mb-2">
                  {a.title}
                </h3>

                <p style={{ color: T.ink, fontFamily: FS }} className="text-sm leading-relaxed whitespace-pre-wrap">
                  {a.body}
                </p>

                <div className="flex items-center justify-between mt-3 pt-3 border-t" style={{ borderColor: T.borderSoft }}>
                  <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px] uppercase tracking-wider">
                    {new Date(a.created_at).toLocaleString("mn-MN", { day: "2-digit", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" })}
                  </span>
                  {a.expires_at && (
                    <span style={{ color: T.muted, fontFamily: FM }} className="text-[10px]">
                      ⏰ {new Date(a.expires_at).toLocaleDateString("mn-MN")} хүртэл
                    </span>
                  )}
                </div>
              </article>
            );
          })}
        </div>
      )}

      {confirmDel && (
        <Modal onClose={() => setConfirmDel(null)} title="Зарлал устгах?" maxW="max-w-sm">
          <p style={{ color: T.muted }} className="text-sm mb-5">
            <strong style={{ color: T.ink }}>{confirmDel.title}</strong> устгагдана.
          </p>
          <div className="flex gap-3">
            <button onClick={() => setConfirmDel(null)}
              className="glass-soft press-btn flex-1 py-2.5 rounded-xl text-sm"
              style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
            <button onClick={() => { onDelete(confirmDel.id); setConfirmDel(null); }}
              className="glow-danger press-btn flex-1 py-2.5 rounded-xl text-sm font-medium"
              style={{ fontFamily: FS }}>Устгах</button>
          </div>
        </Modal>
      )}
    </div>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  ANNOUNCEMENT FORM MODAL
// ═══════════════════════════════════════════════════════════════════════════
function AnnouncementFormModal({ mode, announcement, onSave, onClose }) {
  const [title, setTitle] = useState(announcement?.title || "");
  const [body, setBody] = useState(announcement?.body || "");
  const [priority, setPriority] = useState(announcement?.priority || "normal");
  const [pinned, setPinned] = useState(announcement?.pinned || false);
  const [expiresAt, setExpiresAt] = useState(announcement?.expires_at ? announcement.expires_at.slice(0, 10) : "");
  const [busy, setBusy] = useState(false);
  const [err, setErr] = useState("");

  const submit = async () => {
    setErr("");
    if (!title.trim()) return setErr("Гарчиг бичнэ үү");
    if (!body.trim()) return setErr("Агуулга бичнэ үү");
    setBusy(true);
    await onSave({
      id: announcement?.id || null,
      title: title.trim(),
      body: body.trim(),
      priority,
      pinned,
      expires_at: expiresAt ? new Date(expiresAt + "T23:59:59").toISOString() : null,
    });
    setBusy(false);
  };

  return (
    <Modal onClose={onClose} title={mode === "add" ? "Шинэ зарлал" : "Зарлал засах"}>
      <div className="space-y-4">
        <Field label="Гарчиг" required>
          <Input value={title} onChange={setTitle} placeholder="Жишээ: Маргааш баяр өдөр" autoFocus />
        </Field>

        <Field label="Агуулга" required>
          <textarea value={body} onChange={(e) => setBody(e.target.value)} rows={5}
            placeholder="Зарлалын дэлгэрэнгүй мэдээлэл"
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FS }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none resize-none" />
        </Field>

        <Field label="Зэрэг">
          <div className="flex gap-1.5">
            {Object.entries(ANN_PRIORITY).map(([k, v]) => (
              <button key={k} onClick={() => setPriority(k)}
                className={`${priority === k ? "tab-active" : "tab-inactive glass-soft"} press-btn flex-1 py-2 rounded-lg text-[10px] uppercase tracking-wider`}
                style={{ fontFamily: FM, borderColor: priority === k ? "transparent" : T.borderSoft, border: "1px solid" }}>
                {v.emoji} {v.label}
              </button>
            ))}
          </div>
        </Field>

        <Field label="Дуусах огноо (заавал биш)">
          <input type="date" value={expiresAt} onChange={(e) => setExpiresAt(e.target.value)}
            style={{ borderColor: T.border, background: "rgba(255,255,255,0.7)", color: T.ink, fontFamily: FM }}
            className="w-full px-3 py-2.5 rounded-lg border text-sm outline-none" />
        </Field>

        <label className="flex items-center gap-2 cursor-pointer">
          <input type="checkbox" checked={pinned} onChange={(e) => setPinned(e.target.checked)} />
          <span style={{ fontFamily: FM }} className="text-sm">📌 Дээр бэхлэх</span>
        </label>

        {err && <ErrorBox>{err}</ErrorBox>}

        <div className="flex gap-3 pt-2">
          <button onClick={onClose}
            className="glass-soft press-btn flex-1 py-3 rounded-xl text-sm font-medium"
            style={{ fontFamily: FS, color: T.ink }}>Цуцлах</button>
          <button onClick={submit} disabled={busy}
            className="glow-primary press-btn flex-1 py-3 rounded-xl text-sm font-medium disabled:opacity-50 flex items-center justify-center gap-2"
            style={{ fontFamily: FS }}>
            {busy && <Loader2 size={13} className="spin" />}
            Хадгалах
          </button>
        </div>
      </div>
    </Modal>
  );
}

// ═══════════════════════════════════════════════════════════════════════════
//  DEFAULT EXPORT — Sentry ErrorBoundary-аар ороосон App
// ═══════════════════════════════════════════════════════════════════════════
// ═══════════════════════════════════════════════════════════════════════════
// 🔧 MAINTENANCE MODE — Засварын үеэр 502-маягт дэлгэц харуулах
//
// ХЭРЭГЛЭХ ЗААВАР:
//   1. Засвар хийхийн өмнө: MAINTENANCE_MODE_ENABLED = true болгоно
//   2. Файлыг commit & push → Vercel deploy
//   3. Засвар дуусаны дараа: MAINTENANCE_MODE_ENABLED = false болгоно
//   4. Дахин commit & push → буцаагаад нээгдэнэ
//
// BYPASS: URL дотор ?bypass=orgooadmin тавихад maintenance дэлгэц алгасах
//          (Admin засвар хийх явцад өөрөө системд орох боломжтой)
// ═══════════════════════════════════════════════════════════════════════════
const MAINTENANCE_MODE_ENABLED = false; // ⚠ ХЭРЭГТЭЙ ҮЕД true БОЛГОНО
const MAINTENANCE_BYPASS_KEY = "orgooadmin"; // URL: ?bypass=orgooadmin

function MaintenanceScreen() {
  const [tick, setTick] = useState(0);
  // Цаг дамжаад refresh товчны label-ийг өөрчилнө
  useEffect(() => {
    const t = setInterval(() => setTick((x) => x + 1), 1000);
    return () => clearInterval(t);
  }, []);

  return (
    <div style={{
      minHeight: "100vh",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      padding: 20,
      background: "#f5f5f5",
      fontFamily: "system-ui, -apple-system, sans-serif",
      color: "#333",
    }}>
      <div style={{
        maxWidth: 500,
        width: "100%",
        textAlign: "center",
      }}>
        <div style={{
          fontSize: 80,
          fontWeight: 900,
          color: "#dc2626",
          lineHeight: 1,
          marginBottom: 8,
          fontFamily: "Arial, sans-serif",
          letterSpacing: -2,
        }}>
          502
        </div>
        <div style={{
          fontSize: 22,
          fontWeight: 600,
          marginBottom: 24,
          color: "#1f2937",
        }}>
          Bad Gateway
        </div>
        <div style={{
          background: "white",
          borderRadius: 8,
          padding: "24px 20px",
          textAlign: "left",
          border: "1px solid #e5e7eb",
          fontSize: 14,
          lineHeight: 1.6,
          color: "#4b5563",
        }}>
          <div style={{ fontWeight: 600, color: "#1f2937", marginBottom: 8 }}>
            🔧 Сервер засвар хийгдэж байна
          </div>
          <p style={{ margin: "0 0 12px" }}>
            Системд түр зуурын засвар хийгдэж байна. Удалгүй буцаагаад ажиллана.
          </p>
          <p style={{ margin: 0, fontSize: 12, color: "#6b7280" }}>
            Хэрэв удсан бол админд хандана уу.
          </p>
        </div>
        <button onClick={() => window.location.reload()}
          style={{
            marginTop: 20,
            padding: "10px 20px",
            background: "#374151",
            color: "white",
            border: "none",
            borderRadius: 6,
            fontSize: 14,
            cursor: "pointer",
            fontWeight: 500,
          }}>
          🔄 Дахин оролдох
        </button>
        <div style={{
          marginTop: 40,
          fontSize: 11,
          color: "#9ca3af",
          fontFamily: "monospace",
        }}>
          nginx/1.18.0 · {new Date().toUTCString()}
        </div>
      </div>
    </div>
  );
}

export default function App() {
  // 🔧 Maintenance Mode шалгалт
  if (MAINTENANCE_MODE_ENABLED) {
    // URL bypass шалгах: ?bypass=KEY
    const urlParams = new URLSearchParams(window.location.search);
    const bypass = urlParams.get("bypass");
    if (bypass !== MAINTENANCE_BYPASS_KEY) {
      return <MaintenanceScreen />;
    }
  }

  // Хэрэв Sentry тохируулагдсан бол ErrorBoundary-аар ороох, эс бол шууд AppRoot
  if (SENTRY_DSN) {
    return (
      <Sentry.ErrorBoundary
        fallback={(props) => <ErrorFallback {...props} />}
        showDialog={false}
      >
        <AppRoot />
      </Sentry.ErrorBoundary>
    );
  }
  return <AppRoot />;
}
